-- Poems batch 434
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('yuding-21','游陸渾南山自歇馬嶺到楓香林以詩代書答李舍人適','宋之問','唐','御定全唐诗','yuding','','[]','晨登歇馬嶺，遙望伏牛山。孤出群峰首，熊熊元氣間。',156,'御定全唐詩/json/051.json','["晨登歇馬嶺，遙望伏牛山。孤出群峰首，熊熊元氣間。", "太和亦崔嵬，石扇橫閃倏。細岑互攢倚，浮巘競奔蹙。", "白雲遙入懷，青靄近可掬。徒尋靈異跡，周顧愜心目。", "晨拂鳥路行，暮投人煙宿。粳稻遠彌秀，栗芋秋新熟。", "石髓非一岩，藥苗乃萬族。間關踏雲雨，繚繞緣水木。", "西見商山芝，南到楚鄉竹。楚竹幽且深，半雜楓香林。", "浩歌清潭曲，寄爾桃源心。"]'),
('yuding-22','早發大庾嶺','宋之問','唐','御定全唐诗','yuding','','[]','晨躋大庾險，驛鞍馳複息。霧露晝未開，浩途不可測。',180,'御定全唐詩/json/051.json','["晨躋大庾險，驛鞍馳複息。霧露晝未開，浩途不可測。", "嵥起華夷界，信為造化力。歇鞍問徒旅，鄉關在西北。", "出門怨別家，登嶺恨辭國。自惟勖忠孝，斯罪懵所得。", "皇明頗照洗，廷議日紛惑。兄弟遠淪居，妻子成異域。", "羽翮傷已毀，童幼憐未識。躊躕戀北顧，亭午晞霽色。", "春暖陰梅花，瘴回陽鳥翼。含沙緣澗聚，吻草依林植。", "適蠻悲疾首，懷鞏淚沾臆。感謝鵷鷺朝，勤修魑魅職。", "生還倘非遠，誓擬酬恩德。"]'),
('yuding-23','自洪府舟行直書其事','宋之問','唐','御定全唐诗','yuding','','[]','仲春辭國門，畏途橫萬里。越淮乘楚嶂，造江泛吳汜。',324,'御定全唐詩/json/051.json','["仲春辭國門，畏途橫萬里。越淮乘楚嶂，造江泛吳汜。", "嚴程無休隙，日夜涉風水。昔聞垂堂言，將誡千金子。", "問余何奇剝，遷竄極炎鄙。揆己道德餘，幼聞虛白旨。", "貴身賤外物，抗跡遠塵軌。朝游伊水湄，夕臥箕山趾。", "妙年拙自晦，皎潔弄文史。謬辱紫泥書，揮翰青雲裏。", "事往每增傷，寵來常誓止。銘骨懷報稱，逆鱗讓金紫。", "安位釁潛構，退耕禍猶起。棲岩實吾策，觸藩誠內恥。", "濟濟同時人，台庭鳴劍履。愚以卑自衛，兀坐去沉滓。", "迨茲理已極，竊位申知己。群議負宿心，獲戾光華始。", "黃金忽銷鑠，素業坐淪毀。浩歎誣平生，何獨戀枌梓。", "浦樹浮鬱鬱，皋蘭覆靡靡。百越去魂斷，九疑望心死。", "未盡匡阜遊，遠欣羅浮美。周旋本師訓，佩服無生理。", "異國多靈仙，幽探忘年紀。敝廬嵩山下，空谷茂蘭芷。", "悠悠南溟遠，采掇長已矣。"]'),
('yuding-24','下桂江縣黎壁','宋之問','唐','御定全唐诗','yuding','','[]','放溜覿前漵，連山分上幹。江回雲壁轉，天小霧峰攢。',132,'御定全唐詩/json/051.json','["放溜覿前漵，連山分上幹。江回雲壁轉，天小霧峰攢。", "吼沫跳急浪，合流環峻灘。欹離出漩劃，繚繞避渦盤。", "舟子怯桂水，最言斯路難。吾生抱忠信，吟嘯自安閒。", "旦別已千歲，夜愁勞萬端。企予見夜月，委曲破林巒。", "潭曠竹煙盡，洲香橘露團。豈傲夙所好，對之與俱歡。", "思君罷琴酌，泣此夜漫漫。"]'),
('yuding-25','奉使嵩山途經緱嶺','宋之問','唐','御定全唐诗','yuding','','[]','侵星發洛城，城中歌吹聲。畢景至緱嶺，嶺上煙霞生。',48,'御定全唐詩/json/051.json','["侵星發洛城，城中歌吹聲。畢景至緱嶺，嶺上煙霞生。", "草樹饒野意，山川多古情。大隱德所薄，歸來可退耕。"]'),
('yuding-26','傷王七秘書監寄呈揚州陸長史通簡府僚廣陵以廣好事','宋之問','唐','御定全唐诗','yuding','','[]','王氏貴先宗，衡門棲道風。傳心晤有物，秉化遊無窮。',132,'御定全唐詩/json/051.json','["王氏貴先宗，衡門棲道風。傳心晤有物，秉化遊無窮。", "學奧九流異，機玄三語同。書乃墨場絕，文稱詞伯雄。", "白屋藩魏主，蒼生期謝公。一祗賢良詔。遂謁承明宮。", "補袞望奚塞，尊儒位未充。罷官七門裏，歸老一丘中。", "嘗忝長者轍，微言私謂通。我行會稽郡，路出廣陵東。", "物在人已矣，都疑淮海空。"]'),
('yuding-27','使至嵩山尋杜四不遇慨然複傷田洗馬韓觀主因以題壁贈杜侯杜四','宋之問','唐','御定全唐诗','yuding','','[]','洛橋瞻太室，期子在雲煙。歸來不相見，孤賞弄寒泉。',108,'御定全唐詩/json/051.json','["洛橋瞻太室，期子在雲煙。歸來不相見，孤賞弄寒泉。", "與君闊松石，於茲二十年。田公謝昭世，韓子秘幽埏。", "憶昔同攜手，山棲接二賢。笙歌入玄地，詩酒坐寥天。", "舊友悉零落，罷琴私自憐。逝者非藥誤，餐霞意可全。", "為餘理還策，相與事靈仙。"]'),
('yuding-28','玩郡齋海榴','宋之問','唐','御定全唐诗','yuding','','[]','澤國韶氣早，開簾延霽天。野禽宵未囀，山蜚晝仍眠。',132,'御定全唐詩/json/051.json','["澤國韶氣早，開簾延霽天。野禽宵未囀，山蜚晝仍眠。", "目茲海榴發，列映岩楹前。熠爚禦風靜，葳蕤含景鮮。", "清晨綠堪佩，亭午丹欲然。昔忝金閨籍，嘗見玉池蓮。", "未若宗族地，更逢榮耀全。南金雖自貴，賀賞詎能遷。", "撫躬萬里絕，豈染一朝妍。徒緣滯遐郡，常是惜流年。", "越俗鄙章甫，捫心空自憐。"]'),
('yuding-29','長安路','宋之問','唐','御定全唐诗','yuding','','[]','秦地平如掌，層城出雲漢。樓閣九衢春，車馬千門旦。',48,'御定全唐詩/json/051.json','["秦地平如掌，層城出雲漢。樓閣九衢春，車馬千門旦。", "綠柳開複合，紅塵聚還散。日晚鬥雞場，經過狹斜看。"]'),
('yuding-30','折楊柳','宋之問','唐','御定全唐诗','yuding','','[]','玉樹朝日映，羅帳春風吹。拭淚攀楊柳，長條宛地垂。',48,'御定全唐詩/json/051.json','["玉樹朝日映，羅帳春風吹。拭淚攀楊柳，長條宛地垂。", "白花飛曆亂，黃鳥思參差。妾自肝腸斷，傍人那得知。"]'),
('yuding-31','有所思','宋之問','唐','御定全唐诗','yuding','','[]','君子事行役，再空芳歲期。美人曠遙佇，萬里浮雲思。',48,'御定全唐詩/json/051.json','["君子事行役，再空芳歲期。美人曠遙佇，萬里浮雲思。", "園桃綻紅豔，效葉柔綠滋。坐看長夏晚，秋月生羅帷。"]'),
('yuding-32','軍中人日登高贈房明府','宋之問','唐','御定全唐诗','yuding','','[]','幽郊昨夜陰風斷，頓覺朝來陽吹暖。涇水橋南柳欲黃，',40,'御定全唐詩/json/051.json','["幽郊昨夜陰風斷，頓覺朝來陽吹暖。涇水橋南柳欲黃，", "聞道凱旋乘騎入，看君走馬見芳菲。"]'),
('yuding-33','寒食還陸渾別業','宋之問','唐','御定全唐诗','yuding','','[]','洛陽城裏花如雪，陸渾山中今始發。旦別河橋楊柳風，',40,'御定全唐詩/json/051.json','["洛陽城裏花如雪，陸渾山中今始發。旦別河橋楊柳風，", "野老不知堯舜力，酣歌一曲太平人。"]'),
('yuding-34','寒食江州滿塘驛','宋之問','唐','御定全唐诗','yuding','','[]','去年上巳洛橋邊，今年寒食廬山曲。遙憐鞏樹花應滿，',40,'御定全唐詩/json/051.json','["去年上巳洛橋邊，今年寒食廬山曲。遙憐鞏樹花應滿，", "驛騎明朝宿何處，猿聲今夜斷君腸。"]'),
('yuding-35','至端州驛見杜五審言沈三佺期閻五朝隱王二無競題壁慨然成詠','宋之問','唐','御定全唐诗','yuding','','[]','逐臣北地承嚴譴，謂到南中每相見。豈意南中岐路多，',40,'御定全唐詩/json/051.json','["逐臣北地承嚴譴，謂到南中每相見。豈意南中岐路多，", "處處山川同瘴癘，自憐能得幾人歸。"]'),
('yuding-36','綠竹引','宋之問','唐','御定全唐诗','yuding','','[]','青溪綠潭潭水側，修竹嬋娟同一色。徒生仙實鳳不遊，',40,'御定全唐詩/json/051.json','["青溪綠潭潭水側，修竹嬋娟同一色。徒生仙實鳳不遊，", "含情傲睨慰心目，何可一日無此君。"]'),
('yuding-37','明河篇','宋之問','唐','御定全唐诗','yuding','','[]','八月涼風天氣晶，萬里無雲河漢明。昏見南樓清且淺，',96,'御定全唐詩/json/051.json','["八月涼風天氣晶，萬里無雲河漢明。昏見南樓清且淺，", "複道連甍共蔽虧，畫堂瓊戶特相宜。雲母帳前初氾濫，", "南陌征人去不歸，誰家今夜搗寒衣。鴛鴦機上疏螢度，", "已能舒卷任浮雲，不惜光輝讓流月。明河可望不可親，"]'),
('yuding-38','龍門應制','宋之問','唐','御定全唐诗','yuding','','[]','宿雨霽氛埃，流雲度城闕。河堤柳新翠，苑樹花先發。',208,'御定全唐詩/json/051.json','["宿雨霽氛埃，流雲度城闕。河堤柳新翠，苑樹花先發。", "洛陽花柳此時濃，山水樓臺映幾重。群公拂霧朝翔鳳，", "雲罕才臨禦水橋，天衣已入香山會。山壁嶄岩斷複連，", "層巒舊長千尋木，遠壑初飛百丈泉，彩仗蜺旌繞香閣。", "下輦登高望河洛。東城宮闕擬昭回，南陽溝塍殊綺錯。", "林下天香七寶台，山中春酒萬年杯，微風一起祥花落，", "歌舞淹留景欲斜，石關猶駐五雲車。鳥旗翼翼留芳草，", "郊外喧喧引看人，傾都南望屬車塵。囂聲引颺聞黃道，", "吾皇不事瑤池樂，時雨來觀農扈春。"]'),
('yuding-39','初宿淮口','宋之問','唐','御定全唐诗','yuding','','[]','孤舟汴河水，去國情無已。晚泊投楚鄉，明月清淮裏。',48,'御定全唐詩/json/051.json','["孤舟汴河水，去國情無已。晚泊投楚鄉，明月清淮裏。", "汴河東瀉路窮茲，洛陽西顧日增悲。夜聞楚歌思欲斷，"]'),
('yuding-40','王子喬','宋之問','唐','御定全唐诗','yuding','','[]','王子喬，愛神仙，七月七日上賓天。白虎搖瑟鳳吹笙，',36,'御定全唐詩/json/051.json','["王子喬，愛神仙，七月七日上賓天。白虎搖瑟鳳吹笙，", "空望山頭草，草露濕人衣。"]'),
('yuding-41','放白鷳篇','宋之問','唐','御定全唐诗','yuding','','[]','故人贈我綠綺琴，兼致白鷳鳥。琴是嶧山桐，鳥出吳溪中。',74,'御定全唐詩/json/051.json','["故人贈我綠綺琴，兼致白鷳鳥。琴是嶧山桐，鳥出吳溪中。", "我心松石清霞裏，弄此幽弦不能已。我心河海白雲垂，", "乃言物性不可違，白鷳愁慕刷毛衣。玉徽閉匣留為念，"]'),
('yuding-42','桂州三月三日','宋之問','唐','御定全唐诗','yuding','','[]','代業京華裏，遠投魑魅鄉。登高望不極，雲海四茫茫。',184,'御定全唐詩/json/051.json','["代業京華裏，遠投魑魅鄉。登高望不極，雲海四茫茫。", "伊昔承休盼，曾為人所羨。兩朝賜顏色，二紀陪歡宴。", "昆明禦宿侍龍媒，伊闕天泉複幾回。西夏黃河水心劍，", "千春萬壽多行樂，柏梁和歌攀睿作。賜金分帛奉恩輝，", "載筆儒林多歲月，襆被文昌佐吳越。越中山海高且深，", "愚謂嬉遊長似昔，不言流寓欻成今。始安繁華舊風俗，", "荔浦蘅皋萬里餘，洛陽音信絕能疏。故園今日應愁思，", "不求漢使金囊贈，願得佳人錦字書。"]'),
('yuding-43','下山歌','宋之問','唐','御定全唐诗','yuding','','[]','下嵩山兮多所思，攜佳人兮步遲遲。',32,'御定全唐詩/json/051.json','["下嵩山兮多所思，攜佳人兮步遲遲。", "松間明月長如此，君再遊兮複何時。"]'),
('yuding-44','冬宵引贈司馬承禎','宋之問','唐','御定全唐诗','yuding','','[]','河有冰兮山有雪，北戶墐兮行人絕。獨坐山中兮對松月，',41,'御定全唐詩/json/051.json','["河有冰兮山有雪，北戶墐兮行人絕。獨坐山中兮對松月，", "此情不向俗人說，愛而不見恨無窮。"]'),
('yuding-45','高山引','宋之問','唐','御定全唐诗','yuding','','[]','攀雲窈窕兮上躋懸峰，長路浩浩兮此去何從。',62,'御定全唐詩/json/051.json','["攀雲窈窕兮上躋懸峰，長路浩浩兮此去何從。", "水一曲兮腸一曲，山一重兮悲一重。松檟邈已遠，", "天高難訴兮遠負明德，卻望咸京兮揮涕龍鍾。"]'),
('yuding-46','嵩山天門歌','宋之問','唐','御定全唐诗','yuding','','[]','登天門兮坐磐石之嶙峋，前漎漎兮未半，下漠漠兮無垠。',124,'御定全唐詩/json/051.json','["登天門兮坐磐石之嶙峋，前漎漎兮未半，下漠漠兮無垠。", "紛窈窕兮岩倚披以鵬翅，洞膠葛兮峰棱層以龍鱗。", "松移岫轉，左變而右易。風生雲起，出鬼而入神。", "吾亦不知其靈怪如此，願遊杳冥兮見羽人。", "重曰，天門兮穹崇，回合兮攢叢，松萬接兮柱日，", "試一望兮奪魄，況眾妙之無窮。"]'),
('yuding-47','有所思','宋之問','唐','御定全唐诗','yuding','','[]','洛陽城東桃李花，飛來飛去落誰家。幽閨女兒惜顏色，',112,'御定全唐詩/json/051.json','["洛陽城東桃李花，飛來飛去落誰家。幽閨女兒惜顏色，", "已見松柏摧為薪，更聞桑田變成海。古人無複洛城東，", "寄言全盛紅顏子，須憐半死白頭翁。此翁白頭真可憐，", "光祿池台交錦繡，將軍樓閣畫神仙。一朝臥病無相識，", "但看古來歌舞地，唯有黃昏鳥雀飛。"]'),
('yuding-0','奉和立春日侍宴內出剪綵花應制','宋之問','唐','御定全唐诗','yuding','','[]','金閣妝新杏，瓊筵弄綺梅。人間都未識，天上忽先開。',48,'御定全唐詩/json/052.json','["金閣妝新杏，瓊筵弄綺梅。人間都未識，天上忽先開。", "蝶繞香絲住，蜂憐豔粉回。今年春色早，應為剪刀催。"]'),
('yuding-1','春日芙蓉園侍宴應制','宋之問','唐','御定全唐诗','yuding','','[]','芙蓉秦地沼，盧橘漢家園。穀轉斜盤徑，川回曲抱原。',48,'御定全唐詩/json/052.json','["芙蓉秦地沼，盧橘漢家園。穀轉斜盤徑，川回曲抱原。", "風來花自舞，春入鳥能言。侍宴瑤池夕，歸途笳吹繁。"]'),
('yuding-2','夏日仙萼亭應制','宋之問','唐','御定全唐诗','yuding','','[]','高嶺逼星河，乘輿此日過。野含時雨潤，山雜夏雲多。',48,'御定全唐詩/json/052.json','["高嶺逼星河，乘輿此日過。野含時雨潤，山雜夏雲多。", "睿藻光岩穴，宸襟洽薜蘿。悠然小天下，歸路滿笙歌。"]'),
('yuding-3','奉和九月九日登慈恩寺浮屠應制','宋之問','唐','御定全唐诗','yuding','','[]','鳳刹侵雲半，虹旌倚日邊。散花多寶塔，張樂布金田。',48,'御定全唐詩/json/052.json','["鳳刹侵雲半，虹旌倚日邊。散花多寶塔，張樂布金田。", "時菊芳仙醞，秋蘭動睿篇。香街稍欲晚，清蹕扈歸天。"]'),
('yuding-4','奉和九日幸臨渭亭登高應制得歡字','宋之問','唐','御定全唐诗','yuding','','[]','令節三秋晚，重陽九日歡。仙杯還泛菊，寶饌且調蘭。',48,'御定全唐詩/json/052.json','["令節三秋晚，重陽九日歡。仙杯還泛菊，寶饌且調蘭。", "禦氣雲霄近，乘高宇宙寬。今朝萬壽引，宜向曲中彈。"]'),
('yuding-5','奉和聖制閏九月九日登莊嚴總持二寺閣','宋之問','唐','御定全唐诗','yuding','','[]','閏月再重陽，仙輿曆寶坊。帝歌雲稍白，禦酒菊猶黃。',48,'御定全唐詩/json/052.json','["閏月再重陽，仙輿曆寶坊。帝歌雲稍白，禦酒菊猶黃。", "風鐸喧行漏，天花拂舞行。豫游多景福，梵宇日生光。"]'),
('yuding-6','麟趾殿侍宴應制','宋之問','唐','御定全唐诗','yuding','','[]','北闕層城峻，西宮複道懸。乘輿曆萬戶，置酒望三川。',48,'御定全唐詩/json/052.json','["北闕層城峻，西宮複道懸。乘輿曆萬戶，置酒望三川。", "花柳含丹日，山河入綺筵。欲知陪賞處，空外有飛煙。"]'),
('yuding-7','上陽宮侍宴應制得林字','宋之問','唐','御定全唐诗','yuding','','[]','廣樂張前殿，重裘感聖心。砌蓂霜月盡，庭樹雪雲深。',48,'御定全唐詩/json/052.json','["廣樂張前殿，重裘感聖心。砌蓂霜月盡，庭樹雪雲深。", "舊渥驂宸禦，慈恩忝翰林。微臣一何幸，再得聽瑤琴。"]'),
('yuding-8','幸少林寺應制','宋之問','唐','御定全唐诗','yuding','','[]','紺宇橫天室，回鑾指帝休。曙陰迎日盡，春氣抱岩流。',48,'御定全唐詩/json/052.json','["紺宇橫天室，回鑾指帝休。曙陰迎日盡，春氣抱岩流。", "空樂繁行漏，香煙薄彩斿。玉膏從此泛，仙馭接浮丘。"]'),
('yuding-9','幸嶽寺應制','宋之問','唐','御定全唐诗','yuding','','[]','暫幸珠筵地，俱憐石瀨清。泛流張翠幕，拂迥掛紅旌。',48,'御定全唐詩/json/052.json','["暫幸珠筵地，俱憐石瀨清。泛流張翠幕，拂迥掛紅旌。", "雅曲龍調管，芳樽蟻泛觥。陪歡玉座晚，複得聽金聲。"]'),
('yuding-10','扈從登封途中作','宋之問','唐','御定全唐诗','yuding','','[]','帳殿鬱崔嵬，仙遊實壯哉。曉雲連幕卷，夜火雜星回。',48,'御定全唐詩/json/052.json','["帳殿鬱崔嵬，仙遊實壯哉。曉雲連幕卷，夜火雜星回。", "穀暗千旗出，山鳴萬乘來。扈從良可賦，終乏掞天才。"]'),
('yuding-11','扈從登封告成頌','宋之問','唐','御定全唐诗','yuding','','[]','複道開行殿，鉤陳列禁兵。和風吹鼓角，佳氣動旗旌。',48,'御定全唐詩/json/052.json','["複道開行殿，鉤陳列禁兵。和風吹鼓角，佳氣動旗旌。", "後騎回天苑，前山入禦營。萬方俱下拜，相與樂升平。"]'),
('yuding-12','松山嶺應制','宋之問','唐','御定全唐诗','yuding','','[]','翼翼高旌轉，鏘鏘鳳輦飛。塵銷清蹕路，雲濕從臣衣。',48,'御定全唐詩/json/052.json','["翼翼高旌轉，鏘鏘鳳輦飛。塵銷清蹕路，雲濕從臣衣。", "白羽搖丹壑，天營逼翠微。芳聲耀今古，四海警宸威。"]'),
('yuding-13','緱山廟','宋之問','唐','御定全唐诗','yuding','','[]','王子賓仙去，飄颻笙鶴飛。徒聞滄海變，不見白雲歸。',48,'御定全唐詩/json/052.json','["王子賓仙去，飄颻笙鶴飛。徒聞滄海變，不見白雲歸。", "天路何其遠，人間此會稀。空歌日雲幕，霜月漸微微。"]'),
('yuding-14','奉和梁王宴龍泓應教得微字','宋之問','唐','御定全唐诗','yuding','','[]','水府淪幽壑，星軺下紫微。鳥驚司僕馭，花落侍臣衣。',48,'御定全唐詩/json/052.json','["水府淪幽壑，星軺下紫微。鳥驚司僕馭，花落侍臣衣。", "芳樹搖春晚，晴雲繞座飛。淮王正留客，不醉莫言歸。"]'),
('yuding-15','壽陽王花燭圖','宋之問','唐','御定全唐诗','yuding','','[]','仙媛乘龍日，天孫捧雁來。可憐桃李樹，更繞鳳凰台。',48,'御定全唐詩/json/052.json','["仙媛乘龍日，天孫捧雁來。可憐桃李樹，更繞鳳凰台。", "燭照香車入，花臨寶扇開。莫令銀箭曉，為盡合歡杯。"]'),
('yuding-16','江南曲','宋之問','唐','御定全唐诗','yuding','','[]','妾住越城南，離居不自堪。采花驚曙鳥，摘葉喂春蠶。',48,'御定全唐詩/json/052.json','["妾住越城南，離居不自堪。采花驚曙鳥，摘葉喂春蠶。", "懶結茱萸帶，愁安玳瑁簪。待君消瘦盡，日暮碧江潭。"]'),
('yuding-17','牛女','宋之問','唐','御定全唐诗','yuding','','[]','粉席秋期緩，針樓別怨多。奔龍爭渡月，飛鵲亂填河。',48,'御定全唐詩/json/052.json','["粉席秋期緩，針樓別怨多。奔龍爭渡月，飛鵲亂填河。", "失喜先臨鏡，含羞未解羅。誰能留夜色，來夕倍還梭。"]'),
('yuding-18','冬夜寓直麟閣','宋之問','唐','御定全唐诗','yuding','','[]','直事披三省，重關閉七門。廣庭憐雪淨，深屋喜爐溫。',48,'御定全唐詩/json/052.json','["直事披三省，重關閉七門。廣庭憐雪淨，深屋喜爐溫。", "月幌花虛馥，風窗竹暗喧。東山白雲意，茲夕寄琴尊。"]'),
('yuding-19','登禪定寺閣','宋之問','唐','御定全唐诗','yuding','','[]','梵宇出三天，登臨望八川。開襟坐霄漢，揮手拂雲煙。',48,'御定全唐詩/json/052.json','["梵宇出三天，登臨望八川。開襟坐霄漢，揮手拂雲煙。", "函谷青山外，昆池落日邊。東京楊柳陌，少別已經年。"]'),
('yuding-20','陸渾山莊','宋之問','唐','御定全唐诗','yuding','','[]','歸來物外情，負杖閱岩耕。源水看花入，幽林采藥行。',48,'御定全唐詩/json/052.json','["歸來物外情，負杖閱岩耕。源水看花入，幽林采藥行。", "野人相問姓，山鳥自呼名。去去獨吾樂，無然愧此生。"]'),
('yuding-21','藍田山莊','宋之問','唐','御定全唐诗','yuding','','[]','宦遊非吏隱，心事好幽偏。考室先依地，為農且用天。',48,'御定全唐詩/json/052.json','["宦遊非吏隱，心事好幽偏。考室先依地，為農且用天。", "輞川朝伐木，藍水暮澆田。獨與秦山老，相歡春酒前。"]'),
('yuding-22','春日山家','宋之問','唐','御定全唐诗','yuding','','[]','今日遊何處，春泉洗藥歸。悠然紫芝曲，晝掩白雲扉。',48,'御定全唐詩/json/052.json','["今日遊何處，春泉洗藥歸。悠然紫芝曲，晝掩白雲扉。", "魚樂偏尋藻，人閑屢采薇。丘中無俗事，身世兩相違。"]'),
('yuding-23','春日宴宋主簿山亭得寒字','宋之問','唐','御定全唐诗','yuding','','[]','公子正邀歡，林亭春未蘭。攀岩踐苔易，迷路出花難。',48,'御定全唐詩/json/052.json','["公子正邀歡，林亭春未蘭。攀岩踐苔易，迷路出花難。", "窗覆垂楊暖，階侵瀑水寒。帝城歸路直，留興接鵷鸞。"]'),
('yuding-24','江亭晚望','宋之問','唐','御定全唐诗','yuding','','[]','浩渺浸雲根，煙嵐出遠村。鳥歸沙有跡，帆過浪無痕。',48,'御定全唐詩/json/052.json','["浩渺浸雲根，煙嵐出遠村。鳥歸沙有跡，帆過浪無痕。", "望水知柔性，看山欲斷魂。縱情猶未已，回馬欲黃昏。"]'),
('yuding-25','秋晚遊普耀寺','宋之問','唐','御定全唐诗','yuding','','[]','薄暮曲江頭，仁祠暫可留。山形無隱霽，野色遍呈秋。',48,'御定全唐詩/json/052.json','["薄暮曲江頭，仁祠暫可留。山形無隱霽，野色遍呈秋。", "荷覆香泉密，藤緣寶樹幽。平生厭塵事，過此忽悠悠。"]'),
('yuding-26','答李司戶夔','宋之問','唐','御定全唐诗','yuding','','[]','遠方來下客，輶軒攝使臣。弄琴宜在夜，傾酒貴逢春。',48,'御定全唐詩/json/052.json','["遠方來下客，輶軒攝使臣。弄琴宜在夜，傾酒貴逢春。", "駟馬留孤館，雙魚贈故人。明朝散雲雨，遙仰德為鄰。"]'),
('yuding-27','寄天臺司馬道士','宋之問','唐','御定全唐诗','yuding','','[]','臥來生白髮，覽鏡忽成絲。遠愧餐霞子，童顏且自持。',48,'御定全唐詩/json/052.json','["臥來生白髮，覽鏡忽成絲。遠愧餐霞子，童顏且自持。", "舊遊惜疏曠，微尚日磷緇。不寄西山藥，何由東海期。"]'),
('yuding-28','使往天平軍馬約與陳子昂新鄉為期，及還而不相遇','宋之問','唐','御定全唐诗','yuding','','[]','入衛期之子，籲嗟不少留。情人去何處，淇水日悠悠。',48,'御定全唐詩/json/052.json','["入衛期之子，籲嗟不少留。情人去何處，淇水日悠悠。", "恒碣青雲斷，衡漳白露秋。知君心許國，不是愛封侯。"]'),
('yuding-29','過函谷關','宋之問','唐','御定全唐诗','yuding','','[]','二百四十載，海內何紛紛。六國兵同合，七雄勢未分。',48,'御定全唐詩/json/052.json','["二百四十載，海內何紛紛。六國兵同合，七雄勢未分。", "從成拒秦帝，策決問蘇君。雞鳴將狗盜，論德不論勳。"]'),
('yuding-30','送朔方何侍郎','宋之問','唐','御定全唐诗','yuding','','[]','聞道雲中使，乘驄往復還。河兵守陽月，塞虜失陰山。',48,'御定全唐詩/json/052.json','["聞道雲中使，乘驄往復還。河兵守陽月，塞虜失陰山。", "拜職嘗隨驃，銘功不讓班。旋聞受降日，歌舞入蕭關。"]'),
('yuding-31','送田道士使蜀投龍','宋之問','唐','御定全唐诗','yuding','','[]','風馭忽泠然，雲台路幾千。蜀門峰勢斷，巴字水形連。',48,'御定全唐詩/json/052.json','["風馭忽泠然，雲台路幾千。蜀門峰勢斷，巴字水形連。", "人隔壺中地，龍遊洞裏天。贈言回馭日，圖畫彼山川。"]'),
('yuding-32','送許州宋司馬赴任','宋之問','唐','御定全唐诗','yuding','','[]','潁郡水東流，荀陳兄弟游。偏傷茲日遠，獨向聚星州。',48,'御定全唐詩/json/052.json','["潁郡水東流，荀陳兄弟游。偏傷茲日遠，獨向聚星州。", "河潤在明德，人康非外求。當聞力為政，遙慰我心愁。"]'),
('yuding-33','送趙司馬赴蜀州','宋之問','唐','御定全唐诗','yuding','','[]','餞子西南望，煙綿劍道微。橋寒金雁落，林曙碧雞飛。',48,'御定全唐詩/json/052.json','["餞子西南望，煙綿劍道微。橋寒金雁落，林曙碧雞飛。", "職拜輿方遠，仙成履會歸。定知和氏璧，遙掩玉輪輝。"]'),
('yuding-34','送永昌蕭贊府','宋之問','唐','御定全唐诗','yuding','','[]','柳變曲江頭，送君函谷遊。弄琴寬別意，酌醴醉春愁。',48,'御定全唐詩/json/052.json','["柳變曲江頭，送君函谷遊。弄琴寬別意，酌醴醉春愁。", "戀本亦何極，贈言微所求。莫令金谷水，不入故園流。"]'),
('yuding-35','送李侍禦','宋之問','唐','御定全唐诗','yuding','','[]','行李戀庭闈，乘軺振彩衣。南登指吳服，北走出秦畿。',48,'御定全唐詩/json/052.json','["行李戀庭闈，乘軺振彩衣。南登指吳服，北走出秦畿。", "去國夏雲斷，還鄉秋雁飛。旋聞郡計入，更有使臣歸。"]'),
('yuding-36','餞湖州薛司馬','宋之問','唐','御定全唐诗','yuding','','[]','別駕促嚴程，離筵多故情。交深季作友，義重伯為兄。',48,'御定全唐詩/json/052.json','["別駕促嚴程，離筵多故情。交深季作友，義重伯為兄。", "鎮靜移吳俗，風流在漢京。會看陳仲舉，從此拜公卿。"]'),
('yuding-37','送杜審言','宋之問','唐','御定全唐诗','yuding','','[]','臥病人事絕，嗟君萬里行。河橋不相送，江樹遠含情。',48,'御定全唐詩/json/052.json','["臥病人事絕，嗟君萬里行。河橋不相送，江樹遠含情。", "別路追孫楚，維舟吊屈平。可惜龍泉劍，流落在豐城。"]'),
('yuding-38','送武進鄭明府','宋之問','唐','御定全唐诗','yuding','','[]','弦歌試宰日，城闕賞心違。北謝蒼龍去，南隨黃鵠飛。',48,'御定全唐詩/json/052.json','["弦歌試宰日，城闕賞心違。北謝蒼龍去，南隨黃鵠飛。", "夏雲海中出，吳山江上微。甿謠豈雲遠，從此慶緇衣。"]'),
('yuding-39','送姚侍禦出使江東','宋之問','唐','御定全唐诗','yuding','','[]','帝憂河朔郡，南發海陵倉。坐歎青春別，逶迤碧水長。',48,'御定全唐詩/json/052.json','["帝憂河朔郡，南發海陵倉。坐歎青春別，逶迤碧水長。", "飲冰朝受命，衣錦晝還鄉。為問東山桂，無人何自芳。"]'),
('yuding-40','留別之望舍弟','宋之問','唐','御定全唐诗','yuding','','[]','同氣有三人，分飛在此晨。西馳巴嶺徼，東去洛陽濱。',48,'御定全唐詩/json/052.json','["同氣有三人，分飛在此晨。西馳巴嶺徼，東去洛陽濱。", "強飲離前酒，終傷別後神。誰憐散花萼，獨赴日南春。"]'),
('yuding-41','漢江宴別','宋之問','唐','御定全唐诗','yuding','','[]','漢廣不分天，舟移杳若仙。秋虹映晚日，江鶴弄晴煙。',48,'御定全唐詩/json/052.json','["漢廣不分天，舟移杳若仙。秋虹映晚日，江鶴弄晴煙。", "積水浮冠蓋，遙風逐管弦。嬉遊不可極，留恨此山川。"]'),
('yuding-42','初發荊府贈長史','宋之問','唐','御定全唐诗','yuding','','[]','□□□□□，□□□□□。仍隨五馬謫，載與兩禽奔。',48,'御定全唐詩/json/052.json','["□□□□□，□□□□□。仍隨五馬謫，載與兩禽奔。", "明主無由見，群公莫與言。幸君逢聖日，何惜理虞翻。"]'),
('yuding-43','晚泊湘江','宋之問','唐','御定全唐诗','yuding','','[]','五嶺恓惶客，三湘憔悴顏。況複秋雨霽，表裏見衡山。',48,'御定全唐詩/json/052.json','["五嶺恓惶客，三湘憔悴顏。況複秋雨霽，表裏見衡山。", "路逐鵬南轉，心依雁北還。唯餘望鄉淚，更染竹成斑。"]'),
('yuding-44','過蠻洞','宋之問','唐','御定全唐诗','yuding','','[]','越嶺千重合，蠻溪十裏斜。竹迷樵子徑，萍匝釣人家。',48,'御定全唐詩/json/052.json','["越嶺千重合，蠻溪十裏斜。竹迷樵子徑，萍匝釣人家。", "林暗交楓葉，園香覆橘花。誰憐在荒外，孤賞足雲霞。"]'),
('yuding-45','經梧州','宋之問','唐','御定全唐诗','yuding','','[]','南國無霜霰，連年見物華。青林暗換葉，紅蕊續開花。',48,'御定全唐詩/json/052.json','["南國無霜霰，連年見物華。青林暗換葉，紅蕊續開花。", "春去聞山鳥，秋來見海槎。流芳雖可悅，會自泣長沙。"]'),
('yuding-46','渡吳江別王長史','宋之問','唐','御定全唐诗','yuding','','[]','倚棹望茲川，銷魂獨黯然。鄉連江北樹，雲斷日南天。',48,'御定全唐詩/json/052.json','["倚棹望茲川，銷魂獨黯然。鄉連江北樹，雲斷日南天。", "劍別龍初沒，書成雁不傳。離舟意無限，催渡複催年。"]'),
('yuding-47','泛鏡湖南溪','宋之問','唐','御定全唐诗','yuding','','[]','乘興入幽棲，舟行日向低。岩花候冬發，穀鳥作春啼。',48,'御定全唐詩/json/052.json','["乘興入幽棲，舟行日向低。岩花候冬發，穀鳥作春啼。", "遝嶂開天小，叢篁夾路迷。猶聞可憐處，更在若邪溪。"]'),
('yuding-48','途中寒食題黃梅臨江驛寄崔融','宋之問','唐','御定全唐诗','yuding','','[]','馬上逢寒食，愁中屬暮春。可憐江浦望，不見洛陽人。',48,'御定全唐詩/json/052.json','["馬上逢寒食，愁中屬暮春。可憐江浦望，不見洛陽人。", "北極懷明主，南溟作逐臣。故園腸斷處，日夜柳條新。"]'),
('yuding-49','遊韶州廣界寺','宋之問','唐','御定全唐诗','yuding','','[]','影殿臨丹壑，香台隱翠霞。巢飛銜象鳥，砌蹋雨空花。',48,'御定全唐詩/json/052.json','["影殿臨丹壑，香台隱翠霞。巢飛銜象鳥，砌蹋雨空花。", "寶鐸搖初霽，金池映晚沙。莫愁歸路遠，門外有三車。"]'),
('yuding-50','宿清遠峽山寺','宋之問','唐','御定全唐诗','yuding','','[]','香岫懸金刹，飛泉屆石門。空山唯習靜，中夜寂無喧。',48,'御定全唐詩/json/052.json','["香岫懸金刹，飛泉屆石門。空山唯習靜，中夜寂無喧。", "說法初聞鳥，看心欲定猿。寥寥隔塵市，何異武陵源。"]'),
('yuding-51','題大庾嶺北驛','宋之問','唐','御定全唐诗','yuding','','[]','陽月南飛雁，傳聞至此回。我行殊未已，何日複歸來。',48,'御定全唐詩/json/052.json','["陽月南飛雁，傳聞至此回。我行殊未已，何日複歸來。", "江靜潮初落，林昏瘴不開。明朝望鄉處，應見隴頭梅。"]'),
('yuding-52','度大庾嶺','宋之問','唐','御定全唐诗','yuding','','[]','度嶺方辭國，停軺一望家。魂隨南翥鳥，淚盡北枝花。',48,'御定全唐詩/json/052.json','["度嶺方辭國，停軺一望家。魂隨南翥鳥，淚盡北枝花。", "山雨初含霽，江雲欲變霞。但令歸有日，不敢恨長沙。"]'),
('yuding-53','端州別袁侍郎','宋之問','唐','御定全唐诗','yuding','','[]','合浦途未極，端溪行暫臨。淚來空泣臉，愁至不知心。',48,'御定全唐詩/json/052.json','["合浦途未極，端溪行暫臨。淚來空泣臉，愁至不知心。", "客醉山月靜，猿啼江樹深。明朝共分手，之子愛千金。"]'),
('yuding-54','過史正議宅','宋之問','唐','御定全唐诗','yuding','','[]','舊交此零落，雨泣訪遺塵。劍幾傳好事，池台傷故人。',48,'御定全唐詩/json/052.json','["舊交此零落，雨泣訪遺塵。劍幾傳好事，池台傷故人。", "國香蘭已歇，裏樹橘猶新。不見吳中隱，空餘江海濱。"]'),
('yuding-55','梁宣王挽詞三首','宋之問','唐','御定全唐诗','yuding','','[]','貴藩堯母族，外戚漢家親。業重興王際，功高復辟辰。',144,'御定全唐詩/json/052.json','["貴藩堯母族，外戚漢家親。業重興王際，功高復辟辰。", "愛賢唯報國，樂善不防身。今日衣冠送，空傷置醴人。", "金精何日閉，玉匣此時開。東望連吾子，南瞻近帝台。", "地形龜食報，墳土燕銜來。可歎虞歌夕，紛紛騎吹回。", "像設千年在，平生萬事違。彩旌翻葆吹，圭翣奠靈衣。", "壟日寒無影，郊雲凍不飛。君王留此地，駟馬欲何歸。"]'),
('yuding-56','魯忠王挽詞三首','宋之問','唐','御定全唐诗','yuding','','[]','同盟會五月，歸葬出三條。日慘咸陽樹，天寒渭水橋。',144,'御定全唐詩/json/052.json','["同盟會五月，歸葬出三條。日慘咸陽樹，天寒渭水橋。", "稍看朱鷺轉，尚識紫騮驕。寂寂泉台恨，從茲罷玉簫。", "邦家錫寵光，存沒貴忠良。遂裂山河地，追尊父子王。", "人悲槐裏月，馬踏槿原霜。別向天京北，悠悠此路長。", "樹羽迎朝日，撞鐘望早霞。故人悲宿草，中使慘晨笳。", "氣有沖天劍，星無犯鬥槎。唯餘孔公宅，長接魯王家。"]'),
('yuding-57','范陽王挽詞二首','宋之問','唐','御定全唐诗','yuding','','[]','賢相稱邦傑，清流舉代推。公才掩諸夏，文體變當時。',96,'御定全唐詩/json/052.json','["賢相稱邦傑，清流舉代推。公才掩諸夏，文體變當時。", "賓吊翻成鶴，人亡惜喻龜。洛陽今紙貴，猶寫太沖詞。", "贈秩徽章洽，求書秘草成。客隨朝露盡，人逐夜舟驚。", "蒿裏衣冠送，松門印綬迎。誰知楊伯起，今日重哀榮。"]'),
('yuding-58','故趙王屬贈黃門侍郎上官公挽詞二首','宋之問','唐','御定全唐诗','yuding','','[]','韋門旌舊德，班氏業前書。謫去因丞相，歸來為婕妤。',96,'御定全唐詩/json/052.json','["韋門旌舊德，班氏業前書。謫去因丞相，歸來為婕妤。", "周原烏相塚，越嶺雁隨車。冥漠辭昭代，空憐賦子虛。", "綠車隨帝子，青瑣翊宸機。昔枉朝歌騎，今虛夕拜闈。", "柳河淒挽曲，薤露濕靈衣。一厝窮泉閉，雙鸞遂不飛。"]'),
('yuding-59','藥','宋之問','唐','御定全唐诗','yuding','','[]','有卉秘神仙，君臣有禮焉。忻當苦口喻，不畏入腸偏。',48,'御定全唐詩/json/052.json','["有卉秘神仙，君臣有禮焉。忻當苦口喻，不畏入腸偏。", "扁鵲功成日，神農定品年。丹成如可待，雞犬自聞天。"]'),
('yuding-60','奉和九日登慈恩寺浮圖應制','宋之問','唐','御定全唐诗','yuding','','[]','瑞塔千尋起，仙輿九日來。萸房陳寶席，菊蕊散花台。',48,'御定全唐詩/json/052.json','["瑞塔千尋起，仙輿九日來。萸房陳寶席，菊蕊散花台。", "禦氣鵬霄近，升高鳳野開。天歌將梵樂，空裏共裴回。"]'),
('yuding-61','送沙門泓景道俊玄奘還荊州應制','宋之問','唐','御定全唐诗','yuding','','[]','三乘歸淨域，萬騎餞通莊。就日離亭近，彌天別路長。',48,'御定全唐詩/json/052.json','["三乘歸淨域，萬騎餞通莊。就日離亭近，彌天別路長。", "荊南旋杖缽，渭北限津梁。何日紆真果，還來入帝鄉。"]'),
('yuding-62','春日芙蓉園侍宴應制','宋之問','唐','御定全唐诗','yuding','','[]','年光竹裏遍，春色杏間遙。煙氣籠青閣，流文蕩畫橋。',48,'御定全唐詩/json/052.json','["年光竹裏遍，春色杏間遙。煙氣籠青閣，流文蕩畫橋。", "飛花隨蝶舞，豔曲伴鶯嬌。今日陪歡豫，還疑陟紫霄。"]'),
('yuding-63','詠笛','宋之問','唐','御定全唐诗','yuding','','[]','羌笛寫龍聲，長吟入夜清。關山孤月下，來向隴頭鳴。',48,'御定全唐詩/json/052.json','["羌笛寫龍聲，長吟入夜清。關山孤月下，來向隴頭鳴。", "逐吹梅花落，含春柳色驚。行觀向子賦，坐憶舊鄰情。"]'),
('yuding-64','詠鐘','宋之問','唐','御定全唐诗','yuding','','[]','既接南鄰磬，還隨北裏笙。平陵通曙響，長樂警宵聲。',48,'御定全唐詩/json/052.json','["既接南鄰磬，還隨北裏笙。平陵通曙響，長樂警宵聲。", "秋至含霜動，春歸應律鳴。豈惟恒待扣，金簴有餘清。"]'),
('yuding-65','花落','宋之問','唐','御定全唐诗','yuding','','[]','鐵騎幾時回，金閨怨早梅。雪寒花已落，風暖葉還開。',48,'御定全唐詩/json/052.json','["鐵騎幾時回，金閨怨早梅。雪寒花已落，風暖葉還開。", "夕逐新春管，香迎小歲杯。盛時何足貴，書裏報輪台。"]'),
('yuding-66','旅宿淮陽亭口號','宋之問','唐','御定全唐诗','yuding','','[]','日暮風亭上，悠悠旅思多。故鄉臨桂水，今夜渺星河。',48,'御定全唐詩/json/052.json','["日暮風亭上，悠悠旅思多。故鄉臨桂水，今夜渺星河。", "暗草霜華髮，空亭雁影過。興來誰與語，勞者自為歌。"]'),
('yuding-67','內題賦得巫山雨','宋之問','唐','御定全唐诗','yuding','','[]','神女向高唐，巫山下夕陽。裴回作行雨，婉戀逐荊王。',48,'御定全唐詩/json/052.json','["神女向高唐，巫山下夕陽。裴回作行雨，婉戀逐荊王。", "電影江前落，雷聲峽外長。霽雲無處所，台館曉蒼蒼。"]'),
('yuding-68','王昭君','宋之問','唐','御定全唐诗','yuding','','[]','非君惜鸞殿，非妾妒娥眉。薄命由驕虜，無情是畫師。',48,'御定全唐詩/json/052.json','["非君惜鸞殿，非妾妒娥眉。薄命由驕虜，無情是畫師。", "嫁來胡地日，不並漢宮時。辛苦無聊賴，何堪上馬辭。"]'),
('yuding-69','銅雀台','宋之問','唐','御定全唐诗','yuding','','[]','昔年分鼎地，今日望陵台。一旦雄圖盡，千秋遺令開。',48,'御定全唐詩/json/052.json','["昔年分鼎地，今日望陵台。一旦雄圖盡，千秋遺令開。", "綺羅君不見，歌舞妾空來。恩共漳河水，東流無重回。"]'),
('yuding-70','巫山高','宋之問','唐','御定全唐诗','yuding','','[]','巫山峰十二，環合象昭回。俯聽琵琶峽，平看雲雨台。',48,'御定全唐詩/json/052.json','["巫山峰十二，環合象昭回。俯聽琵琶峽，平看雲雨台。", "古槎天外落，瀑水日邊來。何忍猿啼夜，荊王枕席開。"]'),
('yuding-71','望月有懷','宋之問','唐','御定全唐诗','yuding','','[]','天使下西樓，含光萬里秋。台前似掛鏡，簾外如懸鉤。',48,'御定全唐詩/json/052.json','["天使下西樓，含光萬里秋。台前似掛鏡，簾外如懸鉤。", "張尹將眉學，班姬取扇儔。佳期應借問，為報大刀頭。"]'),
('yuding-72','駕出長安','宋之問','唐','御定全唐诗','yuding','','[]','聖德超千古，皇風扇九圍。天回萬象出，駕動六龍飛。',48,'御定全唐詩/json/052.json','["聖德超千古，皇風扇九圍。天回萬象出，駕動六龍飛。", "淑氣來黃道，祥雲覆紫微。太平多扈從，文物有光輝。"]'),
('yuding-73','餞中書侍郎來濟','宋之問','唐','御定全唐诗','yuding','','[]','曖曖去塵昏灞岸，飛飛輕蓋指河梁。雲峰衣結千重葉，',40,'御定全唐詩/json/052.json','["曖曖去塵昏灞岸，飛飛輕蓋指河梁。雲峰衣結千重葉，", "卻將分手沾襟淚，還用持添離席觴。"]'),
('yuding-74','奉和春初幸太平公主南莊應制','宋之問','唐','御定全唐诗','yuding','','[]','青門路接鳳凰台，素滻宸游龍騎來。澗草自迎香輦合，',40,'御定全唐詩/json/052.json','["青門路接鳳凰台，素滻宸游龍騎來。澗草自迎香輦合，", "此日侍臣將石去，共歡明主賜金回。"]'),
('yuding-75','三陽宮侍宴應制得幽字','宋之問','唐','御定全唐诗','yuding','','[]','離宮秘苑勝瀛洲，別有仙人洞壑幽。岩邊樹色含風冷，',40,'御定全唐詩/json/052.json','["離宮秘苑勝瀛洲，別有仙人洞壑幽。岩邊樹色含風冷，", "微臣昔忝方明禦，今日還陪八駿遊。"]'),
('yuding-0','奉和晦日幸昆明池應制','宋之問','唐','御定全唐诗','yuding','','[]','春豫靈池會，滄波帳殿開。舟淩石鯨度，槎拂鬥牛回。',72,'御定全唐詩/json/053.json','["春豫靈池會，滄波帳殿開。舟淩石鯨度，槎拂鬥牛回。", "節晦蓂全落，春遲柳暗催。象溟看浴景，燒劫辨沉灰。", "鎬飲周文樂，汾歌漢武才。不愁明月盡，自有夜珠來。"]'),
('yuding-1','奉和幸大薦福寺','宋之問','唐','御定全唐诗','yuding','','[]','香刹中天起，宸游滿路輝。乘龍太子去，駕象法王歸。',72,'御定全唐詩/json/053.json','["香刹中天起，宸游滿路輝。乘龍太子去，駕象法王歸。", "殿飾金人影，窗搖玉女扉。稍迷新草木，遍識舊庭闈。", "水入禪心定，雲從寶思飛。欲知皇劫遠，初拂六銖衣。"]'),
('yuding-2','奉和幸三會寺應制','宋之問','唐','御定全唐诗','yuding','','[]','六飛回玉輦，雙樹謁金仙。瑞鳥呈書字，神龍吐浴泉。',72,'御定全唐詩/json/053.json','["六飛回玉輦，雙樹謁金仙。瑞鳥呈書字，神龍吐浴泉。", "淨心遙證果，睿想獨超禪。塔湧香花地，山圍日月天。", "梵音迎漏徹，空樂倚雲懸。今日登仁壽，長看法鏡圓。"]'),
('yuding-3','奉和薦福寺應制','宋之問','唐','御定全唐诗','yuding','','[]','梵筵光聖邸，遊豫覽宏規。不改靈光殿，因開功德池。',72,'御定全唐詩/json/053.json','["梵筵光聖邸，遊豫覽宏規。不改靈光殿，因開功德池。", "蓮生新步葉，桂長昔攀枝。湧塔庭中見，飛樓海上移。", "聞韶三月幸，觀象七星危。欲識龍歸處，朝朝雲氣隨。"]'),
('yuding-4','奉和幸神皋亭應制','宋之問','唐','御定全唐诗','yuding','','[]','清蹕喧黃道，乘輿降紫宸。霜戈凝曉日，雲管發陽春。',72,'御定全唐詩/json/053.json','["清蹕喧黃道，乘輿降紫宸。霜戈凝曉日，雲管發陽春。", "台古全疑漢，林餘半識秦。宴酣詩布澤，節改令行仁。", "昔恃山河險，今依道德淳。多慚獻嘉頌，空累屬車塵。"]'),
('yuding-5','奉和幸長安故城未央宮應制','宋之問','唐','御定全唐诗','yuding','','[]','漢王未息戰，蕭相乃營宮。壯麗一朝盡，威靈千載空。',72,'御定全唐詩/json/053.json','["漢王未息戰，蕭相乃營宮。壯麗一朝盡，威靈千載空。", "皇明悵前跡，置酒宴群公。寒輕彩仗外，春發幔城中。", "樂思回斜日，歌詞繼大風。今朝天子貴，不假叔孫通。"]'),
('yuding-6','奉和幸韋嗣立山莊侍宴應制','宋之問','唐','御定全唐诗','yuding','','[]','樞掖調梅暇，林園藝槿初。入朝榮劍履，退食偶琴書。',96,'御定全唐詩/json/053.json','["樞掖調梅暇，林園藝槿初。入朝榮劍履，退食偶琴書。", "地隱東岩室，天回北斗車。旌門臨窈窕，輦道屬扶疏。", "雲罕明丹壑，霜笳徹紫虛。水疑投石處，溪似釣璜餘。", "帝澤頒卮酒，人歡頌裏閭。一承黃竹詠，長奉白茅居。"]'),
('yuding-7','扈從登封告成頌應制','宋之問','唐','御定全唐诗','yuding','','[]','禦路回中嶽，天營接下都。百靈無後至，萬國競前驅。',96,'御定全唐詩/json/053.json','["禦路回中嶽，天營接下都。百靈無後至，萬國競前驅。", "文衛嚴清蹕，幽仙讀寶符。貝花明漢果，芝草入堯廚。", "濟濟衣冠會，喧喧夷夏俱。宗禋仰神理，刊木望川途。", "撫己貧非病，時來本不愚。願陪丹鳳輦，率舞白雲衢。"]'),
('yuding-8','宴安樂公主宅得空字','宋之問','唐','御定全唐诗','yuding','','[]','英藩築外館，愛主出王宮。賓至星槎落，仙來月宇空。',72,'御定全唐詩/json/053.json','["英藩築外館，愛主出王宮。賓至星槎落，仙來月宇空。", "玳梁翻賀燕，金埒倚晴虹。簫奏秦台裏，書開魯壁中。", "短歌能駐日，豔舞欲嬌風。聞有淹留處，山阿滿桂叢。"]'),
('yuding-9','春日鄭協律山亭陪宴餞鄭卿同用樓字','宋之問','唐','御定全唐诗','yuding','','[]','潘園枕郊郭，愛客坐相求。尊酒東城外，驂騑南陌頭。',72,'御定全唐詩/json/053.json','["潘園枕郊郭，愛客坐相求。尊酒東城外，驂騑南陌頭。", "池平分洛水，林缺見嵩丘。暗竹侵山徑，垂楊拂妓樓。", "彩雲歌處斷，遲日舞前留。此地何年別，蘭芳空自幽。"]'),
('yuding-10','和姚給事寓直之作','宋之問','唐','御定全唐诗','yuding','','[]','清論滿朝陽，高才拜夕郎。還從避馬路，來接珥貂行。',96,'御定全唐詩/json/053.json','["清論滿朝陽，高才拜夕郎。還從避馬路，來接珥貂行。", "寵就黃扉日，威回白簡霜。柏台遷鳥茂，蘭署得人芳。", "禁靜鐘初徹，更疏漏漸長。曉河低武庫，流火度文昌。", "寓直恩徽重，乘秋藻翰揚。暗投空欲報，下調不成章。"]'),
('yuding-11','和庫部李員外秋夜寓直之作','宋之問','唐','御定全唐诗','yuding','','[]','相庭貽慶遠，才子拜郎初。起草徯仙閣，焚香臥直廬。',72,'御定全唐詩/json/053.json','["相庭貽慶遠，才子拜郎初。起草徯仙閣，焚香臥直廬。", "更深河欲斷，節勁柳偏疏。氣耿淩雲筆，心搖待漏車。", "叨榮廁儔侶，省己恧空虛。徒斐陽春和，難參麗曲餘。"]'),
('yuding-12','酬李丹徒見贈之作','宋之問','唐','御定全唐诗','yuding','','[]','鎮吳稱奧裏，試劇仰通才。近挹人披霧，遙聞境震雷。',84,'御定全唐詩/json/053.json','["鎮吳稱奧裏，試劇仰通才。近挹人披霧，遙聞境震雷。", "一朝逢解榻，累日共銜杯。連轡登山盡，浮舟望海回。", "以予慚拙宦，期子遇良媒。贈曲南鳧斷，征途北雁催。", "更憐江上月，還入鏡中開。"]'),
('yuding-13','使過襄陽登鳳林寺閣','宋之問','唐','御定全唐诗','yuding','','[]','香閣臨清漢，丹梯隱翠微。林篁天際密，人世穀中違。',72,'御定全唐詩/json/053.json','["香閣臨清漢，丹梯隱翠微。林篁天際密，人世穀中違。", "苔石銜仙洞，蓮舟泊釣磯。山雲浮棟起，江雨入庭飛。", "信美雖南國，嚴程限北歸。幽尋不可再，留步惜芳菲。"]'),
('yuding-14','宋公宅送寧諫議','宋之問','唐','御定全唐诗','yuding','','[]','宋公爰創宅，庾氏更誅茅。間出人三秀，平臨楚四郊。',72,'御定全唐詩/json/053.json','["宋公爰創宅，庾氏更誅茅。間出人三秀，平臨楚四郊。", "漢臣來絳節，荊牧動金鐃。尊溢宜城酒，笙裁曲沃匏。", "露荷秋變節，風柳夕鳴梢。一散陽臺雨，方隨越鳥巢。"]'),
('yuding-15','送合宮蘇明府頲','宋之問','唐','御定全唐诗','yuding','','[]','鉉府誕英規，公才天下知。謂乘羔雁族，繼入鳳凰池。',72,'御定全唐詩/json/053.json','["鉉府誕英規，公才天下知。謂乘羔雁族，繼入鳳凰池。", "赤縣求人隱，青門起路岐。翟回車少別，鳧化舄遙馳。", "神哭周南境，童歌渭北垂。賢哉荀奉倩，袞職佇來儀。"]'),
('yuding-16','送楊六望赴金水','宋之問','唐','御定全唐诗','yuding','','[]','借問梁山道，嶔岑幾萬重。遙州刀作字，絕壁劍為峰。',72,'御定全唐詩/json/053.json','["借問梁山道，嶔岑幾萬重。遙州刀作字，絕壁劍為峰。", "惜別路窮此，留歡意不從。憂來生白髮，時晚愛青松。", "勿以西南遠，夷歌寢盛容。臺階有高位，寧複久臨邛。"]'),
('yuding-17','下桂江龍目灘','宋之問','唐','御定全唐诗','yuding','','[]','停午出灘險，輕舟容易前。峰攢入雲樹，崖噴落江泉。',72,'御定全唐詩/json/053.json','["停午出灘險，輕舟容易前。峰攢入雲樹，崖噴落江泉。", "巨石潛山怪，深篁隱洞仙。鳥遊溪寂寂，猿嘯嶺娟娟。", "揮袂日凡幾，我行途已千。暝投蒼梧郡，愁枕白雲眠。"]'),
('yuding-18','入瀧州江','宋之問','唐','御定全唐诗','yuding','','[]','孤舟泛盈盈，江流日縱橫。夜雜蛟螭寢，晨披瘴癘行。',156,'御定全唐詩/json/053.json','["孤舟泛盈盈，江流日縱橫。夜雜蛟螭寢，晨披瘴癘行。", "潭蒸水沫起，山熱火雲生。猿躩時能嘯，鳶飛莫敢鳴。", "海窮南徼盡，鄉遠北魂驚。泣向文身國，悲看鑿齒氓。", "地偏多育蠱，風惡好相鯨。餘本岩棲客，悠哉慕玉京。", "厚恩嘗願答，薄宦不祈成。違隱乖求志，披荒為近名。", "鏡愁玄發改，心負紫芝榮。運啟中興曆，時逢外域清。", "只應保忠信，延促付神明。"]'),
('yuding-19','始安秋日','宋之問','唐','御定全唐诗','yuding','','[]','桂林風景異，秋似洛陽春。晚霽江天好，分明愁殺人。',60,'御定全唐詩/json/053.json','["桂林風景異，秋似洛陽春。晚霽江天好，分明愁殺人。", "卷雲山𧥄𧥄，碎石水磷磷。世業事黃老，妙年孤隱淪。", "歸歟臥滄海，何物貴吾身。"]'),
('yuding-20','桂州黃潭舜祠','宋之問','唐','御定全唐诗','yuding','','[]','虞世巡百越，相傳葬九疑。精靈遊此地，祠樹日光輝。',72,'御定全唐詩/json/053.json','["虞世巡百越，相傳葬九疑。精靈遊此地，祠樹日光輝。", "禋祭忽群望，丹青圖二妃。神來獸率舞，仙去鳳還飛。", "日暝山氣落，江空潭靄微。帝鄉三萬里，乘彼白雲歸。"]'),
('yuding-21','登粵王台','宋之問','唐','御定全唐诗','yuding','','[]','江上粵王台，登高望幾回。南溟天外合，北戶日邊開。',72,'御定全唐詩/json/053.json','["江上粵王台，登高望幾回。南溟天外合，北戶日邊開。", "地濕煙嘗起，山晴雨半來。冬花采盧橘，夏果摘楊梅。", "跡類虞翻枉，人非賈誼才。歸心不可見，白髮重相催。"]'),
('yuding-22','早發始興江口至虛氏村作','宋之問','唐','御定全唐诗','yuding','','[]','候曉逾閩嶠，乘春望越台。宿雲鵬際落，殘月蚌中開。',96,'御定全唐詩/json/053.json','["候曉逾閩嶠，乘春望越台。宿雲鵬際落，殘月蚌中開。", "薜荔搖青氣，桄榔翳碧苔。桂香多露裛，石響細泉回。", "抱葉玄猿嘯，銜花翡翠來。南中雖可悅，北思日悠哉。", "鬒發俄成素，丹心已作灰。何當首歸路，行剪故園萊。"]'),
('yuding-23','發藤州','宋之問','唐','御定全唐诗','yuding','','[]','朝夕苦遄征，孤魂長自驚。泛舟依雁渚，投館聽猿鳴。',120,'御定全唐詩/json/053.json','["朝夕苦遄征，孤魂長自驚。泛舟依雁渚，投館聽猿鳴。", "石發緣溪蔓，林衣掃地輕。雲峰刻不似，苔蘚畫難成。", "露裛千花氣，泉和萬籟聲。攀幽紅處歇，躋險綠中行。", "戀切芝蘭砌，悲纏松柏塋。丹心江北死，白髮嶺南生。", "魑魅天邊國，窮愁海上城。勞歌意無限，今日為誰明。"]'),
('yuding-24','遊稱心寺','宋之問','唐','御定全唐诗','yuding','','[]','釋事懷三隱，清襟謁四禪。江鳴潮未落，林曉日初懸。',96,'御定全唐詩/json/053.json','["釋事懷三隱，清襟謁四禪。江鳴潮未落，林曉日初懸。", "寶葉交香雨，金沙吐細泉。望諧舟客趣，思發海人煙。", "顧櫪仍留馬，乘杯久棄船。未憂龜負嶽，且識鳥耘田。", "理契都無象，心冥不寄筌。安期庶可揖，天地得齊年。"]'),
('yuding-25','游法華寺','宋之問','唐','御定全唐诗','yuding','','[]','高岫擬耆闍，真乘引妙車。空中結樓殿，意表出雲霞。',120,'御定全唐詩/json/053.json','["高岫擬耆闍，真乘引妙車。空中結樓殿，意表出雲霞。", "後果纏三足，前因感六牙。宴林熏寶樹，水溜滴金沙。", "寒谷梅猶淺，溫庭橘未華。台香紅藥亂，塔影綠篁遮。", "果漸輪王族，緣超梵帝家。晨行踏忍草，夜誦得靈花。", "江郡將何匹，天都亦未加。朝來沿泛所，應是逐仙槎。"]'),
('yuding-26','夜渡吳松江懷古','宋之問','唐','御定全唐诗','yuding','','[]','宿帆震澤口，曉渡松江濆。棹發魚龍氣，舟沖鴻雁群。',72,'御定全唐詩/json/053.json','["宿帆震澤口，曉渡松江濆。棹發魚龍氣，舟沖鴻雁群。", "寒潮頓覺滿，暗浦稍將分。氣出海生日，光清湖起雲。", "水鄉盡天衛，歎息為吳君。謀士伏劍死，至今悲所聞。"]'),
('yuding-27','謁禹廟','宋之問','唐','御定全唐诗','yuding','','[]','夏王乘四載，茲地發金符。峻命終不易，報功疇敢渝。',240,'御定全唐詩/json/053.json','["夏王乘四載，茲地發金符。峻命終不易，報功疇敢渝。", "先驅總昌會，後至伏靈誅。玉帛空天下，衣冠照海隅。", "旋聞厭黃屋，更道出蒼梧。林表祠轉茂，山阿井詎枯。", "舟遷龍負壑，田變鳥芸蕪。舊物森如在，天威肅未殊。", "玄夷屆瑤席，玉女侍清都。奕奕扃闈邃，軒軒仗衛趨。", "氣青連曙海，雲白洗春湖。猿嘯有時答，禽言常自呼。", "靈歆異蒸糈，至樂匪笙竽。茅殿今文襲，梅梁古制無。", "運遙日崇麗，業盛答昭蘇。伊昔力雲盡，而今功尚敷。", "揆材非美箭，精享愧生芻。郡職昧為理，邦空寧自誣。", "下車霰已積，攝事露行濡。人隱冀多佑，曷唯沾薄軀。"]'),
('yuding-28','游禹穴回出若邪','宋之問','唐','御定全唐诗','yuding','','[]','禹穴今朝到，邪溪此路通。著書聞太史，煉藥有仙翁。',72,'御定全唐詩/json/053.json','["禹穴今朝到，邪溪此路通。著書聞太史，煉藥有仙翁。", "鶴往籠猶掛，龍飛劍已空。石帆搖海上，天鏡落湖中。", "水低寒雲白，山邊墜葉紅。歸舟何慮晚，日暮使樵風。"]'),
('yuding-29','靈隱寺','宋之問','唐','御定全唐诗','yuding','','[]','鷲嶺鬱岧嶢，龍宮鎖寂寥。樓觀滄海日，門對浙江潮。',84,'御定全唐詩/json/053.json','["鷲嶺鬱岧嶢，龍宮鎖寂寥。樓觀滄海日，門對浙江潮。", "桂子月中落，天香雲外飄。捫蘿登塔遠，刳木取泉遙。", "霜薄花更發，冰輕葉未凋。夙齡尚遐異，搜對滌煩囂。", "待入天臺路，看余度石橋。"]'),
('yuding-30','遊雲門寺','宋之問','唐','御定全唐诗','yuding','','[]','維舟探靜域，作禮事尊經。投跡一蕭散，為心自杳冥。',132,'御定全唐詩/json/053.json','["維舟探靜域，作禮事尊經。投跡一蕭散，為心自杳冥。", "龕依大禹穴，樓倚少微星。遝嶂圍蘭若，回溪抱竹庭。", "覺花塗砌白，甘露洗山青。雁塔鶱金地，虹橋轉翠屏。", "人天宵現景，神鬼晝潛形。理勝常虛寂，緣空自感靈。", "入禪從鴿繞，說法有龍聽。劫累終期滅，塵躬且未寧。", "搖搖不安寐，待月詠岩扃。"]'),
('yuding-31','早發韶州','宋之問','唐','御定全唐诗','yuding','','[]','炎徼行應盡，回瞻鄉路遙。珠厓天外郡，銅柱海南標。',120,'御定全唐詩/json/053.json','["炎徼行應盡，回瞻鄉路遙。珠厓天外郡，銅柱海南標。", "日夜清明少，春冬霧雨饒。身經大火熱，顏入瘴江消。", "觸影含沙怒，逢人女草搖。露濃看菌濕，風颶覺船飄。", "直禦魑將魅，寧論鴟與鴞。虞翻思報國，許靖願歸朝。", "綠樹秦京道，青雲洛水橋。故園長在目，魂去不須招。"]'),
('yuding-32','早入清遠峽','宋之問','唐','御定全唐诗','yuding','','[]','傳聞峽山好，旭日棹前沂。雨色搖丹嶂，泉聲聒翠微。',132,'御定全唐詩/json/053.json','["傳聞峽山好，旭日棹前沂。雨色搖丹嶂，泉聲聒翠微。", "兩岩天作帶，萬壑樹披衣。秋菊迎霜序，春藤礙日輝。", "翳潭花似織，緣嶺竹成圍。寂曆環沙浦，蔥蘢轉石圻。", "露餘江未熱，風落瘴初稀。猿飲排虛上，禽驚掠水飛。", "榜童夷唱合，樵女越吟歸。良候斯為美，邊愁自有違。", "誰言望鄉國，流涕失芳菲。"]'),
('yuding-33','發端州初入西江','宋之問','唐','御定全唐诗','yuding','','[]','問我將何去，清晨溯越溪。翠微懸宿雨，丹壑飲晴霓。',120,'御定全唐詩/json/053.json','["問我將何去，清晨溯越溪。翠微懸宿雨，丹壑飲晴霓。", "樹影捎雲密，藤陰覆水低。潮回出浦駛，洲轉望鄉迷。", "人意長懷北，江行日向西。破顏看鵲喜，拭淚聽猿啼。", "骨肉初分愛，親朋忽解攜。路遙魂欲斷，身辱理能齊。", "疇日三山意，于茲萬緒暌。金陵有仙館，即事尋丹梯。"]'),
('yuding-34','渡漢江','宋之問','唐','御定全唐诗','yuding','','[]','嶺外音書斷，經冬複曆春。近鄉情更怯，不敢問來人。',24,'御定全唐詩/json/053.json','["嶺外音書斷，經冬複曆春。近鄉情更怯，不敢問來人。"]'),
('yuding-35','嵩山夜還','宋之問','唐','御定全唐诗','yuding','','[]','家住嵩山下，好采舊山薇。自省游泉石，何曾不夜歸。',24,'御定全唐詩/json/053.json','["家住嵩山下，好采舊山薇。自省游泉石，何曾不夜歸。"]'),
('yuding-36','湖中別鑒上人','宋之問','唐','御定全唐诗','yuding','','[]','願與道林近，在意逍遙篇。自有靈佳寺，何用沃洲禪。',24,'御定全唐詩/json/053.json','["願與道林近，在意逍遙篇。自有靈佳寺，何用沃洲禪。"]'),
('yuding-37','題鑒上人房二首','宋之問','唐','御定全唐诗','yuding','','[]','落花雙樹積，芳草一庭春。玩之堪興異，何必見幽人。',48,'御定全唐詩/json/053.json','["落花雙樹積，芳草一庭春。玩之堪興異，何必見幽人。", "晚入應真理，經行尚未回。房中無俗物，林下有青苔。"]'),
('yuding-38','答田征君','宋之問','唐','御定全唐诗','yuding','','[]','山遊杳何處，遲回伊洛間。歸寢忽成夢，宛在嵩丘山。',24,'御定全唐詩/json/053.json','["山遊杳何處，遲回伊洛間。歸寢忽成夢，宛在嵩丘山。"]'),
('yuding-39','傷曹娘二首','宋之問','唐','御定全唐诗','yuding','','[]','鳳飛樓伎絕，鸞死鏡臺空。獨憐脂粉氣，猶著舞衣中。',48,'御定全唐詩/json/053.json','["鳳飛樓伎絕，鸞死鏡臺空。獨憐脂粉氣，猶著舞衣中。", "河伯憐嬌態，馮夷要姝妓。寄言遊戲人，莫弄黃河水。"]'),
('yuding-40','河陽','宋之問','唐','御定全唐诗','yuding','','[]','昔日河陽縣，氛氳香氣多。曹娘嬌態盡，春樹不堪過。',24,'御定全唐詩/json/053.json','["昔日河陽縣，氛氳香氣多。曹娘嬌態盡，春樹不堪過。"]'),
('yuding-41','燕巢軍幕','宋之問','唐','御定全唐诗','yuding','','[]','非關憐翠幕，不是厭朱樓。故來呈燕頷，報導欲封侯。',24,'御定全唐詩/json/053.json','["非關憐翠幕，不是厭朱樓。故來呈燕頷，報導欲封侯。"]'),
('yuding-42','苑中遇雪應制','宋之問','唐','御定全唐诗','yuding','','[]','紫禁仙輿詰旦來，青旗遙倚望春台。',32,'御定全唐詩/json/053.json','["紫禁仙輿詰旦來，青旗遙倚望春台。", "不知庭霰今朝落，疑是林花昨夜開。"]'),
('yuding-43','送司馬道士游天臺','宋之問','唐','御定全唐诗','yuding','','[]','羽客笙歌此地違，離筵數處白雲飛。',32,'御定全唐詩/json/053.json','["羽客笙歌此地違，離筵數處白雲飛。", "蓬萊闕下長相憶，桐柏山頭去不歸。"]'),
('yuding-44','登逍遙樓','宋之問','唐','御定全唐诗','yuding','','[]','逍遙樓上望鄉關，綠水泓澄雲霧間。',32,'御定全唐詩/json/053.json','["逍遙樓上望鄉關，綠水泓澄雲霧間。", "北去衡陽二千里，無因雁足系書還。"]'),
('yuding-45','奉和春日玩雪應制','宋之問','唐','御定全唐诗','yuding','','[]','北闕彤雲掩曙霞，東風吹雪舞山家。',32,'御定全唐詩/json/053.json','["北闕彤雲掩曙霞，東風吹雪舞山家。", "瓊章定少千人和，銀樹長芳六出花。"]'),
('yuding-46','傷曹娘二首','宋之問','唐','御定全唐诗','yuding','','[]','可憐冥漠去何之，獨立豐茸無見期。',64,'御定全唐詩/json/053.json','["可憐冥漠去何之，獨立豐茸無見期。", "君看水上芙蓉色，恰似生前歌舞時。", "前溪妙舞今應盡，子夜新歌遂不傳。", "無複綺羅嬌白日，直將珠玉閉黃泉。"]'),
('yuding-47','郡宅中齋','宋之問','唐','御定全唐诗','yuding','','[]','郡宅枕層嶺，春湖繞芳甸。雲甍出萬家，臥覽皆已遍。',216,'御定全唐詩/json/053.json','["郡宅枕層嶺，春湖繞芳甸。雲甍出萬家，臥覽皆已遍。", "漁商汗成雨，廨邑明若練。越俗鏡中行，夏祠雲表見。", "茲都信盤郁，英遠常棲眄。王子事黃老，獨樂恣遊衍。", "謝公念蒼生，同憂感推薦。靈越多秀士，運闊無由面。", "神理翳青山，風流滿黃卷。揆予謬承獎，自昔從纓弁。", "瑤水執仙羈，金閨負時選。晨趨博望苑，夜直明光殿。", "一朝罷台閣，萬里違鄉縣。風土足慰心，況悅年芳變。", "淮廩佇滋實，沂歌非所羨。訟寢歸四明，齡頹親九轉。", "微尚本江海，少留豈交戰。唯餘後凋色，竊比東南箭。"]'),
('yuding-48','稱心寺','宋之問','唐','御定全唐诗','yuding','','[]','步陟招提宮，北極山海觀。千岩遞縈繞，萬壑殊悠漫。',96,'御定全唐詩/json/053.json','["步陟招提宮，北極山海觀。千岩遞縈繞，萬壑殊悠漫。", "喬木轉夕陽，文軒劃清渙。泄雲多表裏，驚潮每昏旦。", "問予金門客，何事滄洲畔。謬以三署資，來刺百城半。", "人隱尚未弭，歲華豈兼玩。東山桂枝芳，明發坐盈歎。"]'),
('yuding-49','新年作','宋之問','唐','御定全唐诗','yuding','','[]','鄉心新歲切，天畔獨潸然。老至居人下，春歸在客先。',48,'御定全唐詩/json/053.json','["鄉心新歲切，天畔獨潸然。老至居人下，春歸在客先。", "嶺猿同旦暮，江柳共風煙。已似長沙傅，從今又幾年。"]'),
('yuding-50','剪綵','宋之問','唐','御定全唐诗','yuding','','[]','駐想持金錯，居然作管灰。綺羅纖手制，桃李向春開。',48,'御定全唐詩/json/053.json','["駐想持金錯，居然作管灰。綺羅纖手制，桃李向春開。", "拾藻蜂初泊，銜花鳥未回。不言將巧笑，翻逐美人來。"]'),
('yuding-51','七夕','宋之問','唐','御定全唐诗','yuding','','[]','傳道仙星媛，年年會水隅。停梭借蟋蟀，留巧付蜘蛛。',48,'御定全唐詩/json/053.json','["傳道仙星媛，年年會水隅。停梭借蟋蟀，留巧付蜘蛛。", "去晝從雲請，歸輪佇日輸。莫言相見闊，天上日應殊。"]'),
('yuding-52','桂州陪王都督晦日宴逍遙樓','宋之問','唐','御定全唐诗','yuding','','[]','晦節高樓望，山川一半春。意隨蓂葉盡，愁共柳條新。',48,'御定全唐詩/json/053.json','["晦節高樓望，山川一半春。意隨蓂葉盡，愁共柳條新。", "投刺登龍日，開懷納鳥晨。兀然心似醉，不覺有吾身。"]'),
('yuding-53','和趙員外桂陽橋遇佳人','宋之問','唐','御定全唐诗','yuding','','[]','江雨朝飛浥細塵，陽橋花柳不勝春。金鞍白馬來從趙，',40,'御定全唐詩/json/053.json','["江雨朝飛浥細塵，陽橋花柳不勝春。金鞍白馬來從趙，", "蕩舟為樂非吾事，自歎空閨夢寐頻。"]'),
('yuding-54','函谷關','宋之問','唐','御定全唐诗','yuding','','[]','至人□□識仙風，瑞靄丹光遠鬱蔥。靈跡才辭周柱下，',40,'御定全唐詩/json/053.json','["至人□□識仙風，瑞靄丹光遠鬱蔥。靈跡才辭周柱下，", "欲訪乘牛求寶籙，願隨鶴駕遍瑤空。"]'),
('yuding-55','詠省壁畫鶴','宋之問','唐','御定全唐诗','yuding','','[]','粉壁圖仙鶴，昂藏真氣多。鶱飛竟不去，當是戀恩波。',24,'御定全唐詩/json/053.json','["粉壁圖仙鶴，昂藏真氣多。鶱飛竟不去，當是戀恩波。"]'),
('yuding-56','廣州朱長史座觀妓','宋之問','唐','御定全唐诗','yuding','','[]','歌舞須連夜，神仙莫放歸。參差隨暮雨，前路濕人衣。',24,'御定全唐詩/json/053.json','["歌舞須連夜，神仙莫放歸。參差隨暮雨，前路濕人衣。"]'),
('yuding-57','謁二妃廟','宋之問','唐','御定全唐诗','yuding','','[]','還以金屋貴，留茲寶席尊。江鳧嘯風雨，山鬼泣朝昏。',24,'御定全唐詩/json/053.json','["還以金屋貴，留茲寶席尊。江鳧嘯風雨，山鬼泣朝昏。"]'),
('yuding-58','贈嚴侍禦','宋之問','唐','御定全唐诗','yuding','','[]','受脤清邊服，乘驄曆塞塵。當聞漢雪恥，羞共虜和親。',24,'御定全唐詩/json/053.json','["受脤清邊服，乘驄曆塞塵。當聞漢雪恥，羞共虜和親。"]'),
('yuding-59','在荊州重赴嶺南','宋之問','唐','御定全唐诗','yuding','','[]','夢澤三秋日，蒼梧一片雲。還將鵷鷺羽，重入鷓鴣群。',24,'御定全唐詩/json/053.json','["夢澤三秋日，蒼梧一片雲。還將鵷鷺羽，重入鷓鴣群。"]'),
('yuding-60','則天皇後挽歌','宋之問','唐','御定全唐诗','yuding','','[]','象物行周禮，衣冠集漢都。誰憐事虞舜，下裏泣蒼梧。',24,'御定全唐詩/json/053.json','["象物行周禮，衣冠集漢都。誰憐事虞舜，下裏泣蒼梧。"]'),
('yuding-61','鄧國太夫人挽歌','宋之問','唐','御定全唐诗','yuding','','[]','鸞死鉛妝歇，人亡錦字空。悲端若能減，渭水亦應窮。',24,'御定全唐詩/json/053.json','["鸞死鉛妝歇，人亡錦字空。悲端若能減，渭水亦應窮。"]'),
('yuding-62','楊將軍挽歌','宋之問','唐','御定全唐诗','yuding','','[]','亭寒照苦月，隴暗積愁雲。今日山門樹，何處有將軍。',24,'御定全唐詩/json/053.json','["亭寒照苦月，隴暗積愁雲。今日山門樹，何處有將軍。"]'),
('yuding-0','塞垣行','崔湜','唐','御定全唐诗','yuding','','[]','疾風卷溟海，萬里揚砂礫。仰望不見天，昏昏竟朝夕。',132,'御定全唐詩/json/054.json','["疾風卷溟海，萬里揚砂礫。仰望不見天，昏昏竟朝夕。", "是時軍兩進，東拒複西敵。蔽山張旗鼓，間道潛鋒鏑。", "精騎突曉圍，奇兵襲暗壁。十月邊塞寒，四山冱陰積。", "雨雪雁南飛，風塵景西迫。昔我事討論，未嘗怠經籍。", "一朝棄筆硯，十年操矛戟。豈要黃河誓，須勒燕然石。", "可嗟牧羊臣，海上久為客。"]'),
('yuding-1','送梁卿王郎中使東蕃吊冊','崔湜','唐','御定全唐诗','yuding','','[]','梁侯上卿秀，王子中台傑。贈冊綏九夷，旌旃下雙闕。',72,'御定全唐詩/json/054.json','["梁侯上卿秀，王子中台傑。贈冊綏九夷，旌旃下雙闕。", "西堂禮樂送，南陌軒車別。征路入海雲，行舟溯江月。", "茲邦久欽化，曆載歸朝謁。皇心諒所嘉，寄爾宣風烈。"]'),
('yuding-2','餞唐州高使君赴任','崔湜','唐','御定全唐诗','yuding','','[]','芳春桃李時，京都物華好。為嶽豈不貴，所悲涉遠道。',48,'御定全唐詩/json/054.json','["芳春桃李時，京都物華好。為嶽豈不貴，所悲涉遠道。", "遠道不可思，宿昔夢見之。贈君雙佩刀，日夕視來期。"]'),
('yuding-3','冀北春望','崔湜','唐','御定全唐诗','yuding','','[]','回首覽燕趙，春生兩河間。曠然萬里餘，際海不見山。',48,'御定全唐詩/json/054.json','["回首覽燕趙，春生兩河間。曠然萬里餘，際海不見山。", "雨歇青林潤，煙空綠野閑。問鄉何處所，目送白雲還。"]'),
('yuding-4','景龍二年余自門下平章事削階授江州員外司馬尋拜襄州刺史春日赴襄陽途中言志','崔湜','唐','御定全唐诗','yuding','','[]','余本燕趙人，秉心愚且直。群籍備所見，孤貞每自飭。',240,'御定全唐詩/json/054.json','["余本燕趙人，秉心愚且直。群籍備所見，孤貞每自飭。", "徇祿期代耕，受任亦量力。幸逢休明時，朝野兩薦推。", "一朝趨金門，十載奉瑤墀。入掌遷固筆，出參枚馬詞。", "吏部既三踐，中書亦五期。進無負鼎說，退慚補袞詩。", "常恐嬰悔吝，不得少酬私。嗷嗷路傍子，納謗紛無已。", "上動明主疑，下貽大臣恥。毫髮顧無累，冰壺邈自持。", "天道何期平，幽冤終見明。始佐廬陵郡，尋牧襄陽城。", "彤幃荷新寵，朱黻蒙舊榮。力薄慚任重，恩深知命輕。", "飭徒留前路，行子悲且慕。猶聞長樂鐘，尚辨青門樹。", "慈親不忍訣，昆弟默相顧。去去勿重陳，川長日雲暮。"]'),
('yuding-5','大漠行','崔湜','唐','御定全唐诗','yuding','','[]','單于犯薊壖，驃騎略蕭邊。南山木葉飛下地，',148,'御定全唐詩/json/054.json','["單于犯薊壖，驃騎略蕭邊。南山木葉飛下地，", "三軍遙倚仗，萬里相馳逐。旌旆悠悠靜瀚源，", "馬蹄凍溜石，胡毳暖生冰。雲沙泱漭天光閉，", "近見行人畏白龍，遙聞公主愁黃鶴。陽春半，岐路間，", "陣雲不散魚龍水，雨雪猶飛鴻雁山。山嶂連綿不可極，", "漢將紛紜攻戰盈，胡寇蕭條幽朔清。韓君拜節偏知遠，", "但使將軍能百戰，不須天子築長城。"]'),
('yuding-6','奉和登驪山高頂寓目應制','崔湜','唐','御定全唐诗','yuding','','[]','名山何壯哉，玄覽一徘徊。禦路穿林轉，旌門倚石開。',48,'御定全唐詩/json/054.json','["名山何壯哉，玄覽一徘徊。禦路穿林轉，旌門倚石開。", "煙霞肘後發，河塞掌中來。不學蓬壺遠，經年猶未回。"]'),
('yuding-7','侍宴長寧公主東莊應制','崔湜','唐','御定全唐诗','yuding','','[]','沁園東郭外，鸞駕一遊盤。水榭宜時陟，山樓向晚看。',48,'御定全唐詩/json/054.json','["沁園東郭外，鸞駕一遊盤。水榭宜時陟，山樓向晚看。", "席臨天女貴，杯接近臣歡。聖藻懸宸象，微臣竊仰觀。"]'),
('yuding-8','奉和送金城公主適西蕃應制','崔湜','唐','御定全唐诗','yuding','','[]','懷戎前策備，降女舊因修。簫鼓辭家怨，旌旃出塞愁。',48,'御定全唐詩/json/054.json','["懷戎前策備，降女舊因修。簫鼓辭家怨，旌旃出塞愁。", "尚孩中念切，方遠禦慈留。顧乏謀臣用，仍勞聖主憂。"]'),
('yuding-9','幸白鹿觀應制','崔湜','唐','御定全唐诗','yuding','','[]','禦旗探紫籙，仙仗辟丹丘。捧藥芝童下，焚香桂女留。',48,'御定全唐詩/json/054.json','["禦旗探紫籙，仙仗辟丹丘。捧藥芝童下，焚香桂女留。", "鸞歌無歲月，鶴語記春秋。臣朔真何幸，常陪漢武遊。"]'),
('yuding-10','幸梨園亭觀打球應制','崔湜','唐','御定全唐诗','yuding','','[]','年光陌上發，香輦禁中游。草綠鴛鴦殿，花明翡翠樓。',48,'御定全唐詩/json/054.json','["年光陌上發，香輦禁中游。草綠鴛鴦殿，花明翡翠樓。", "寶杯承露酌，仙管雜風流。今日陪歡豫，皇恩不可酬。"]'),
('yuding-11','慈恩寺九日應制','崔湜','唐','御定全唐诗','yuding','','[]','帝裏重陽節，香園萬乘來。卻邪萸結佩，獻壽菊傳杯。',48,'御定全唐詩/json/054.json','["帝裏重陽節，香園萬乘來。卻邪萸結佩，獻壽菊傳杯。", "塔類承天湧，門疑待佛開。睿詞懸日月，長得仰昭回。"]'),
('yuding-12','折楊柳','崔湜','唐','御定全唐诗','yuding','','[]','二月風光半，三邊戍不還。年華妾自惜，楊柳為君攀。',48,'御定全唐詩/json/054.json','["二月風光半，三邊戍不還。年華妾自惜，楊柳為君攀。", "落絮縈衫袖，垂條拂髻鬟。那堪音信斷，流涕望陽關。"]'),
('yuding-13','邊愁','崔湜','唐','御定全唐诗','yuding','','[]','九月蓬根斷，三邊草葉腓。風塵馬變色，霜雪劍生衣。',48,'御定全唐詩/json/054.json','["九月蓬根斷，三邊草葉腓。風塵馬變色，霜雪劍生衣。", "客思愁陰晚，邊書驛騎歸。殷勤鳳樓上，還袂及春暉。"]'),
('yuding-14','婕妤怨','崔湜','唐','御定全唐诗','yuding','','[]','不分君恩斷，新妝視鏡中。容華尚春日，嬌愛已秋風。',48,'御定全唐詩/json/054.json','["不分君恩斷，新妝視鏡中。容華尚春日，嬌愛已秋風。", "枕席臨窗曉，帷屏向月空。年年後庭樹，榮落在深宮。"]'),
('yuding-15','酬杜麟台春思','崔湜','唐','御定全唐诗','yuding','','[]','春還上林苑，花滿洛陽城。鴛衾夜凝思，龍鏡曉含情。',48,'御定全唐詩/json/054.json','["春還上林苑，花滿洛陽城。鴛衾夜凝思，龍鏡曉含情。", "憶夢殘燈落，離魂暗馬驚。可憐朝與暮，樓上獨盈盈。"]'),
('yuding-16','寄天臺司馬先生','崔湜','唐','御定全唐诗','yuding','','[]','聞有三元客，祈仙九轉成。人間白雲返，天上赤龍迎。',48,'御定全唐詩/json/054.json','["聞有三元客，祈仙九轉成。人間白雲返，天上赤龍迎。", "尚惜金芝晚，仍攀琪樹榮。何年緱嶺上，一謝洛陽城。"]'),
('yuding-17','唐都尉山池','崔湜','唐','御定全唐诗','yuding','','[]','曲渚颺輕舟，前溪釣晚流。雁翻蒲葉起，魚撥荇花遊。',48,'御定全唐詩/json/054.json','["曲渚颺輕舟，前溪釣晚流。雁翻蒲葉起，魚撥荇花遊。", "金子懸湘柚，珠房折海榴。幽尋惜未已，清月半西樓。"]'),
('yuding-18','江樓夕望','崔湜','唐','御定全唐诗','yuding','','[]','試陟江樓望，悠悠去國情。楚山霞外斷，漢水月中平。',48,'御定全唐詩/json/054.json','["試陟江樓望，悠悠去國情。楚山霞外斷，漢水月中平。", "公子留遺邑，夫人有舊城。蒼蒼煙霧裏，何處是咸京。"]'),
('yuding-19','襄城即事','崔湜','唐','御定全唐诗','yuding','','[]','子牟懷魏闕，元凱滯襄城。冠蓋仍為裏，沙台尚識名。',48,'御定全唐詩/json/054.json','["子牟懷魏闕，元凱滯襄城。冠蓋仍為裏，沙台尚識名。", "山光晴後綠，江色晚來清。為問東流水，何時到玉京。"]'),
('yuding-20','秦州薛都督挽詞','崔湜','唐','御定全唐诗','yuding','','[]','十裏絳山幽，千年汾水流。碑傳門客見，劍是故人留。',48,'御定全唐詩/json/054.json','["十裏絳山幽，千年汾水流。碑傳門客見，劍是故人留。", "隴樹煙含夕，山門月照秋。古來鐘鼎盛，共盡一蒿丘。"]'),
('yuding-21','奉和春日幸望春宮','崔湜','唐','御定全唐诗','yuding','','[]','澹蕩春光滿曉空，逍遙禦輦入離宮。山河眺望雲天外，',40,'御定全唐詩/json/054.json','["澹蕩春光滿曉空，逍遙禦輦入離宮。山河眺望雲天外，", "即此歡娛齊鎬宴，唯應率舞樂熏風。"]'),
('yuding-22','奉和幸韋嗣立山莊侍宴應制','崔湜','唐','御定全唐诗','yuding','','[]','丞相登前府，尚書啟舊林。式閭明主睿，榮族聖嬪心。',96,'御定全唐詩/json/054.json','["丞相登前府，尚書啟舊林。式閭明主睿，榮族聖嬪心。", "川狹旌門抵，岩高蔽帳臨。閑窗憑柳暗，小徑入松深。", "雲卷千峰色，泉和萬籟吟。蘭迎天女佩，竹礙侍臣簪。", "宸翰三光燭，朝榮四海欽。還嗟絕機叟，白首漢川陰。"]'),
('yuding-23','同李員外春閨','崔湜','唐','御定全唐诗','yuding','','[]','落日啼連夜，孤燈坐徹明。捲簾雙燕入，披幌百花驚。',72,'御定全唐詩/json/054.json','["落日啼連夜，孤燈坐徹明。捲簾雙燕入，披幌百花驚。", "隴上寒應晚，閨中織未成。管弦愁不意，梳洗懶無情。", "去歲聞西伐，今年送北征。容顏離別盡，流恨滿長城。"]'),
('yuding-24','襄陽早秋寄岑侍郎','崔湜','唐','御定全唐诗','yuding','','[]','江城秋氣早，旭旦坐南闈。落葉驚衰鬢，清霜換旅衣。',72,'御定全唐詩/json/054.json','["江城秋氣早，旭旦坐南闈。落葉驚衰鬢，清霜換旅衣。", "時來矜早達，事往覺前非。體道徒推理，防身終昧微。", "故人金華省，肅穆秉天機。誰念江漢廣，蹉跎心事違。"]'),
('yuding-25','贈蘇少府赴任江南余時還京','崔湜','唐','御定全唐诗','yuding','','[]','丈夫不歎別，達士自安卑。攬泣固無趣，銜杯空爾為。',72,'御定全唐詩/json/054.json','["丈夫不歎別，達士自安卑。攬泣固無趣，銜杯空爾為。", "流雲春窈窕，去水暮逶迤。行舟忽東泛，歸騎亦西馳。", "秦地多芳草，江潭有桂枝。誰言阻遐闊，所貴在相知。"]'),
('yuding-26','登總持寺閣','崔湜','唐','御定全唐诗','yuding','','[]','宿雨清龍界，晨暉滿鳳城。升攀重閣迥，憑覽四郊明。',72,'御定全唐詩/json/054.json','["宿雨清龍界，晨暉滿鳳城。升攀重閣迥，憑覽四郊明。", "井邑周秦地，山河今古情。紆餘一水合，寥落五陵平。", "處處風煙起，欣欣草木榮。故人不可見，冠蓋滿東京。"]'),
('yuding-27','早春邊城懷歸','崔湜','唐','御定全唐诗','yuding','','[]','大漠羽書飛，長城未解圍。山川淩玉嶂，旌節下金微。',72,'御定全唐詩/json/054.json','["大漠羽書飛，長城未解圍。山川淩玉嶂，旌節下金微。", "路向南庭遠，書因北雁稀。鄉關搖別思，風雪散戎衣。", "歲盡仍為客，春還尚未歸。明年征騎返，歌舞及芳菲。"]'),
('yuding-28','至桃林塞作','崔湜','唐','御定全唐诗','yuding','','[]','去國未千里，離家已再旬。丹心恒戀闕，白首更辭親。',120,'御定全唐詩/json/054.json','["去國未千里，離家已再旬。丹心恒戀闕，白首更辭親。", "懷璧常貽訓，捐金詎得鄰。抱冤非忤物，罹謗豈由人。", "不濫辭終辨，無瑕理竟伸。黻還中省舊，符與外台新。", "塞上同遷客，江潭異逐臣。淚垂非屬峴，腸斷固由秦。", "歲月行遒盡，山川難重陳。始知亭伯去，還是拙謀身。"]'),
('yuding-29','襄陽作','崔湜','唐','御定全唐诗','yuding','','[]','廟堂初解印，郡邸忽腰章。按節巡河右，鳴騶入漢陽。',120,'御定全唐詩/json/054.json','["廟堂初解印，郡邸忽腰章。按節巡河右，鳴騶入漢陽。", "城臨南峴出，樹繞北津長。好學風猶扇，誇才俗未忘。", "江山跨七澤，煙雨接三湘。蛟浦菱荷淨，漁舟橘柚香。", "醉中求習氏，夢裏憶襄王。宅壞仍思鳳，碑存更憶羊。", "下車慚政美，閉閣幸時康。多謝南征術，於今尚不亡。"]'),
('yuding-30','喜入長安','崔湜','唐','御定全唐诗','yuding','','[]','雲日能催曉，風光不惜年。賴逢征客盡，歸在落花前。',24,'御定全唐詩/json/054.json','["雲日能催曉，風光不惜年。賴逢征客盡，歸在落花前。"]'),
('yuding-31','奉和幸韋嗣立山莊應制','崔湜','唐','御定全唐诗','yuding','','[]','竹徑桃源本出塵，松軒茅棟別驚新。',32,'御定全唐詩/json/054.json','["竹徑桃源本出塵，松軒茅棟別驚新。", "禦蹕何須林下駐，山公不是俗中人。"]'),
('yuding-32','踏歌詞二首','崔液','唐','御定全唐诗','yuding','','[]','彩女迎金屋，仙姬出畫堂。鴛鴦裁錦袖，翡翠貼花黃。',72,'御定全唐詩/json/054.json','["彩女迎金屋，仙姬出畫堂。鴛鴦裁錦袖，翡翠貼花黃。", "歌響舞分行，豔色動流光。", "庭際花微落，樓前漢已橫。金台催夜盡，羅袖佛寒輕。", "樂笑暢歡情，未半著天明。"]'),
('yuding-33','代春閨','崔液','唐','御定全唐诗','yuding','','[]','江南日暖鴻始來，柳條初碧葉半開。玉關遙遙戍未回，',48,'御定全唐詩/json/054.json','["江南日暖鴻始來，柳條初碧葉半開。玉關遙遙戍未回，", "青樓明鏡晝無光，紅帳羅衣徒自香。妾恨十年長獨守，"]'),
('yuding-34','上元夜六首','崔液','唐','御定全唐诗','yuding','','[]','玉漏銀壺且莫催，鐵關金鎖徹明開。',192,'御定全唐詩/json/054.json','["玉漏銀壺且莫催，鐵關金鎖徹明開。", "誰家見月能閑坐，何處聞燈不看來。", "神燈佛火百輪張，刻像圖形七寶裝。", "影裏如聞金口說，空中似散玉毫光。", "今年春色勝常年，此夜風光最可憐。", "鳷鵲樓前新月滿，鳳凰臺上寶燈燃。", "金勒銀鞍控紫騮，玉輪珠幰駕青牛。", "驂驔始散東城曲，倏忽還來南陌頭。", "公子王孫意氣驕，不論相識也相邀。", "最憐長袖風前弱，更賞新弦暗裏調。", "星移漢轉月將微，露灑煙飄燈漸稀。", "猶惜路傍歌舞處，躊躕相顧不能歸。"]'),
('yuding-35','冀北春望','崔液','唐','御定全唐诗','yuding','','[]','回首覽燕趙，春生兩河間。曠然餘萬里，際海不見山。',48,'御定全唐詩/json/054.json','["回首覽燕趙，春生兩河間。曠然餘萬里，際海不見山。", "雨歇青林潤，煙空綠野閑。問鄉無處所，目送白雲關。"]'),
('yuding-36','擬古神女宛轉歌二首','崔液','唐','御定全唐诗','yuding','','[]','風已清，月朗琴複明。掩抑悲千態，殷勤是一聲。',74,'御定全唐詩/json/054.json','["風已清，月朗琴複明。掩抑悲千態，殷勤是一聲。", "歌宛轉，宛轉和更長。願為雙鴻鵠，比翼共翱翔。", "日已暮，長簷鳥應度。此時望君君不來，", "願為形與影，出入恒相逐。"]'),
('yuding-37','望韓公堆','崔滌','唐','御定全唐诗','yuding','','[]','韓公堆上望秦川，渺渺關山西接連。',32,'御定全唐詩/json/054.json','["韓公堆上望秦川，渺渺關山西接連。", "孤客一身千裏外，未知歸日是何年。"]'),
('yuding-0','倬彼我系','王勃','唐','御定全唐诗','yuding','','[]','倬彼我系，出自有周。分疆錫社，派別支流。',360,'御定全唐詩/json/055.json','["倬彼我系，出自有周。分疆錫社，派別支流。", "居衛仕宋，臣嬴相劉。乃武乃文，或公或侯。", "晉曆崩坼，衣冠擾弊。粵自太原，播徂江澨。", "禮喪賢隱，時屯道閉。王室如毀，生人多殪。", "伊我有器，思逢其主。自東施西，擇木開宇。", "田彼河曲，家乎汾浦。天未厭亂，吾將誰輔。", "伊我祖德，思濟九埏。不常厥所，於茲五遷。", "欲及時也，夫豈願焉。其位雖屈，其言則傳。", "爰述帝制，大搜王道。曰天曰人，是祖是考。", "禮樂咸若，詩書具草。貽厥孫謀，永為家寶。", "伊餘小子，信慚明哲。彼網有條，彼車有轍。", "思屏人事，克終前烈。于嗟代網，卒餘來絏。", "來絏伊何，謂餘曰仕。我瞻先達，三十方起。", "夫豈不懷，高山仰止。願言毓德，啜菽飲水。", "有鳥反哺，其聲嗷嗷。言念舊德，憂心忉忉。", "今我不養，歲月其滔。黽勉從役，豈敢告勞。", "從役伊何，薄求卑位。告勞伊何，來參卿事。", "名存實爽，負信愆義。靜言遐思，中心是愧。"]'),
('yuding-1','上巳浮江宴韻得址字','王勃','唐','御定全唐诗','yuding','','[]','披觀玉京路，駐賞金台址。逸興懷九仙，良辰傾四美。',48,'御定全唐詩/json/055.json','["披觀玉京路，駐賞金台址。逸興懷九仙，良辰傾四美。", "松吟白雲際，桂馥青溪裏。別有江海心，日暮情何已。"]'),
('yuding-2','春日宴樂遊園賦韻得接字','王勃','唐','御定全唐诗','yuding','','[]','帝裏寒光盡，神皋春望浹。梅郊落晚英，柳甸驚初葉。',48,'御定全唐詩/json/055.json','["帝裏寒光盡，神皋春望浹。梅郊落晚英，柳甸驚初葉。", "流水抽奇弄，崩雲灑芳牒。清尊湛不空，暫喜平生接。"]'),
('yuding-3','山亭夜宴','王勃','唐','御定全唐诗','yuding','','[]','桂宇幽襟積，山亭涼夜永。森沉野徑寒，肅穆岩扉靜。',48,'御定全唐詩/json/055.json','["桂宇幽襟積，山亭涼夜永。森沉野徑寒，肅穆岩扉靜。", "竹晦南汀色，荷翻北潭影。清興殊未闌，林端照初景。"]'),
('yuding-4','詠風','王勃','唐','御定全唐诗','yuding','','[]','肅肅涼景生，加我林壑清。驅煙尋澗戶，卷霧出山楹。',48,'御定全唐詩/json/055.json','["肅肅涼景生，加我林壑清。驅煙尋澗戶，卷霧出山楹。", "去來固無跡，動息如有情。日落山水靜，為君起松聲。"]'),
('yuding-5','懷仙','王勃','唐','御定全唐诗','yuding','','[]','鶴岑有奇徑，麟洲富仙家。紫泉漱珠液，玄岩列丹葩。',72,'御定全唐詩/json/055.json','["鶴岑有奇徑，麟洲富仙家。紫泉漱珠液，玄岩列丹葩。", "常希披塵網，眇然登雲車。鸞情極霄漢，鳳想疲煙霞。", "道存蓬瀛近，意愜朝市賒。無為坐惆悵，虛此江上華。"]'),
('yuding-6','忽夢游仙','王勃','唐','御定全唐诗','yuding','','[]','僕本江上客，牽跡在方內。寤寐霄漢間，居然有靈對。',96,'御定全唐詩/json/055.json','["僕本江上客，牽跡在方內。寤寐霄漢間，居然有靈對。", "翕爾登霞首，依然躡雲背。電策驅龍光，煙途儼鸞態。", "乘月披金帔，連星解瓊佩。浮識俄易歸，真遊邈難再。", "寥廓沉遐想，周遑奉遺誨。流俗非我鄉，何當釋塵昧。"]'),
('yuding-7','雜曲','王勃','唐','御定全唐诗','yuding','','[]','智瓊神女，來訪文君。蛾眉始約，羅袖初熏。',44,'御定全唐詩/json/055.json','["智瓊神女，來訪文君。蛾眉始約，羅袖初熏。", "歌齊曲韻，舞亂行紛。若向陽臺薦枕，何啻得勝朝雲。"]'),
('yuding-8','秋夜長','王勃','唐','御定全唐诗','yuding','','[]','秋夜長，殊未央，月明白露澄清光，層城綺閣遙相望。',120,'御定全唐詩/json/055.json','["秋夜長，殊未央，月明白露澄清光，層城綺閣遙相望。", "遙相望，川無梁，北風受節南雁翔，崇蘭委質時菊芳。", "鳴環曳履出長廊，為君秋夜搗衣裳。", "纖羅對鳳凰，丹綺雙鴛鴦，調砧亂杵思自傷。", "思自傷，征夫萬里戍他鄉。鶴關音信斷，龍門道路長。", "君在天一方，寒衣徒自香。"]'),
('yuding-9','採蓮曲','王勃','唐','御定全唐诗','yuding','','[]','採蓮歸，綠水芙蓉衣。秋風起浪鳧雁飛。',182,'御定全唐詩/json/055.json','["採蓮歸，綠水芙蓉衣。秋風起浪鳧雁飛。", "桂棹蘭橈下長浦，羅裙玉腕輕搖櫓。葉嶼花潭極望平，", "塞外征夫猶未還，江南採蓮今已暮。今已暮，採蓮花。", "渠今那必盡娼家。官道城南把桑葉，何如江上採蓮花。", "蓮花複蓮花，花葉何稠疊。葉翠本羞眉，花紅強如頰。", "佳人不在茲，悵望別離時。牽花憐共蒂，折藕愛連絲。", "故情無處所，新物從華滋。不惜西津交佩解，", "正逢浩蕩江上風，又值裴回江上月。裴回蓮浦夜相逢，"]'),
('yuding-10','臨高臺','王勃','唐','御定全唐诗','yuding','','[]','臨高臺，高臺迢遞絕浮埃。瑤軒綺構何崔嵬，',166,'御定全唐詩/json/055.json','["臨高臺，高臺迢遞絕浮埃。瑤軒綺構何崔嵬，", "斜對甘泉路，蒼蒼茂陵樹。高臺四望同，", "東彌長樂觀，西指未央宮。赤城映朝日，綠樹搖春風。", "旗亭百隧開新市，甲第千甍分戚裏。朱輪翠蓋不勝春，", "錦衾夜不襞，羅帷晝未空。歌屏朝掩翠，妝鏡晚窺紅。", "為君安寶髻，蛾眉罷花叢。塵間狹路黯將暮，", "物色正如此，佳期那不顧。銀鞍繡轂盛繁華，", "君看舊日高臺處，柏梁銅雀生黃塵。"]'),
('yuding-11','滕王閣','王勃','唐','御定全唐诗','yuding','','[]','滕王高閣臨江渚，佩玉鳴鸞罷歌舞。畫棟朝飛南浦雲，',40,'御定全唐詩/json/055.json','["滕王高閣臨江渚，佩玉鳴鸞罷歌舞。畫棟朝飛南浦雲，", "閣中帝子今何在，檻外長江空自流。"]'),
('yuding-12','江南弄','王勃','唐','御定全唐诗','yuding','','[]','江南弄，巫山連楚夢，行雨行雲幾相送。',42,'御定全唐詩/json/055.json','["江南弄，巫山連楚夢，行雨行雲幾相送。", "瑤軒金谷上春時，玉童仙女無見期。紫露香煙渺難托，"]'),
('yuding-0','聖泉宴','王勃','唐','御定全唐诗','yuding','','[]','披襟乘石磴，列籍俯春泉。蘭氣熏山酌，松聲韻野弦。',48,'御定全唐詩/json/056.json','["披襟乘石磴，列籍俯春泉。蘭氣熏山酌，松聲韻野弦。", "影飄垂葉外，香度落花前。興洽林塘晚，重岩起夕煙。"]'),
('yuding-1','尋道觀','王勃','唐','御定全唐诗','yuding','','[]','芝廛光分野，蓬闕盛規模。碧壇清桂閾，丹洞肅松樞。',48,'御定全唐詩/json/056.json','["芝廛光分野，蓬闕盛規模。碧壇清桂閾，丹洞肅松樞。", "玉笈三山記，金箱五嶽圖。蒼虯不可得，空望白雲衢。"]'),
('yuding-2','散關晨度','王勃','唐','御定全唐诗','yuding','','[]','關山淩旦開，石路無塵埃。白馬高譚去，青牛真氣來。',48,'御定全唐詩/json/056.json','["關山淩旦開，石路無塵埃。白馬高譚去，青牛真氣來。", "重門臨巨壑，連棟起崇隈。即今揚策度，非是棄繻回。"]'),
('yuding-3','別薛華','王勃','唐','御定全唐诗','yuding','','[]','送送多窮路，遑遑獨問津。悲涼千里道，淒斷百年身。',48,'御定全唐詩/json/056.json','["送送多窮路，遑遑獨問津。悲涼千里道，淒斷百年身。", "心事同漂泊，生涯共苦辛。無論去與住，俱是夢中人。"]'),
('yuding-4','重別薛華','王勃','唐','御定全唐诗','yuding','','[]','明月沉珠浦，風飄濯錦川。樓臺臨絕岸，洲渚亙長天。',48,'御定全唐詩/json/056.json','["明月沉珠浦，風飄濯錦川。樓臺臨絕岸，洲渚亙長天。", "旅泊成千里，棲遑共百年。窮途唯有淚，還望獨潸然。"]'),
('yuding-5','遊梵宇三覺寺','王勃','唐','御定全唐诗','yuding','','[]','杏閣披青磴，雕台控紫岑。葉齊山路狹，花積野壇深。',48,'御定全唐詩/json/056.json','["杏閣披青磴，雕台控紫岑。葉齊山路狹，花積野壇深。", "蘿幌棲禪影，松門聽梵音。遽忻陪妙躅，延賞滌煩襟。"]'),
('yuding-6','麻平晚行','王勃','唐','御定全唐诗','yuding','','[]','百年懷土望，千里倦遊情。高低尋戍道，遠近聽泉聲。',48,'御定全唐詩/json/056.json','["百年懷土望，千里倦遊情。高低尋戍道，遠近聽泉聲。", "澗葉才分色，山花不辨名。羈心何處盡，風急暮猿清。"]'),
('yuding-7','送盧主簿','王勃','唐','御定全唐诗','yuding','','[]','窮途非所恨，虛室自相依。城闕居年滿，琴尊俗事稀。',48,'御定全唐詩/json/056.json','["窮途非所恨，虛室自相依。城闕居年滿，琴尊俗事稀。", "開襟方未已，分袂忽多違。東岩富松竹，歲暮幸同歸。"]'),
('yuding-8','餞韋兵曹','王勃','唐','御定全唐诗','yuding','','[]','征驂臨野次，別袂慘江垂。川霽浮煙斂，山明落照移。',48,'御定全唐詩/json/056.json','["征驂臨野次，別袂慘江垂。川霽浮煙斂，山明落照移。", "鷹風凋晚葉，蟬露泣秋枝。亭皋分遠望，延想間雲涯。"]'),
('yuding-9','白下驛餞唐少府','王勃','唐','御定全唐诗','yuding','','[]','下驛窮交日，昌亭旅食年。相知何用早，懷抱即依然。',48,'御定全唐詩/json/056.json','["下驛窮交日，昌亭旅食年。相知何用早，懷抱即依然。", "浦樓低晚照，鄉路隔風煙。去去如何道，長安在日邊。"]'),
('yuding-10','杜少府之任蜀州','王勃','唐','御定全唐诗','yuding','','[]','城闕輔三秦，風煙望五津。與君離別意，同是宦遊人。',49,'御定全唐詩/json/056.json','["城闕輔三秦，風煙望五津。與君離別意，同是宦遊人。", "海記憶體知己，天涯若比鄰。無為在岐路，兒女共沾巾。"]'),
('yuding-11','仲春郊外','王勃','唐','御定全唐诗','yuding','','[]','東園垂柳徑，西堰落花津。物色連三月，風光絕四鄰。',48,'御定全唐詩/json/056.json','["東園垂柳徑，西堰落花津。物色連三月，風光絕四鄰。", "鳥飛村覺曙，魚戲水知春。初晴山院裏，何處染囂塵。"]'),
('yuding-12','郊興','王勃','唐','御定全唐诗','yuding','','[]','空園歌獨酌，春日賦閒居。澤蘭侵小徑，河柳覆長渠。',48,'御定全唐詩/json/056.json','["空園歌獨酌，春日賦閒居。澤蘭侵小徑，河柳覆長渠。", "雨去花光濕，風歸葉影疏。山人不惜醉，唯畏綠尊虛。"]'),
('yuding-13','郊園即事','王勃','唐','御定全唐诗','yuding','','[]','煙霞春旦賞，松竹故年心。斷山疑畫障，縣溜瀉鳴琴。',48,'御定全唐詩/json/056.json','["煙霞春旦賞，松竹故年心。斷山疑畫障，縣溜瀉鳴琴。", "草遍南亭合，花開北院深。閒居饒酒賦，隨興欲抽簪。"]'),
('yuding-14','觀佛跡寺','王勃','唐','御定全唐诗','yuding','','[]','蓮座神容儼，松崖聖趾餘。年長金跡淺，地久石文疏。',48,'御定全唐詩/json/056.json','["蓮座神容儼，松崖聖趾餘。年長金跡淺，地久石文疏。", "頹華臨曲磴，傾影赴前除。共嗟陵穀遠，俄視化城虛。"]'),
('yuding-15','山居晚眺贈王道士','王勃','唐','御定全唐诗','yuding','','[]','金壇疏俗宇，玉洞侶仙群。花枝棲晚露，峰葉度晴雲。',48,'御定全唐詩/json/056.json','["金壇疏俗宇，玉洞侶仙群。花枝棲晚露，峰葉度晴雲。", "斜照移山影，回沙擁籀文。琴尊方待興，竹樹已迎曛。"]'),
('yuding-16','八仙徑','王勃','唐','御定全唐诗','yuding','','[]','柰園欣八正，松岩訪九仙。援蘿窺霧術，攀林俯雲煙。',48,'御定全唐詩/json/056.json','["柰園欣八正，松岩訪九仙。援蘿窺霧術，攀林俯雲煙。", "代北鸞驂至，遼西鶴騎旋。終希脫塵網，連翼下芝田。"]'),
('yuding-17','春日還郊','王勃','唐','御定全唐诗','yuding','','[]','閒情兼嘿語，攜杖赴岩泉。草綠縈新帶，榆青綴古錢。',48,'御定全唐詩/json/056.json','["閒情兼嘿語，攜杖赴岩泉。草綠縈新帶，榆青綴古錢。", "魚床侵岸水，鳥路入山煙。還題平子賦，花樹滿春田。"]'),
('yuding-18','對酒春園作','王勃','唐','御定全唐诗','yuding','','[]','投簪下山閣，攜酒對河梁。狹水牽長鏡，高花送斷香。',48,'御定全唐詩/json/056.json','["投簪下山閣，攜酒對河梁。狹水牽長鏡，高花送斷香。", "繁鶯歌似曲，疏蝶舞成行。自然催一醉，非但閱年光。"]'),
('yuding-19','觀內懷仙','王勃','唐','御定全唐诗','yuding','','[]','玉架殘書隱，金壇舊跡迷。牽花尋紫澗，步葉下清溪。',48,'御定全唐詩/json/056.json','["玉架殘書隱，金壇舊跡迷。牽花尋紫澗，步葉下清溪。", "瓊漿猶類乳，石髓尚如泥。自能成羽翼，何必仰雲梯。"]'),
('yuding-20','秋日別王長史','王勃','唐','御定全唐诗','yuding','','[]','別路餘千里，深恩重百年。正悲西候日，更動北梁篇。',48,'御定全唐詩/json/056.json','["別路餘千里，深恩重百年。正悲西候日，更動北梁篇。", "野色籠寒霧，山光斂暮煙。終知難再奉，懷德自潸然。"]'),
('yuding-21','上巳浮江宴韻得遙字','王勃','唐','御定全唐诗','yuding','','[]','上巳年光促，中川興緒遙。綠齊山葉滿，紅泄片花銷。',48,'御定全唐詩/json/056.json','["上巳年光促，中川興緒遙。綠齊山葉滿，紅泄片花銷。", "泉聲喧後澗，虹影照前橋。遽悲春望遠，江路積波潮。"]'),
('yuding-22','長柳','王勃','唐','御定全唐诗','yuding','','[]','晨征犯煙磴，夕憩在雲關。晚風清近壑，新月照澄灣。',48,'御定全唐詩/json/056.json','["晨征犯煙磴，夕憩在雲關。晚風清近壑，新月照澄灣。", "郊童樵唱返，津叟釣歌還。客行無與晤，賴此釋愁顏。"]'),
('yuding-23','銅雀妓二首','王勃','唐','御定全唐诗','yuding','','[]','金鳳鄰銅雀，漳河望鄴城。君王無處所，台榭若平生。',96,'御定全唐詩/json/056.json','["金鳳鄰銅雀，漳河望鄴城。君王無處所，台榭若平生。", "舞席紛何就，歌梁儼未傾。西陵松檟冷，誰見綺羅情。", "妾本深宮妓，層城閉九重。君王歡愛盡，歌舞為誰容。", "錦衾不復襞，羅衣誰再縫。高臺西北望，流涕向青松。"]'),
('yuding-24','羈游餞別','王勃','唐','御定全唐诗','yuding','','[]','客心懸隴路，遊子倦江幹。槿豐朝砌靜，筱密夜窗寒。',48,'御定全唐詩/json/056.json','["客心懸隴路，遊子倦江幹。槿豐朝砌靜，筱密夜窗寒。", "琴聲銷別恨，風景駐離歡。寧覺山川遠，悠悠旅思難。"]'),
('yuding-25','易陽早發','王勃','唐','御定全唐诗','yuding','','[]','飭裝侵曉月，奔策候殘星。危閣尋丹障，回梁屬翠屏。',48,'御定全唐詩/json/056.json','["飭裝侵曉月，奔策候殘星。危閣尋丹障，回梁屬翠屏。", "雲間迷樹影，霧裏失峰形。複此涼飆至，空山飛夜螢。"]'),
('yuding-26','焦岸早行和陸四','王勃','唐','御定全唐诗','yuding','','[]','侵星違旅館，乘月戒征儔。複嶂迷晴色，虛岩辨暗流。',48,'御定全唐詩/json/056.json','["侵星違旅館，乘月戒征儔。複嶂迷晴色，虛岩辨暗流。", "猿吟山漏曉，螢散野風秋。故人渺何際，鄉關雲霧浮。"]'),
('yuding-27','深灣夜宿','王勃','唐','御定全唐诗','yuding','','[]','津塗臨巨壑，村宇架危岑。堰絕灘聲隱，風交樹影深。',48,'御定全唐詩/json/056.json','["津塗臨巨壑，村宇架危岑。堰絕灘聲隱，風交樹影深。", "江童暮理楫，山女夜調砧。此時故鄉遠，甯知遊子心。"]'),
('yuding-28','傷裴錄事喪子','王勃','唐','御定全唐诗','yuding','','[]','蘭階霜候早，松露穸台深。魄散珠胎沒，芳銷玉樹沉。',48,'御定全唐詩/json/056.json','["蘭階霜候早，松露穸台深。魄散珠胎沒，芳銷玉樹沉。", "露文晞宿草，煙照慘平林。芝焚空歎息，流恨滿籝金。"]'),
('yuding-29','泥溪','王勃','唐','御定全唐诗','yuding','','[]','弭棹淩奔壑，低鞭躡峻岐。江濤出岸險，峰磴入雲危。',72,'御定全唐詩/json/056.json','["弭棹淩奔壑，低鞭躡峻岐。江濤出岸險，峰磴入雲危。", "溜急船文亂，岩斜騎影移。水煙籠翠渚，山照落丹崖。", "風生蘋浦葉，露泣竹潭枝。泛水雖雲美，勞歌誰複知。"]'),
('yuding-30','三月曲水宴得煙字','王勃','唐','御定全唐诗','yuding','','[]','彭澤官初去，河陽賦始傳。田園歸舊國，詩酒間長筵。',120,'御定全唐詩/json/056.json','["彭澤官初去，河陽賦始傳。田園歸舊國，詩酒間長筵。", "列室窺丹洞，分樓瞰紫煙。縈回亙津渡，出沒控郊鄽。", "鳳琴調上客，龍轡儼群仙。松石偏宜古，藤蘿不記年。", "重簷交密樹，複磴擁危泉。抗石晞南嶺，乘沙眇北川。", "傅岩來築處，磻溪入釣前。日斜真趣遠，幽思夢涼蟬。"]'),
('yuding-31','秋日仙游觀贈道士','王勃','唐','御定全唐诗','yuding','','[]','石圖分帝宇，銀牒洞靈宮。回丹縈岫室，複翠上岩櫳。',72,'御定全唐詩/json/056.json','["石圖分帝宇，銀牒洞靈宮。回丹縈岫室，複翠上岩櫳。", "霧濃金灶靜，雲暗玉壇空。野花常捧露，山葉自吟風。", "林泉明月在，詩酒故人同。待余逢石髓，從爾命飛鴻。"]'),
('yuding-32','晚留鳳州','王勃','唐','御定全唐诗','yuding','','[]','寶雞辭舊役，仙鳳曆遺墟。去此近城闕，青山明月初。',24,'御定全唐詩/json/056.json','["寶雞辭舊役，仙鳳曆遺墟。去此近城闕，青山明月初。"]'),
('yuding-33','羈春','王勃','唐','御定全唐诗','yuding','','[]','客心千里倦，春事一朝歸。還傷北園裏，重見落花飛。',24,'御定全唐詩/json/056.json','["客心千里倦，春事一朝歸。還傷北園裏，重見落花飛。"]'),
('yuding-34','林塘懷友','王勃','唐','御定全唐诗','yuding','','[]','芳屏畫春草，仙杼織朝霞。何如山水路，對面即飛花。',24,'御定全唐詩/json/056.json','["芳屏畫春草，仙杼織朝霞。何如山水路，對面即飛花。"]'),
('yuding-35','山扉夜坐','王勃','唐','御定全唐诗','yuding','','[]','抱琴開野室，攜酒對情人。林塘花月下，別似一家春。',24,'御定全唐詩/json/056.json','["抱琴開野室，攜酒對情人。林塘花月下，別似一家春。"]'),
('yuding-36','春莊','王勃','唐','御定全唐诗','yuding','','[]','山中蘭葉徑，城外李桃園。豈知人事靜，不覺鳥聲喧。',24,'御定全唐詩/json/056.json','["山中蘭葉徑，城外李桃園。豈知人事靜，不覺鳥聲喧。"]'),
('yuding-37','春遊','王勃','唐','御定全唐诗','yuding','','[]','客念紛無極，春淚倍成行。今朝花樹下，不覺戀年光。',24,'御定全唐詩/json/056.json','["客念紛無極，春淚倍成行。今朝花樹下，不覺戀年光。"]'),
('yuding-38','春園','王勃','唐','御定全唐诗','yuding','','[]','山泉兩處晚，花柳一園春。還持千日醉，共作百年人。',24,'御定全唐詩/json/056.json','["山泉兩處晚，花柳一園春。還持千日醉，共作百年人。"]'),
('yuding-39','林泉獨飲','王勃','唐','御定全唐诗','yuding','','[]','丘壑經塗賞，花柳遇時春。相逢今不醉，物色自輕人。',24,'御定全唐詩/json/056.json','["丘壑經塗賞，花柳遇時春。相逢今不醉，物色自輕人。"]'),
('yuding-40','登城春望','王勃','唐','御定全唐诗','yuding','','[]','物外山川近，晴初景靄新。芳郊花柳遍，何處不宜春。',24,'御定全唐詩/json/056.json','["物外山川近，晴初景靄新。芳郊花柳遍，何處不宜春。"]'),
('yuding-41','他鄉敘興','王勃','唐','御定全唐诗','yuding','','[]','綴葉歸煙晚，乘花落照春。邊城琴酒處，俱是越鄉人。',24,'御定全唐詩/json/056.json','["綴葉歸煙晚，乘花落照春。邊城琴酒處，俱是越鄉人。"]'),
('yuding-42','夜興','王勃','唐','御定全唐诗','yuding','','[]','野煙含夕渚，山月照秋林。還將中散興，來偶步兵琴。',24,'御定全唐詩/json/056.json','["野煙含夕渚，山月照秋林。還將中散興，來偶步兵琴。"]'),
('yuding-43','臨江二首','王勃','唐','御定全唐诗','yuding','','[]','泛泛東流水，飛飛北上塵。歸驂將別棹，俱是倦遊人。',48,'御定全唐詩/json/056.json','["泛泛東流水，飛飛北上塵。歸驂將別棹，俱是倦遊人。", "去驂嘶別路，歸棹隱寒洲。江皋木葉下，應想故城秋。"]'),
('yuding-44','江亭夜月送別二首','王勃','唐','御定全唐诗','yuding','','[]','江送巴南水，山橫塞北雲。津亭秋月夜，誰見泣離群。',48,'御定全唐詩/json/056.json','["江送巴南水，山橫塞北雲。津亭秋月夜，誰見泣離群。", "亂煙籠碧砌，飛月向南端。寂寂離亭掩，江山此夜寒。"]'),
('yuding-45','別人四首','王勃','唐','御定全唐诗','yuding','','[]','久客逢餘閏，他鄉別故人。自然堪下淚，誰忍望征塵。',96,'御定全唐詩/json/056.json','["久客逢餘閏，他鄉別故人。自然堪下淚，誰忍望征塵。", "江上風煙積，山幽雲霧多。送君南浦外，還望將如何。", "桂軺雖不駐，蘭筵幸未開。林塘風月賞，還待故人來。", "霜華淨天末，霧色籠江際。客子常畏人，何為久留滯。"]'),
('yuding-46','贈李十四四首','王勃','唐','御定全唐诗','yuding','','[]','野客思茅宇，山人愛竹林。琴尊唯待處，風月自相尋。',96,'御定全唐詩/json/056.json','["野客思茅宇，山人愛竹林。琴尊唯待處，風月自相尋。", "小徑偏宜草，空庭不厭花。平生詩與酒，自得會仙家。", "亂竹開三徑，飛花滿四鄰。從來揚子宅，別有尚玄人。", "風筵調桂軫，月徑引藤杯。直當花院裏，書齋望曉開。"]'),
('yuding-47','早春野望','王勃','唐','御定全唐诗','yuding','','[]','江曠春潮白，山長曉岫青。他鄉臨睨極，花柳映邊亭。',24,'御定全唐詩/json/056.json','["江曠春潮白，山長曉岫青。他鄉臨睨極，花柳映邊亭。"]'),
('yuding-48','山中','王勃','唐','御定全唐诗','yuding','','[]','長江悲已滯，萬里念將歸。況屬高風晚，山山黃葉飛。',24,'御定全唐詩/json/056.json','["長江悲已滯，萬里念將歸。況屬高風晚，山山黃葉飛。"]'),
('yuding-49','冬郊行望','王勃','唐','御定全唐诗','yuding','','[]','桂密岩花白，梨疏林葉紅。江皋寒望盡，歸念斷征篷。',24,'御定全唐詩/json/056.json','["桂密岩花白，梨疏林葉紅。江皋寒望盡，歸念斷征篷。"]'),
('yuding-50','寒夜思友三首','王勃','唐','御定全唐诗','yuding','','[]','久別侵懷抱，他鄉變容色。月下調鳴琴，相思此何極。',72,'御定全唐詩/json/056.json','["久別侵懷抱，他鄉變容色。月下調鳴琴，相思此何極。", "雲間征思斷，月下歸愁切。鴻雁西南飛，如何故人別。", "朝朝翠山下，夜夜蒼江曲。複此遙相思，清尊湛芳綠。"]'),
('yuding-51','始平晚息','王勃','唐','御定全唐诗','yuding','','[]','觀闕長安近，江山蜀路賒。客行朝複夕，無處是鄉家。',24,'御定全唐詩/json/056.json','["觀闕長安近，江山蜀路賒。客行朝複夕，無處是鄉家。"]'),
('yuding-52','扶風晝屆離京浸遠','王勃','唐','御定全唐诗','yuding','','[]','帝裏金莖去，扶風石柱來。山川殊未已，行路方悠哉。',24,'御定全唐詩/json/056.json','["帝裏金莖去，扶風石柱來。山川殊未已，行路方悠哉。"]'),
('yuding-53','普安建陰題壁','王勃','唐','御定全唐诗','yuding','','[]','江漢深無極，梁岷不可攀。山川雲霧裏，遊子幾時還。',24,'御定全唐詩/json/056.json','["江漢深無極，梁岷不可攀。山川雲霧裏，遊子幾時還。"]'),
('yuding-54','九日','王勃','唐','御定全唐诗','yuding','','[]','九日重陽節，開門有菊花。不知來送酒，若個是陶家。',24,'御定全唐詩/json/056.json','["九日重陽節，開門有菊花。不知來送酒，若個是陶家。"]'),
('yuding-55','秋江送別二首','王勃','唐','御定全唐诗','yuding','','[]','早是他鄉值早秋，江亭明月帶江流。',64,'御定全唐詩/json/056.json','["早是他鄉值早秋，江亭明月帶江流。", "已覺逝川傷別念，複看津樹隱離舟。", "歸舟歸騎儼成行，江南江北互相望。", "誰謂波瀾才一水，已覺山川是兩鄉。"]'),
('yuding-56','蜀中九日','王勃','唐','御定全唐诗','yuding','','[]','九月九日望鄉台，他席他鄉送客杯。',32,'御定全唐詩/json/056.json','["九月九日望鄉台，他席他鄉送客杯。", "人情已厭南中苦，鴻雁那從北地來。"]'),
('yuding-57','寒夜懷友雜體二首','王勃','唐','御定全唐诗','yuding','','[]','北山煙霧始茫茫，南津霜月正蒼蒼。',64,'御定全唐詩/json/056.json','["北山煙霧始茫茫，南津霜月正蒼蒼。", "秋深客思紛無已，複值征鴻中夜起。", "複合重樓向浦開，秋風明月度江來。", "故人故情懷故宴，相望相思不相見。"]'),
('yuding-58','落花落','王勃','唐','御定全唐诗','yuding','','[]','落花落，落花紛漠漠。綠葉青跗映丹萼，',96,'御定全唐詩/json/056.json','["落花落，落花紛漠漠。綠葉青跗映丹萼，", "落花飛，撩亂入中帷。落花春正滿，春人歸不歸。", "落花度，氛氳繞高樹。落花春已繁，春人春不顧。", "綺合青台靜且閑，羅袂紅巾複往還。盛年不再得，", "與君落花院，臺上起雙鬟。"]'),
('yuding-59','九日懷封元寂','王勃','唐','御定全唐诗','yuding','','[]','九日郊原望，平野遍霜威。蘭氣添新酌，花香染別衣。',48,'御定全唐詩/json/056.json','["九日郊原望，平野遍霜威。蘭氣添新酌，花香染別衣。", "九秋良會少，千里故人稀。今日龍山外，當憶雁書歸。"]'),
('yuding-60','出境遊山二首','王勃','唐','御定全唐诗','yuding','','[]','源水終無路，山阿若有人。驅羊先動石，走兔欲投巾。',156,'御定全唐詩/json/056.json','["源水終無路，山阿若有人。驅羊先動石，走兔欲投巾。", "洞晚秋泉冷，岩朝古樹新。峰斜連鳥翅，磴疊上魚鱗。", "化鶴千齡早，元龜六代春。浮雲今可駕，滄海自成塵。", "振翮淩霜吹，正月佇天潯。回鑣淩翠壑，飛軫控青岑。", "岩深靈灶沒，澗毀石渠沉。宮闕雲間近，江山物外臨。", "玉壇棲暮夜，珠洞結秋陰。蕭蕭離俗影，擾擾望鄉心。", "誰意山遊好，屢傷人事侵。"]'),
('yuding-61','河陽橋代竇郎中佳人答楊中舍','王勃','唐','御定全唐诗','yuding','','[]','披風聽鳥長河路，臨津織女遙相妒。',32,'御定全唐詩/json/056.json','["披風聽鳥長河路，臨津織女遙相妒。", "判知秋夕帶啼還，那及春朝攜手度。"]'),
('yuding-62','晦日宴高氏林亭同用華字','王勔','唐','御定全唐诗','yuding','','[]','上序披林館，中京視物華。竹窗低露葉，梅徑起風花。',48,'御定全唐詩/json/056.json','["上序披林館，中京視物華。竹窗低露葉，梅徑起風花。", "景落春台霧，池侵舊渚沙。綺筵歌吹晚，暮雨泛香車。"]'),
('yuding-0','奉教追赴九成宮途中口號','李嶠','唐','御定全唐诗','yuding','','[]','委質承仙翰，祗命遄遙策。事偶從梁遊，人非背淮客。',84,'御定全唐詩/json/057.json','["委質承仙翰，祗命遄遙策。事偶從梁遊，人非背淮客。", "長驅曆川阜，迥眺窮原澤。鬱鬱桑柘繁，油油禾黍積。", "雨餘林氣靜，日下山光夕。未攀叢桂岩，猶倦飄蓬陌。", "行當奉麾蓋，慰此勞行役。"]'),
('yuding-1','秋山望月酬李騎曹','李嶠','唐','御定全唐诗','yuding','','[]','愁客坐山隈，懷抱自悠哉。況複高秋夕，明月正裴回。',96,'御定全唐詩/json/057.json','["愁客坐山隈，懷抱自悠哉。況複高秋夕，明月正裴回。", "亭亭出迥岫，皎皎映層台。色帶銀河滿，光含玉露開。", "淡雲籠影度，虛暈抱輪回。谷邃涼陰靜，山空夜響哀。", "寒催數雁過，風送一螢來。獨軫離居恨，遙想故人杯。"]'),
('yuding-2','和同府李祭酒休沐田居','李嶠','唐','御定全唐诗','yuding','','[]','列位簪纓序，隱居林野躅。徇物爽全直，棲真昧均俗。',120,'御定全唐詩/json/057.json','["列位簪纓序，隱居林野躅。徇物爽全直，棲真昧均俗。", "若人兼吏隱，率性夷榮辱。地藉朱邸基，家在青山足。", "暫弭西園蓋，言事東皋粟。築室俯澗濱，開扉面岩曲。", "庭幽引夕霧，簷迥通晨旭。迎秋谷黍黃，含露園葵綠。", "勝情狎蘭杜，雅韻鏘金玉。伊我懷丘園，願心從所欲。"]'),
('yuding-3','扈從還洛呈侍從群官','李嶠','唐','御定全唐诗','yuding','','[]','四海帝王家，兩都周漢室。觀風昔來幸，禦氣今旋蹕。',300,'御定全唐詩/json/057.json','["四海帝王家，兩都周漢室。觀風昔來幸，禦氣今旋蹕。", "雷奮六合開，天行萬乘出。玄冥奉時駕，白拒參戎律。", "後隊咽笳簫，前驅嚴罕畢。輝光射東井，禁令橫西秩。", "帳殿別陽秋，旌門臨甲乙。將交洛城雨，稍遠長安日。", "邙鞏雲外來，咸秦霧中失。孟冬霜霰下，是月農功畢。", "天道向歸餘，皇情美陰騭。行存名嶽禮，遞問高年疾。", "祝鳥既開羅，調人更張瑟。登原采謳誦，俯穀求才術。", "邑罕懸磬貧，山無掛瓢逸。施恩浹寰宇，展義該文質。", "德澤盛軒遊，哀矜深禹恤。申歌地廬駭，獻壽衢尊溢。", "瑞色抱氤氳，寒光變蕭飋。宗枝旦奭輔，侍從王劉匹。", "並輯蛟龍書，同簪鳳凰筆。陶甄荷吹萬，頌漢歸明一。", "歡與道路長，顧隨談笑密。叨承廊廟選，謬齒夔龍弼。", "喜構大廈成，慚非棟隆吉。"]'),
('yuding-4','奉使築朔方六州城率爾而作','李嶠','唐','御定全唐诗','yuding','','[]','奉詔受邊服，總徒築朔方。驅彼犬羊族，正此戎夏疆。',192,'御定全唐詩/json/057.json','["奉詔受邊服，總徒築朔方。驅彼犬羊族，正此戎夏疆。", "子來多悅豫，王事寧怠遑。三旬無愆期，百雉鬱相望。", "雄視沙漠垂，有截北海陽。二庭已頓顙，五嶺盡來王。", "驅車登崇墉，顧眄淩大荒。千里何蕭條，草木自悲涼。", "憑軾訊古今，慨焉感興亡。漢障緣河遠，秦城入海長。", "顧無廟堂策，貽此中夏殃。道隱前業衰，運開今化昌。", "制為百王式，舉合千載防。馬牛被路隅，鋒鏑銷戰場。", "豈不懷賢勞，所圖在永康。王事何為者，稱代陳頌章。"]'),
('yuding-5','早發苦竹館','李嶠','唐','御定全唐诗','yuding','','[]','合遝岩嶂深，朦朧煙霧曉。荒阡下樵客，野猿驚山鳥。',120,'御定全唐詩/json/057.json','["合遝岩嶂深，朦朧煙霧曉。荒阡下樵客，野猿驚山鳥。", "開門聽潺湲，入徑尋窈窕。棲鼯抱寒木，流螢飛暗筱。", "早霞稍霏霏，殘月猶皎皎。行看遠星稀，漸覺遊氛少。", "我行撫軺傳，兼得傍林沼。貪玩水石奇，不知川路渺。", "徒憐野心曠，詎惻浮年小。方解寵辱情，永托累塵表。"]'),
('yuding-6','安輯嶺表事平罷歸','李嶠','唐','御定全唐诗','yuding','','[]','雲端想京縣，帝鄉如可見。天涯望越台，海路幾悠哉。',240,'御定全唐詩/json/057.json','["雲端想京縣，帝鄉如可見。天涯望越台，海路幾悠哉。", "六月飛鵬去，三年瑞雉來。境遙銅柱出，山險石門開。", "自我違瀍洛，瞻途屢揮霍。朝朝寒露多，夜夜征衣薄。", "白簡承朝憲，朱方撫夷落。既弘天覆廣，且諭皇恩博。", "皇恩溢外區，憬俗詠來蘇。聲朔臣天子，壇場拜老夫。", "絳宮韜將略，黃石寢兵符。返旆收龍虎，空營集鳥烏。", "日落澄氛靄，憑高視襟帶。東甌抗於越，南斗臨吳會。", "春色繞邊陲，飛花出荒外。卉服紛如積，長川思遊客。", "風生丹桂晚，雲起蒼梧夕。去舳艤清江，歸軒趨紫陌。", "衣裳會百蠻，琛贐委重關。不學金刀使，空持寶劍還。"]'),
('yuding-7','鷓鴣','李嶠','唐','御定全唐诗','yuding','','[]','可憐鷓鴣飛，飛向樹南枝。南枝日照暖，北枝霜露滋。',84,'御定全唐詩/json/057.json','["可憐鷓鴣飛，飛向樹南枝。南枝日照暖，北枝霜露滋。", "露滋不堪棲，使我常夜啼。願逢雲中鶴，銜我向寥廓。", "願作城上烏，一年生九雛。何不舊巢住，枝弱不得去。", "何意道苦辛，客子常畏人。"]'),
('yuding-8','清明日龍門游泛','李嶠','唐','御定全唐诗','yuding','','[]','晴曉國門通，都門藹將發。紛紛洛陽道，南望伊川闕。',72,'御定全唐詩/json/057.json','["晴曉國門通，都門藹將發。紛紛洛陽道，南望伊川闕。", "衍漾乘和風，清明送芬月。林窺二山動，水見千龕越。", "羅袂罥楊絲，香橈犯苔發。群心行樂未，唯恐流芳歇。"]'),
('yuding-9','雲','李嶠','唐','御定全唐诗','yuding','','[]','大樑白雲起，氛氳殊未歇。錦文觸石來，蓋影淩天發。',48,'御定全唐詩/json/057.json','["大樑白雲起，氛氳殊未歇。錦文觸石來，蓋影淩天發。", "煙煴萬年樹，掩映三秋月。會入大風歌，從龍赴圓闕。"]'),
('yuding-10','擬古東飛伯勞西飛燕','李嶠','唐','御定全唐诗','yuding','','[]','傳書青鳥迎簫鳳，巫嶺荊台數通夢。誰家窈窕住園樓，',48,'御定全唐詩/json/057.json','["傳書青鳥迎簫鳳，巫嶺荊台數通夢。誰家窈窕住園樓，", "佳人二八盛舞歌，羞將百萬呈雙蛾。庭前芳樹朝夕改，"]'),
('yuding-11','寶劍篇','李嶠','唐','御定全唐诗','yuding','','[]','吳山開，越溪涸，三金合冶成寶鍔。淬綠水，鑒紅雲，',96,'御定全唐詩/json/057.json','["吳山開，越溪涸，三金合冶成寶鍔。淬綠水，鑒紅雲，", "龜甲參差白虹色，轆轤宛轉黃金飾。駭犀中斷甯方利，", "避災朝穿晉帝屋，逃亂夜入楚王城。一朝運偶逢大仙，", "承平久息干戈事，僥倖得充文武備。除災避患宜君王，"]'),
('yuding-12','汾陰行','李嶠','唐','御定全唐诗','yuding','','[]','君不見昔日西京全盛時，汾陰後土親祭祠。',187,'御定全唐詩/json/057.json','["君不見昔日西京全盛時，汾陰後土親祭祠。", "齋宮宿寢設儲供，撞鐘鳴鼓樹羽旗。漢家五葉才且雄，", "河東太守親掃除，奉迎至尊導鑾輿。五營夾道列容衛，", "金鼎發色正焜煌，靈祇煒燁攄景光。埋玉陳牲禮神畢，", "棹歌微吟彩鷁浮，簫鼓哀鳴白雲秋。歡娛宴洽賜群後，", "自從天子向秦關，玉輦金車不復還。珠簾羽扇長寂寞，", "豪雄意氣今何在，壇場宮館盡蒿蓬。路逢故老長歎息，", "山川滿目淚沾衣，富貴榮華能幾時。不見只今汾水上，"]'),
('yuding-0','中宗降誕日長寧公主滿月侍宴應制','李嶠','唐','御定全唐诗','yuding','','[]','神龍見像日，仙鳳養雛年。大火乘天正，明珠對月圓。',48,'御定全唐詩/json/058.json','["神龍見像日，仙鳳養雛年。大火乘天正，明珠對月圓。", "作新金篋裏，歌奏玉筐前。今日宜孫慶，還參祝壽篇。"]'),
('yuding-1','奉和送金城公主適西蕃應制','李嶠','唐','御定全唐诗','yuding','','[]','漢帝撫戎臣，絲言命錦輪。還將弄機女，遠嫁織皮人。',48,'御定全唐詩/json/058.json','["漢帝撫戎臣，絲言命錦輪。還將弄機女，遠嫁織皮人。", "曲怨關山月，妝消道路塵。所嗟穠李樹，空對小榆春。"]'),
('yuding-2','侍宴長寧公主東莊應制','李嶠','唐','御定全唐诗','yuding','','[]','別業臨青甸，鳴鑾降紫霄。長筵鵷鷺集，仙管鳳凰調。',48,'御定全唐詩/json/058.json','["別業臨青甸，鳴鑾降紫霄。長筵鵷鷺集，仙管鳳凰調。", "樹接南山近，煙含北渚遙。承恩咸已醉，戀賞未還鑣。"]'),
('yuding-3','立春日侍宴內殿出剪綵花應制','李嶠','唐','御定全唐诗','yuding','','[]','早聞年欲至，剪綵學芳辰。綴綠奇能似，裁紅巧逼真。',48,'御定全唐詩/json/058.json','["早聞年欲至，剪綵學芳辰。綴綠奇能似，裁紅巧逼真。", "花從篋裏發，葉向手中春。不與時光競，何名天上人。"]'),
('yuding-4','奉和人日清暉閣宴群臣遇雪應制','李嶠','唐','御定全唐诗','yuding','','[]','三陽偏勝節，七日最靈辰。行慶傳芳蟻，升高綴彩人。',48,'御定全唐詩/json/058.json','["三陽偏勝節，七日最靈辰。行慶傳芳蟻，升高綴彩人。", "階前蓂候月，樓上雪驚春。今日銜天造，還疑上漢津。"]'),
('yuding-5','奉和春日游苑喜雨應制','李嶠','唐','御定全唐诗','yuding','','[]','仙蹕九成台，香筵萬壽杯。一旬初降雨，二月早聞雷。',48,'御定全唐詩/json/058.json','["仙蹕九成台，香筵萬壽杯。一旬初降雨，二月早聞雷。", "葉向朝隮密，花含宿潤開。幸承天澤豫，無使日光催。"]'),
('yuding-6','春日侍宴幸芙蓉園應制','李嶠','唐','御定全唐诗','yuding','','[]','年光竹裏遍，春色杏間遙。煙氣籠青閣，流文蕩畫橋。',48,'御定全唐詩/json/058.json','["年光竹裏遍，春色杏間遙。煙氣籠青閣，流文蕩畫橋。", "飛花隨蝶舞，豔曲伴鶯嬌。今日陪歡豫，還疑陟紫霄。"]'),
('yuding-7','甘露殿侍宴應制','李嶠','唐','御定全唐诗','yuding','','[]','月宇臨丹地，雲窗網碧紗。禦筵陳桂醑，天酒酌榴花。',48,'御定全唐詩/json/058.json','["月宇臨丹地，雲窗網碧紗。禦筵陳桂醑，天酒酌榴花。", "水向浮橋直，城連禁苑斜。承恩恣歡賞，歸路滿煙霞。"]'),
('yuding-8','奉和七夕兩儀殿會宴應制','李嶠','唐','御定全唐诗','yuding','','[]','靈匹三秋會，仙期七夕過。查來人泛海，橋渡鵲填河。',48,'御定全唐詩/json/058.json','["靈匹三秋會，仙期七夕過。查來人泛海，橋渡鵲填河。", "帝縷升銀閣，天機罷玉梭。誰言七襄詠，重入五弦歌。"]'),
('yuding-9','奉和九月九日登慈恩寺浮圖應制','李嶠','唐','御定全唐诗','yuding','','[]','瑞塔千尋起，仙輿九日來。萸房陳寶席，菊蕊散花台。',48,'御定全唐詩/json/058.json','["瑞塔千尋起，仙輿九日來。萸房陳寶席，菊蕊散花台。", "禦氣鵬霄近，升高鳳野開。天歌將梵樂，空裏共裴回。"]'),
('yuding-10','閏九月九日幸總持寺登浮圖應制','李嶠','唐','御定全唐诗','yuding','','[]','閏節開重九，真遊下大千。花寒仍薦菊，座晚更披蓮。',48,'御定全唐詩/json/058.json','["閏節開重九，真遊下大千。花寒仍薦菊，座晚更披蓮。", "刹鳳回雕輦，帆虹間彩旃。還將西梵曲，助入南熏弦。"]'),
('yuding-11','奉和驪山高頂寓目應制','李嶠','唐','御定全唐诗','yuding','','[]','步輦陟山巔，山高入紫煙。忠臣還捧日，聖後欲捫天。',48,'御定全唐詩/json/058.json','["步輦陟山巔，山高入紫煙。忠臣還捧日，聖後欲捫天。", "迥識平陵樹，低看華嶽蓮。帝鄉應不遠，空見白雲懸。"]'),
('yuding-12','游禁苑陪幸臨渭亭遇雪應制','李嶠','唐','御定全唐诗','yuding','','[]','同雲接野煙，飛雪暗長天。拂樹添梅色，過樓助粉妍。',48,'御定全唐詩/json/058.json','["同雲接野煙，飛雪暗長天。拂樹添梅色，過樓助粉妍。", "光含班女扇，韻入楚王弦。六出迎仙藻，千箱答瑞年。"]'),
('yuding-13','幸白鹿觀應制','李嶠','唐','御定全唐诗','yuding','','[]','駐蹕三天路，回旃萬仞溪。真庭群帝饗，洞府百靈棲。',48,'御定全唐詩/json/058.json','["駐蹕三天路，回旃萬仞溪。真庭群帝饗，洞府百靈棲。", "玉酒仙壚釀，金方暗壁題。佇看青鳥入，還陟紫雲梯。"]'),
('yuding-14','送沙門弘景道俊玄奘還荊州應制','李嶠','唐','御定全唐诗','yuding','','[]','三乘歸淨域，萬騎餞通莊。就日離亭近，彌天別路長。',48,'御定全唐詩/json/058.json','["三乘歸淨域，萬騎餞通莊。就日離亭近，彌天別路長。", "荊南旋杖缽，渭北限津梁。何日紆真果，還來入帝鄉。"]'),
('yuding-15','酬和杜五弟晴朝獨坐見贈','李嶠','唐','御定全唐诗','yuding','','[]','平明坐虛館，曠望幾悠哉。宿霧分空盡，朝光度隙來。',48,'御定全唐詩/json/058.json','["平明坐虛館，曠望幾悠哉。宿霧分空盡，朝光度隙來。", "影低藤架密，香動藥闌開。未展山陽會，空留池上杯。"]'),
('yuding-16','同賦山居七夕','李嶠','唐','御定全唐诗','yuding','','[]','明月青山夜，高天白露秋。花庭開粉席，雲岫敞針樓。',48,'御定全唐詩/json/058.json','["明月青山夜，高天白露秋。花庭開粉席，雲岫敞針樓。", "石類支機影，池似泛槎流。暫驚河女鵲，終狎野人鷗。"]'),
('yuding-17','送崔主簿赴滄州','李嶠','唐','御定全唐诗','yuding','','[]','紫陌追隨日，青門相見時。宦遊從此去，離別幾年期。',48,'御定全唐詩/json/058.json','["紫陌追隨日，青門相見時。宦遊從此去，離別幾年期。", "芳桂尊中酒，幽蘭下調詞。他鄉有明月，千里照相思。"]'),
('yuding-18','寒食清明日早赴王門率成','李嶠','唐','御定全唐诗','yuding','','[]','遊客趨梁邸，朝光入楚台。槐煙乘曉散，榆火應春開。',48,'御定全唐詩/json/058.json','["遊客趨梁邸，朝光入楚台。槐煙乘曉散，榆火應春開。", "日帶晴虹上，花隨早蝶來。雄風乘令節，餘吹拂輕灰。"]'),
('yuding-19','和周記室從駕曉發合璧宮','李嶠','唐','御定全唐诗','yuding','','[]','濯龍春苑曙，翠鳳曉旗舒。野色開煙後，山光澹月餘。',48,'御定全唐詩/json/058.json','["濯龍春苑曙，翠鳳曉旗舒。野色開煙後，山光澹月餘。", "風長笳響咽，川迥騎行疏。珠履陪仙駕，金聲振屬車。"]'),
('yuding-20','和杜侍禦太清台宿直旦有懷','李嶠','唐','御定全唐诗','yuding','','[]','貂冠朝彩振，烏署曉光分。欲嘯遷喬侶，先飛擲地文。',48,'御定全唐詩/json/058.json','["貂冠朝彩振，烏署曉光分。欲嘯遷喬侶，先飛擲地文。", "庭虛麥雨潤，林靜蕙風熏。嵇駕終難仰，梁鳧且自群。"]'),
('yuding-21','和杜學士江南初霽羈懷','李嶠','唐','御定全唐诗','yuding','','[]','大江開宿雨，征棹下春流。霧卷晴山出，風恬晚浪收。',48,'御定全唐詩/json/058.json','["大江開宿雨，征棹下春流。霧卷晴山出，風恬晚浪收。", "岸花明水樹，川鳥亂沙洲。羈眺傷千里，勞歌動四愁。"]'),
('yuding-22','晚景悵然簡二三子','李嶠','唐','御定全唐诗','yuding','','[]','楚客秋悲動，梁台夕望賒。梧桐稍下葉，山桂欲開花。',48,'御定全唐詩/json/058.json','["楚客秋悲動，梁台夕望賒。梧桐稍下葉，山桂欲開花。", "氣引迎寒露，光收向晚霞。長歌白水曲，空對綠池華。"]'),
('yuding-23','送李邕','李嶠','唐','御定全唐诗','yuding','','[]','落日荒郊外，風景正淒淒。離人席上起，征馬路傍嘶。',48,'御定全唐詩/json/058.json','["落日荒郊外，風景正淒淒。離人席上起，征馬路傍嘶。", "別酒傾壺贈，行書掩淚題。殷勤禦溝水，從此各東西。"]'),
('yuding-24','又送別','李嶠','唐','御定全唐诗','yuding','','[]','岐路方為客，芳尊暫解顏。人隨轉蓬去，春伴落梅還。',48,'御定全唐詩/json/058.json','["岐路方為客，芳尊暫解顏。人隨轉蓬去，春伴落梅還。", "白雲度汾水，黃河繞晉關。離心不可問，宿昔鬢成斑。"]'),
('yuding-25','餞駱四二首','李嶠','唐','御定全唐诗','yuding','','[]','平生何以樂，鬥酒夜相逢。曲中驚別緒，醉裏失愁容。',96,'御定全唐詩/json/058.json','["平生何以樂，鬥酒夜相逢。曲中驚別緒，醉裏失愁容。", "星月懸秋漢，風霜入曙鐘。明日臨溝水，青山幾萬重。", "甲第驅車入，良宵秉燭遊。人追竹林會，酒獻菊花秋。", "霜吹飄無已，星河漫不流。重嗟歡賞地，翻召別離憂。"]'),
('yuding-26','春日游苑喜雨應詔','李嶠','唐','御定全唐诗','yuding','','[]','園樓春正歸，入苑弄芳菲。密雨迎仙步，低雲拂禦衣。',48,'御定全唐詩/json/058.json','["園樓春正歸，入苑弄芳菲。密雨迎仙步，低雲拂禦衣。", "危花沾易落，度鳥濕難飛。膏澤登千庾，歡情遍九圍。"]'),
('yuding-27','九日應制得歡字','李嶠','唐','御定全唐诗','yuding','','[]','令節三秋晚，重陽九日歡。仙杯還泛菊，寶饌且調蘭。',48,'御定全唐詩/json/058.json','["令節三秋晚，重陽九日歡。仙杯還泛菊，寶饌且調蘭。", "禦氣雲霄近，乘高宇宙寬。今朝萬壽引，宜向曲中彈。"]'),
('yuding-28','二月奉教作','李嶠','唐','御定全唐诗','yuding','','[]','柳陌鶯初囀，梅梁燕始歸。和風泛紫若，柔露濯青薇。',48,'御定全唐詩/json/058.json','["柳陌鶯初囀，梅梁燕始歸。和風泛紫若，柔露濯青薇。", "日豔臨花影，霞翻入浪暉。乘春重遊豫，淹賞玩芳菲。"]'),
('yuding-29','三月奉教作','李嶠','唐','御定全唐诗','yuding','','[]','銀井桐花發，金堂草色齊。韶光愛日宇，淑氣滿風蹊。',48,'御定全唐詩/json/058.json','["銀井桐花發，金堂草色齊。韶光愛日宇，淑氣滿風蹊。", "蝶影將花亂，虹文向水低。芳春隨意晚，佳賞日無暌。"]'),
('yuding-30','四月奉教作','李嶠','唐','御定全唐诗','yuding','','[]','暄鑰三春謝，炎鐘九夏初。潤浮梅雨夕，涼散麥風餘。',48,'御定全唐詩/json/058.json','["暄鑰三春謝，炎鐘九夏初。潤浮梅雨夕，涼散麥風餘。", "葉暗庭幃滿，花殘院錦疏。勝情多賞托，尊酒狎林箊。"]'),
('yuding-31','五月奉教作','李嶠','唐','御定全唐诗','yuding','','[]','綠樹炎氛滿，朱樓夏景長。池含凍雨氣，山映火雲光。',48,'御定全唐詩/json/058.json','["綠樹炎氛滿，朱樓夏景長。池含凍雨氣，山映火雲光。", "果院新櫻熟，花庭曙槿芳。欲逃三伏暑，還泛十旬觴。"]'),
('yuding-32','六月奉教作','李嶠','唐','御定全唐诗','yuding','','[]','養日暫裴回，畏景尚悠哉。避暑移琴席，追涼□□□。',48,'御定全唐詩/json/058.json','["養日暫裴回，畏景尚悠哉。避暑移琴席，追涼□□□。", "竹風依扇動，桂酒溢壺開。勞餌□飛雪，自可□□□。"]'),
('yuding-33','八月奉教作','李嶠','唐','御定全唐诗','yuding','','[]','黃葉秋風起，蒼葭曉露團。鶴鳴初警候，雁上欲淩寒。',48,'御定全唐詩/json/058.json','["黃葉秋風起，蒼葭曉露團。鶴鳴初警候，雁上欲淩寒。", "月鏡如開匣，雲纓似綴冠。清尊對旻序，高宴有餘歡。"]'),
('yuding-34','九月奉教作','李嶠','唐','御定全唐诗','yuding','','[]','曲池朝下雁，幽砌夕吟蛩。葉徑蘭芳盡，花潭菊氣濃。',48,'御定全唐詩/json/058.json','["曲池朝下雁，幽砌夕吟蛩。葉徑蘭芳盡，花潭菊氣濃。", "寒催四序律，霜度九秋鐘。還當明月夜，飛蓋遠相從。"]'),
('yuding-35','十月奉教作','李嶠','唐','御定全唐诗','yuding','','[]','白藏初送節，玄律始迎冬。林枯黃葉盡，水耗綠池空。',48,'御定全唐詩/json/058.json','["白藏初送節，玄律始迎冬。林枯黃葉盡，水耗綠池空。", "霜待臨庭月，寒隨入牖風。別有歡娛地，歌舞應絲桐。"]'),
('yuding-36','十一月奉教作','李嶠','唐','御定全唐诗','yuding','','[]','凝陰結暮序，嚴氣肅長飆。霜犯狐裘夕，寒侵獸火朝。',48,'御定全唐詩/json/058.json','["凝陰結暮序，嚴氣肅長飆。霜犯狐裘夕，寒侵獸火朝。", "冰深遙架浦，雪凍近封條。平原已從獵，日暮整還鑣。"]'),
('yuding-37','十二月奉教作','李嶠','唐','御定全唐诗','yuding','','[]','玉燭年行盡，銅史漏猶長。池冷凝宵凍，庭寒積曙霜。',48,'御定全唐詩/json/058.json','["玉燭年行盡，銅史漏猶長。池冷凝宵凍，庭寒積曙霜。", "蘭心未動色，梅館欲含芳。裴回臨歲晚，顧步佇春光。"]'),
('yuding-38','和麹典設扈從東郊憶弟使往安西冬至日恨不得同申拜慶','李嶠','唐','御定全唐诗','yuding','','[]','玉關方叱馭，桂苑正陪輿。桓嶺嗟分翼，薑川限饋魚。',48,'御定全唐詩/json/058.json','["玉關方叱馭，桂苑正陪輿。桓嶺嗟分翼，薑川限饋魚。", "雪花含□晚，雲葉帶荊舒。重此西流詠，彌傷南至初。"]'),
('yuding-39','馬武騎挽歌二首','李嶠','唐','御定全唐诗','yuding','','[]','五日皆休沐，三泉獨不歸。池台金闕是，尊酒玳筵非。',96,'御定全唐詩/json/058.json','["五日皆休沐，三泉獨不歸。池台金闕是，尊酒玳筵非。", "巷靜游禽入，門閑過客稀。唯餘昔年鳳，尚繞故樓飛。", "昔下天津館，嘗過帝子家。夜傾金屋酒，春舞玉台花。", "試馬依紅埒，吹簫弄紫霞。誰言東郭路，翻枉北門車。"]'),
('yuding-40','武三思挽歌','李嶠','唐','御定全唐诗','yuding','','[]','玉匣金為縷，銀鉤石作銘。短歌傷薤曲，長暮泣松扃。',48,'御定全唐詩/json/058.json','["玉匣金為縷，銀鉤石作銘。短歌傷薤曲，長暮泣松扃。", "事往昏朝霧，人亡折夜星。忠賢良可惜，圖畫入丹青。"]'),
('yuding-41','天官崔侍郎夫人吳氏挽歌','李嶠','唐','御定全唐诗','yuding','','[]','寵服當年盛，芳魂此地窮。劍飛龍匣在，人去鵲巢空。',48,'御定全唐詩/json/058.json','["寵服當年盛，芳魂此地窮。劍飛龍匣在，人去鵲巢空。", "簟愴孤生竹，琴哀半死桐。唯當青史上，千載仰嬪風。"]'),
('yuding-0','日','李嶠','唐','御定全唐诗','yuding','','[]','旦出扶桑路，遙升若木枝。雲間五色滿，霞際九光披。',48,'御定全唐詩/json/059.json','["旦出扶桑路，遙升若木枝。雲間五色滿，霞際九光披。", "東陸蒼龍駕，南郊赤羽馳。傾心比葵藿，朝夕奉光曦。"]'),
('yuding-1','月','李嶠','唐','御定全唐诗','yuding','','[]','桂滿三五夕，蓂開二八時。清輝飛鵲鑒，新影學蛾眉。',48,'御定全唐詩/json/059.json','["桂滿三五夕，蓂開二八時。清輝飛鵲鑒，新影學蛾眉。", "皎潔臨疏牖，玲瓏鑒薄帷。願言從愛客，清夜幸同嬉。"]'),
('yuding-2','星','李嶠','唐','御定全唐诗','yuding','','[]','蜀郡靈槎轉，豐城寶劍新。將軍臨北塞，天子入西秦。',48,'御定全唐詩/json/059.json','["蜀郡靈槎轉，豐城寶劍新。將軍臨北塞，天子入西秦。", "未作三台輔，寧為五老臣。今宵潁川曲，誰識聚賢人。"]'),
('yuding-3','風','李嶠','唐','御定全唐诗','yuding','','[]','落日生蘋末，搖揚遍遠林。帶花疑鳳舞，向竹似龍吟。',48,'御定全唐詩/json/059.json','["落日生蘋末，搖揚遍遠林。帶花疑鳳舞，向竹似龍吟。", "月動臨秋扇，松清入夜琴。若至蘭台下，還拂楚王襟。"]'),
('yuding-4','雲','李嶠','唐','御定全唐诗','yuding','','[]','英英大樑國，鬱鬱秘書台。碧落從龍起，青山觸石來。',48,'御定全唐詩/json/059.json','["英英大樑國，鬱鬱秘書台。碧落從龍起，青山觸石來。", "官名光邃古，蓋影耿輕埃。飛感高歌發，威加四海回。"]'),
('yuding-5','煙','李嶠','唐','御定全唐诗','yuding','','[]','瑞氣淩青合，空蒙上翠微。迥浮雙闕路，遙拂九仙衣。',48,'御定全唐詩/json/059.json','["瑞氣淩青合，空蒙上翠微。迥浮雙闕路，遙拂九仙衣。", "桑柘迎寒色，松篁暗晚暉。還當紫霄上，時接彩鸞飛。"]'),
('yuding-6','露','李嶠','唐','御定全唐诗','yuding','','[]','滴瀝明花苑，葳蕤泫竹叢。玉垂丹棘上，珠湛綠荷中。',48,'御定全唐詩/json/059.json','["滴瀝明花苑，葳蕤泫竹叢。玉垂丹棘上，珠湛綠荷中。", "夜警千年鶴，朝零七月風。願凝仙掌內，長奉未央宮。"]'),
('yuding-7','霧','李嶠','唐','御定全唐诗','yuding','','[]','曹公迷楚澤，漢帝出平城。涿鹿妖氛靜，丹山霽色明。',48,'御定全唐詩/json/059.json','["曹公迷楚澤，漢帝出平城。涿鹿妖氛靜，丹山霽色明。", "類煙飛稍重，方雨散還輕。倘入非熊兆，甯思玄豹情。"]'),
('yuding-8','雨','李嶠','唐','御定全唐诗','yuding','','[]','西北雲膚起，東南雨足來。靈童出海見，神女向台回。',48,'御定全唐詩/json/059.json','["西北雲膚起，東南雨足來。靈童出海見，神女向台回。", "斜影風前合，圓文水上開。十旬無破塊，九土信康哉。"]'),
('yuding-9','雪','李嶠','唐','御定全唐诗','yuding','','[]','瑞雪驚千里，同雲暗九霄。地疑明月夜，山似白雲朝。',48,'御定全唐詩/json/059.json','["瑞雪驚千里，同雲暗九霄。地疑明月夜，山似白雲朝。", "逐舞花光動，臨歌扇影飄。大周天闕路，今日海神朝。"]'),
('yuding-10','山','李嶠','唐','御定全唐诗','yuding','','[]','地鎮標神秀，峨峨上翠氛。泉飛一道帶，峰出半天雲。',48,'御定全唐詩/json/059.json','["地鎮標神秀，峨峨上翠氛。泉飛一道帶，峰出半天雲。", "古壁丹青色，新花綺繡紋。已開封禪所，希謁聖明君。"]'),
('yuding-11','石','李嶠','唐','御定全唐诗','yuding','','[]','宗子維城固，將軍飲羽威。岩花鑒裏發，雲葉錦中飛。',48,'御定全唐詩/json/059.json','["宗子維城固，將軍飲羽威。岩花鑒裏發，雲葉錦中飛。", "入宋星初隕，過湘燕早歸。倘因持補極，甯複想支機。"]'),
('yuding-12','原','李嶠','唐','御定全唐诗','yuding','','[]','王粲銷憂日，江淹起恨年。帶川遙綺錯，分隰迥阡眠。',48,'御定全唐詩/json/059.json','["王粲銷憂日，江淹起恨年。帶川遙綺錯，分隰迥阡眠。", "□□橫周甸，莓苔闕晉田。方知急難響，長在脊令篇。"]'),
('yuding-13','野','李嶠','唐','御定全唐诗','yuding','','[]','鳳出秦郊迥，鶉飛楚塞空。蒼梧雲影去，涿鹿霧光通。',48,'御定全唐詩/json/059.json','["鳳出秦郊迥，鶉飛楚塞空。蒼梧雲影去，涿鹿霧光通。", "草暗少原綠，花明入蜀紅。誰言版築士，猶處傅岩中。"]'),
('yuding-14','田','李嶠','唐','御定全唐诗','yuding','','[]','貢禹懷書日，張衡作賦辰。杏花開鳳軫，菖葉布龍鱗。',48,'御定全唐詩/json/059.json','["貢禹懷書日，張衡作賦辰。杏花開鳳軫，菖葉布龍鱗。", "瑞麥兩岐秀，嘉禾同穎新。寧知帝王力，擊壤自安貧。"]'),
('yuding-15','道','李嶠','唐','御定全唐诗','yuding','','[]','銅駝分鞏洛，劍閣低臨邛。紫徼三千里，青樓十二重。',48,'御定全唐詩/json/059.json','["銅駝分鞏洛，劍閣低臨邛。紫徼三千里，青樓十二重。", "玉關塵似雪，金穴馬如龍。今日中衢上，堯尊更可逢。"]'),
('yuding-16','海','李嶠','唐','御定全唐诗','yuding','','[]','習坎疏丹壑，朝宗合紫微。三山巨鼇湧，萬里大鵬飛。',48,'御定全唐詩/json/059.json','["習坎疏丹壑，朝宗合紫微。三山巨鼇湧，萬里大鵬飛。", "樓寫春雲色，珠含明月輝。會因添霧露，方逐眾川歸。"]'),
('yuding-17','江','李嶠','唐','御定全唐诗','yuding','','[]','日夕三江望，靈潮萬里回。霞津錦浪動，月浦練花開。',48,'御定全唐詩/json/059.json','["日夕三江望，靈潮萬里回。霞津錦浪動，月浦練花開。", "湍似黃牛去，濤從白馬來。英靈已傑出，誰識卿雲才。"]'),
('yuding-18','河','李嶠','唐','御定全唐诗','yuding','','[]','源出昆侖中，長波接漢空。桃花來馬頰，竹箭入龍宮。',48,'御定全唐詩/json/059.json','["源出昆侖中，長波接漢空。桃花來馬頰，竹箭入龍宮。", "德水千年變，榮光五色通。若披蘭葉檢，□□□□□。"]'),
('yuding-19','洛','李嶠','唐','御定全唐诗','yuding','','[]','九洛韶光媚，三川物候新。花明丹鳳浦，日映玉雞津。',48,'御定全唐詩/json/059.json','["九洛韶光媚，三川物候新。花明丹鳳浦，日映玉雞津。", "元禮期仙客，陳王睹麗人。神龜方錫瑞，綠字重來臻。"]'),
('yuding-20','城','李嶠','唐','御定全唐诗','yuding','','[]','四塞稱天府，三河建洛都。飛雲靄層闕，白日麗南隅。',48,'御定全唐詩/json/059.json','["四塞稱天府，三河建洛都。飛雲靄層闕，白日麗南隅。", "獨下仙人鳳，群驚禦史烏。何辭一萬里，邊徼捍匈奴。"]'),
('yuding-21','門','李嶠','唐','御定全唐诗','yuding','','[]','奕奕彤闈下，煌煌紫禁隈。阿房萬戶列，閶闔九重開。',48,'御定全唐詩/json/059.json','["奕奕彤闈下，煌煌紫禁隈。阿房萬戶列，閶闔九重開。", "疏廣遺榮去，於公待駟來。詎知金馬側，方朔有奇才。"]'),
('yuding-22','市','李嶠','唐','御定全唐诗','yuding','','[]','闤闠開三市，旗亭起百尋。漸離初擊築，司馬正彈琴。',48,'御定全唐詩/json/059.json','["闤闠開三市，旗亭起百尋。漸離初擊築，司馬正彈琴。", "細柳龍鱗映，長槐兔月陰。徒知觀衛玉，詎肯掛秦金。"]'),
('yuding-23','井','李嶠','唐','御定全唐诗','yuding','','[]','玉甃談仙客，銅台賞魏君。蜀都宵映火，杞國旦生雲。',48,'御定全唐詩/json/059.json','["玉甃談仙客，銅台賞魏君。蜀都宵映火，杞國旦生雲。", "向日蓮花淨，含風李樹熏。已開千里國，還聚五星文。"]'),
('yuding-24','宅','李嶠','唐','御定全唐诗','yuding','','[]','寂寞蓬蒿徑，喧喧湫隘廬。屢逢長者轍，時引故人車。',48,'御定全唐詩/json/059.json','["寂寞蓬蒿徑，喧喧湫隘廬。屢逢長者轍，時引故人車。", "孟母遷鄰罷，將軍辭第初。誰憐草玄處，獨對一床書。"]'),
('yuding-25','池','李嶠','唐','御定全唐诗','yuding','','[]','彩棹浮太液，清觴醉習家。詩情對明月，雲曲拂流霞。',48,'御定全唐詩/json/059.json','["彩棹浮太液，清觴醉習家。詩情對明月，雲曲拂流霞。", "煙散龍形淨，波含鳳影斜。安仁動秋興，魚鳥思空賒。"]'),
('yuding-26','樓','李嶠','唐','御定全唐诗','yuding','','[]','百尺重城際，千尋大道隈。漢宮井幹起，吳國落星開。',48,'御定全唐詩/json/059.json','["百尺重城際，千尋大道隈。漢宮井幹起，吳國落星開。", "笛怨綠珠去，簫隨弄玉來。銷憂聊暇日，誰識仲宣才。"]'),
('yuding-27','橋','李嶠','唐','御定全唐诗','yuding','','[]','烏鵲填應滿，黃公去不歸。勢疑虹始見，形似雁初飛。',48,'御定全唐詩/json/059.json','["烏鵲填應滿，黃公去不歸。勢疑虹始見，形似雁初飛。", "妙應七星制，高分半月輝。秦王空構石，仙島遠難依。"]'),
('yuding-28','經','李嶠','唐','御定全唐诗','yuding','','[]','漢室鴻儒盛，鄒堂大義明。五千道德闡，三百禮儀成。',48,'御定全唐詩/json/059.json','["漢室鴻儒盛，鄒堂大義明。五千道德闡，三百禮儀成。", "青紫方拾芥，黃金徒滿籝。誰知懷逸辯，重席冠群英。"]'),
('yuding-29','史','李嶠','唐','御定全唐诗','yuding','','[]','馬記天官設，班圖地裏新。善談方亹亹，青簡見彬彬。',48,'御定全唐詩/json/059.json','["馬記天官設，班圖地裏新。善談方亹亹，青簡見彬彬。", "方朔初聞漢，荊軻昔向秦。正辭堪載筆，終冀作良臣。"]'),
('yuding-30','詩','李嶠','唐','御定全唐诗','yuding','','[]','都尉仙鳧遠，梁王駟馬來。扇中紈素制，機上錦紋回。',48,'御定全唐詩/json/059.json','["都尉仙鳧遠，梁王駟馬來。扇中紈素制，機上錦紋回。", "天子三章傳，陳王七步才。緇衣久擅美，祖德信悠哉。"]'),
('yuding-31','賦','李嶠','唐','御定全唐诗','yuding','','[]','布義孫卿子，登高楚屈平。銅台初下筆，樂觀正飛纓。',48,'御定全唐詩/json/059.json','["布義孫卿子，登高楚屈平。銅台初下筆，樂觀正飛纓。", "乍有淩雲勢，時聞擲地聲。造端長體物，無複大夫名。"]'),
('yuding-32','書','李嶠','唐','御定全唐诗','yuding','','[]','削簡龍文見，臨池鳥跡舒。河圖八卦出，洛范九疇初。',48,'御定全唐詩/json/059.json','["削簡龍文見，臨池鳥跡舒。河圖八卦出，洛范九疇初。", "垂露春光滿，崩雲骨氣餘。請君看入木，一寸乃非虛。"]'),
('yuding-33','檄','李嶠','唐','御定全唐诗','yuding','','[]','羽檄本宣明，由來□木聲。聯翩至漢國，迢遞入燕營。',48,'御定全唐詩/json/059.json','["羽檄本宣明，由來□木聲。聯翩至漢國，迢遞入燕營。", "毛義持書去，張儀韞璧行。曹風雖覺愈，陳草始知名。"]'),
('yuding-34','紙','李嶠','唐','御定全唐诗','yuding','','[]','妙跡蔡侯施，芳名左伯馳。雲飛錦綺落，花發縹紅披。',48,'御定全唐詩/json/059.json','["妙跡蔡侯施，芳名左伯馳。雲飛錦綺落，花發縹紅披。", "舒卷隨幽顯，廉方合軌儀。莫驚反掌字，當取葛洪規。"]'),
('yuding-35','筆','李嶠','唐','御定全唐诗','yuding','','[]','握管門庭側，含毫山水隈。霜輝簡上發，錦字夢中開。',48,'御定全唐詩/json/059.json','["握管門庭側，含毫山水隈。霜輝簡上發，錦字夢中開。", "鸚鵡摛文至，麒麟絕句來。何當遇良史，左右振奇才。"]'),
('yuding-36','硯','李嶠','唐','御定全唐诗','yuding','','[]','左思裁賦日，王充作論年。光隨錦文發，形帶石岩圓。',48,'御定全唐詩/json/059.json','["左思裁賦日，王充作論年。光隨錦文發，形帶石岩圓。", "積潤循毫裏，開池小學前。君苗徒見爇，誰詠士衡篇。"]'),
('yuding-37','墨','李嶠','唐','御定全唐诗','yuding','','[]','長安分石炭，上黨結松心。繞畫蠅初落，含滋綬更深。',48,'御定全唐詩/json/059.json','["長安分石炭，上黨結松心。繞畫蠅初落，含滋綬更深。", "悲絲光易染，疊素彩還沉。別有張芝學，書池幸見臨。"]'),
('yuding-38','劍','李嶠','唐','御定全唐诗','yuding','','[]','我有昆吾劍，求趨夫子庭。白虹時切玉，紫氣夜幹星。',48,'御定全唐詩/json/059.json','["我有昆吾劍，求趨夫子庭。白虹時切玉，紫氣夜幹星。", "鍔上芙蓉動，匣中霜雪明。倚天持報國，畫地取雄名。"]'),
('yuding-39','刀','李嶠','唐','御定全唐诗','yuding','','[]','列辟鳴鸞至，惟良佩犢旋。帶環疑寫月，引鑒似含泉。',48,'御定全唐詩/json/059.json','["列辟鳴鸞至，惟良佩犢旋。帶環疑寫月，引鑒似含泉。", "入夢華梁上，含鋒彩筆前。莫驚開百煉，特擬定三邊。"]'),
('yuding-40','箭','李嶠','唐','御定全唐诗','yuding','','[]','漢甸初收羽，燕城忽解圍。影隨流水急，光帶落星飛。',48,'御定全唐詩/json/059.json','["漢甸初收羽，燕城忽解圍。影隨流水急，光帶落星飛。", "夏列三成範，堯沉九日輝。斷蛟雲夢澤，希為識忘歸。"]'),
('yuding-41','彈','李嶠','唐','御定全唐诗','yuding','','[]','俠客持蘇合，佳游滿帝鄉。避丸深可誚，求炙遂難忘。',48,'御定全唐詩/json/059.json','["俠客持蘇合，佳游滿帝鄉。避丸深可誚，求炙遂難忘。", "金迸疑星落，珠沉似月光。誰知少孺子，將此見吳王。"]'),
('yuding-42','弩','李嶠','唐','御定全唐诗','yuding','','[]','挺質本軒皇，申威振遠方。機張驚雉雊，玉彩耀星芒。',48,'御定全唐詩/json/059.json','["挺質本軒皇，申威振遠方。機張驚雉雊，玉彩耀星芒。", "高鳥行應盡，清猿坐見傷。蘇秦六百步，持此說韓王。"]'),
('yuding-43','旗','李嶠','唐','御定全唐诗','yuding','','[]','桂影承宵月，虹輝接曙雲。縱橫齊八陣，舒卷引三軍。',48,'御定全唐詩/json/059.json','["桂影承宵月，虹輝接曙雲。縱橫齊八陣，舒卷引三軍。", "日薄蛟龍影，風翻鳥隼文。誰知懷勇志，蟠地幾繽紛。"]'),
('yuding-44','旌','李嶠','唐','御定全唐诗','yuding','','[]','告善康莊側，求賢市肆中。擁麾分彩雉，持節曳丹虹。',48,'御定全唐詩/json/059.json','["告善康莊側，求賢市肆中。擁麾分彩雉，持節曳丹虹。", "影麗天山雪，光搖朔塞風。方知美周政，抗旆賦車攻。"]'),
('yuding-45','戈','李嶠','唐','御定全唐诗','yuding','','[]','富父舂喉日，殷辛漂杵年。曉霜含白刃，落影駐雕鋋。',48,'御定全唐詩/json/059.json','["富父舂喉日，殷辛漂杵年。曉霜含白刃，落影駐雕鋋。", "夕擯金門側，朝提玉塞前。願隨龍影度，橫□陣雲邊。"]'),
('yuding-46','鼓','李嶠','唐','御定全唐诗','yuding','','[]','舜日諧鞀響，堯年韻士聲。向樓疑吹擊，震谷似雷驚。',48,'御定全唐詩/json/059.json','["舜日諧鞀響，堯年韻士聲。向樓疑吹擊，震谷似雷驚。", "仙鶴排門起，靈鼉帶水鳴。樂雲行已奏，禮曰冀相成。"]'),
('yuding-47','弓','李嶠','唐','御定全唐诗','yuding','','[]','桃文稱辟惡，桑質表初生。宛轉雕鞬際，依稀半月明。',48,'御定全唐詩/json/059.json','["桃文稱辟惡，桑質表初生。宛轉雕鞬際，依稀半月明。", "遙彎落雁影，虛引怯猿聲。徒切烏號思，攀龍遂不成。"]'),
('yuding-48','琴','李嶠','唐','御定全唐诗','yuding','','[]','名士竹林隈，鳴琴寶匣開。風前中散至，月下步兵來。',48,'御定全唐詩/json/059.json','["名士竹林隈，鳴琴寶匣開。風前中散至，月下步兵來。", "淮海多為室，梁岷舊作台。子期如可聽，山水響餘哀。"]'),
('yuding-49','瑟','李嶠','唐','御定全唐诗','yuding','','[]','伏羲初制法，素女昔傳名。流水嘉魚躍，叢台舞鳳驚。',48,'御定全唐詩/json/059.json','["伏羲初制法，素女昔傳名。流水嘉魚躍，叢台舞鳳驚。", "嘉賓飲未極，君子娛俱並。倘入丘之戶，應知由也情。"]'),
('yuding-50','琵琶','李嶠','唐','御定全唐诗','yuding','','[]','朱絲聞岱穀，鑠質本多端。半月分弦出，叢花拂面安。',48,'御定全唐詩/json/059.json','["朱絲聞岱穀，鑠質本多端。半月分弦出，叢花拂面安。", "將軍曾制曲，司馬屢陪觀。本是胡中樂，希君馬上彈。"]'),
('yuding-51','箏','李嶠','唐','御定全唐诗','yuding','','[]','蒙恬芳軌設，游楚妙彈開。新曲帳中發，清音指下來。',48,'御定全唐詩/json/059.json','["蒙恬芳軌設，游楚妙彈開。新曲帳中發，清音指下來。", "鈿裝模六律，柱列配三才。莫聽西秦奏，箏箏有剩哀。"]'),
('yuding-52','鐘','李嶠','唐','御定全唐诗','yuding','','[]','既接南鄰磬，還隨北裏笙。平陵通曙響，長樂警宵聲。',48,'御定全唐詩/json/059.json','["既接南鄰磬，還隨北裏笙。平陵通曙響，長樂警宵聲。", "秋至含霜動，春歸應律鳴。欲知常待扣，金簴有餘清。"]'),
('yuding-53','簫','李嶠','唐','御定全唐诗','yuding','','[]','虞舜調清管，王褒賦雅音。參差橫鳳翼，搜索動人心。',48,'御定全唐詩/json/059.json','["虞舜調清管，王褒賦雅音。參差橫鳳翼，搜索動人心。", "□□□□□，□□□□□。□□□□□，□□□□□。"]'),
('yuding-54','笛','李嶠','唐','御定全唐诗','yuding','','[]','羌笛寫龍聲，長吟入夜清。關山孤月下，來向隴頭鳴。',48,'御定全唐詩/json/059.json','["羌笛寫龍聲，長吟入夜清。關山孤月下，來向隴頭鳴。", "逐吹梅花落，含春柳色驚。行觀向子賦，坐憶舊鄰情。"]'),
('yuding-55','笙','李嶠','唐','御定全唐诗','yuding','','[]','懸匏曲沃上，孤筱汶陽隈。形寫歌鸞翼，聲隨舞鳳哀。',48,'御定全唐詩/json/059.json','["懸匏曲沃上，孤筱汶陽隈。形寫歌鸞翼，聲隨舞鳳哀。", "歡娛分北裏，純孝即南陔。今日虞音奏，蹌蹌鳥獸來。"]'),
('yuding-56','歌','李嶠','唐','御定全唐诗','yuding','','[]','漢帝臨汾水，周仙去洛濱。郢中吟白雪，梁上繞飛塵。',48,'御定全唐詩/json/059.json','["漢帝臨汾水，周仙去洛濱。郢中吟白雪，梁上繞飛塵。", "響發行雲駐，聲隨子夜新。願君聽扣角，當自識賢臣。"]'),
('yuding-57','舞','李嶠','唐','御定全唐诗','yuding','','[]','妙伎游金谷，佳人滿石城。霞衣席上轉，花岫雪前明。',48,'御定全唐詩/json/059.json','["妙伎游金谷，佳人滿石城。霞衣席上轉，花岫雪前明。", "儀鳳諧清曲，回鸞應雅聲。非君一顧重，誰賞素腰輕。"]'),
('yuding-0','珠','李嶠','唐','御定全唐诗','yuding','','[]','燦爛金輿側，玲瓏玉殿隈。昆池明月滿，合浦夜光回。',48,'御定全唐詩/json/060.json','["燦爛金輿側，玲瓏玉殿隈。昆池明月滿，合浦夜光回。", "彩逐靈蛇轉，形隨舞鳳來。甘泉宮起罷，花媚望風台。"]'),
('yuding-1','玉','李嶠','唐','御定全唐诗','yuding','','[]','映石先過魏，連城欲向秦。洛陽陪勝友，燕趙類佳人。',48,'御定全唐詩/json/060.json','["映石先過魏，連城欲向秦。洛陽陪勝友，燕趙類佳人。", "方水晴虹媚，常山瑞馬新。徒為卞和識，不遇楚王珍。"]'),
('yuding-2','金','李嶠','唐','御定全唐诗','yuding','','[]','南楚標前貢，西秦識舊城。祭天封漢嶺，擲地警孫聲。',48,'御定全唐詩/json/060.json','["南楚標前貢，西秦識舊城。祭天封漢嶺，擲地警孫聲。", "向日披沙淨，含風振鐸鳴。方同楊伯起，獨有四知名。"]'),
('yuding-3','銀','李嶠','唐','御定全唐诗','yuding','','[]','思婦屏輝掩，遊人燭影長。玉壺初下箭，桐井共安床。',48,'御定全唐詩/json/060.json','["思婦屏輝掩，遊人燭影長。玉壺初下箭，桐井共安床。", "色帶長河色，光浮滿月光。靈山有珍甕，仙闕薦君王。"]'),
('yuding-4','錢','李嶠','唐','御定全唐诗','yuding','','[]','漢日五銖建，姬年九府流。天龍帶泉寶，地馬列金溝。',48,'御定全唐詩/json/060.json','["漢日五銖建，姬年九府流。天龍帶泉寶，地馬列金溝。", "趙壹囊初乏，何曾箸欲收。金門應入論，玉井冀來求。"]'),
('yuding-5','錦','李嶠','唐','御定全唐诗','yuding','','[]','漢使巾車遠，河陽步障陳。雲浮仙石日，霞滿蜀江春。',48,'御定全唐詩/json/060.json','["漢使巾車遠，河陽步障陳。雲浮仙石日，霞滿蜀江春。", "機迥回文巧，紳兼束發新。若逢楚王貴，不作夜行人。"]'),
('yuding-6','羅','李嶠','唐','御定全唐诗','yuding','','[]','妙舞隨裙動，行歌入扇清。蓮花依帳發，秋月鑒帷明。',48,'御定全唐詩/json/060.json','["妙舞隨裙動，行歌入扇清。蓮花依帳發，秋月鑒帷明。", "雲薄衣初卷，蟬飛翼轉輕。若珍三代服，同擅綺紈名。"]'),
('yuding-7','綾','李嶠','唐','御定全唐诗','yuding','','[]','金縷通秦國，為裘指魏君。落花遙寫霧，飛鶴近圖雲。',48,'御定全唐詩/json/060.json','["金縷通秦國，為裘指魏君。落花遙寫霧，飛鶴近圖雲。", "馬眼冰淩影，竹根雪霰文。何當畫秦女，煙際坐氤氳。"]'),
('yuding-8','素','李嶠','唐','御定全唐诗','yuding','','[]','□□□□女，纖腰洛浦妃。□□遠方望，雁足上林飛。',48,'御定全唐詩/json/060.json','["□□□□女，纖腰洛浦妃。□□遠方望，雁足上林飛。", "妙奪鮫綃色，光騰月扇輝。非君下路去，誰賞故人機。"]'),
('yuding-9','布','李嶠','唐','御定全唐诗','yuding','','[]','禦績創羲黃，緇冠表素王。瀑飛臨碧海，火浣擅炎方。',48,'御定全唐詩/json/060.json','["禦績創羲黃，緇冠表素王。瀑飛臨碧海，火浣擅炎方。", "孫被登三相，劉衣闡四方。佇因舂鬥粟，來曉棣華芳。"]'),
('yuding-10','舟','李嶠','唐','御定全唐诗','yuding','','[]','征棹三江暮，連檣萬里回。相烏風際轉，畫鷁浪前開。',48,'御定全唐詩/json/060.json','["征棹三江暮，連檣萬里回。相烏風際轉，畫鷁浪前開。", "羽客乘霞至，仙人弄月來。何當同傅說，特展巨川材。"]'),
('yuding-11','車','李嶠','唐','御定全唐诗','yuding','','[]','天子馭金根，蒲輪辟四門。五神趨雪至，雙轂似雷奔。',48,'御定全唐詩/json/060.json','["天子馭金根，蒲輪辟四門。五神趨雪至，雙轂似雷奔。", "丹鳳棲金轄，非熊載寶軒。無階忝虛左，珠乘奉王言。"]'),
('yuding-12','床','李嶠','唐','御定全唐诗','yuding','','[]','傳聞有象床，疇昔獻君王。玳瑁千金起，珊瑚七寶妝。',48,'御定全唐詩/json/060.json','["傳聞有象床，疇昔獻君王。玳瑁千金起，珊瑚七寶妝。", "桂筵含柏馥，蘭席拂沉香。願奉羅帷夜，長乘秋月光。"]'),
('yuding-13','席','李嶠','唐','御定全唐诗','yuding','','[]','避席承宣父，重筵揖戴公。桂香浮半月，蘭氣襲回風。',48,'御定全唐詩/json/060.json','["避席承宣父，重筵揖戴公。桂香浮半月，蘭氣襲回風。", "舞拂丹霞上，歌清白雪中。佇將文綺色，舒卷帝王宮。"]'),
('yuding-14','帷','李嶠','唐','御定全唐诗','yuding','','[]','久閉先生戶，高褰太守車。羅將翡翠合，錦逐鳳凰舒。',48,'御定全唐詩/json/060.json','["久閉先生戶，高褰太守車。羅將翡翠合，錦逐鳳凰舒。", "明月彈琴夜，清風入幌初。方知決勝策，黃石受兵書。"]'),
('yuding-15','簾','李嶠','唐','御定全唐诗','yuding','','[]','清風時入燕，紫殿幾含秋。曖曖籠鈴閣，纖纖上玉鉤。',48,'御定全唐詩/json/060.json','["清風時入燕，紫殿幾含秋。曖曖籠鈴閣，纖纖上玉鉤。", "窗中翡翠動，戶外水精浮。巧作盤龍勢，長迎飛燕遊。"]'),
('yuding-16','屏','李嶠','唐','御定全唐诗','yuding','','[]','洞徹琉璃蔽，威紆屈膝回。錦中雲母列，霞上織成開。',48,'御定全唐詩/json/060.json','["洞徹琉璃蔽，威紆屈膝回。錦中雲母列，霞上織成開。", "山水含春動，神仙倒景來。修身兼竭節，誰識作銘才。"]'),
('yuding-17','被','李嶠','唐','御定全唐诗','yuding','','[]','桂友尋東閣，蘭交聚北堂。象筵分錦繡，羅薦合鴛鴦。',48,'御定全唐詩/json/060.json','["桂友尋東閣，蘭交聚北堂。象筵分錦繡，羅薦合鴛鴦。", "光逸偷眠穩，王章泣恨長。孔懷欣共寢，棣萼幾含芳。"]'),
('yuding-18','鑒','李嶠','唐','御定全唐诗','yuding','','[]','明鑒掩塵埃，含情照魏台。日中烏鵲至，花裏鳳凰來。',48,'御定全唐詩/json/060.json','["明鑒掩塵埃，含情照魏台。日中烏鵲至，花裏鳳凰來。", "玉彩疑冰徹，金輝似月開。方知樂彥輔，自有鑒人才。"]'),
('yuding-19','扇','李嶠','唐','御定全唐诗','yuding','','[]','翟羽舊傳名，蒲葵價不輕。花芳不滿面，羅薄詎障聲。',48,'御定全唐詩/json/060.json','["翟羽舊傳名，蒲葵價不輕。花芳不滿面，羅薄詎障聲。", "禦熱含風細，臨秋帶月明。同心如可贈，持表合歡情。"]'),
('yuding-20','燭','李嶠','唐','御定全唐诗','yuding','','[]','兔月清光隱，龍盤畫燭新。三星花入夜，四序玉調晨。',48,'御定全唐詩/json/060.json','["兔月清光隱，龍盤畫燭新。三星花入夜，四序玉調晨。", "浮炷依羅幌，吹香匝綺茵。若逢燕國相，持用舉賢人。"]'),
('yuding-21','酒','李嶠','唐','御定全唐诗','yuding','','[]','孔坐洽良儔，陳筵幾獻酬。臨風竹葉滿，湛月桂香浮。',48,'御定全唐詩/json/060.json','["孔坐洽良儔，陳筵幾獻酬。臨風竹葉滿，湛月桂香浮。", "每接高陽宴，長陪河朔遊。會從玄石飲，雲雨出圓丘。"]'),
('yuding-22','蘭','李嶠','唐','御定全唐诗','yuding','','[]','虛室重招尋，忘言契斷金。英浮漢家酒，雪儷楚王琴。',48,'御定全唐詩/json/060.json','["虛室重招尋，忘言契斷金。英浮漢家酒，雪儷楚王琴。", "廣殿輕香發，高臺遠吹吟。河汾應擢秀，誰肯訪山陰。"]'),
('yuding-23','菊','李嶠','唐','御定全唐诗','yuding','','[]','玉律三秋暮，金精九日開。榮舒洛媛浦，香泛野人杯。',48,'御定全唐詩/json/060.json','["玉律三秋暮，金精九日開。榮舒洛媛浦，香泛野人杯。", "靃靡寒潭側，豐茸曉岸隈。黃花今日晚，無複白衣來。"]'),
('yuding-24','竹','李嶠','唐','御定全唐诗','yuding','','[]','高簳楚江濆，嬋娟含曙氛。白花搖鳳影，青節動龍文。',48,'御定全唐詩/json/060.json','["高簳楚江濆，嬋娟含曙氛。白花搖鳳影，青節動龍文。", "葉掃東南日，枝捎西北雲。誰知湘水上，流淚獨思君。"]'),
('yuding-25','藤','李嶠','唐','御定全唐诗','yuding','','[]','吐葉依松磴，舒苗長石台。神農嘗藥罷，質子寄書來。',48,'御定全唐詩/json/060.json','["吐葉依松磴，舒苗長石台。神農嘗藥罷，質子寄書來。", "色映蒲萄架，花分竹葉杯。金堤不見識，玉潤幾重開。"]'),
('yuding-26','萱','李嶠','唐','御定全唐诗','yuding','','[]','屣步尋芳草，忘憂自結叢。黃英開養性，綠葉正依籠。',48,'御定全唐詩/json/060.json','["屣步尋芳草，忘憂自結叢。黃英開養性，綠葉正依籠。", "色湛仙人露，香傳少女風。還依北堂下，曹植動文雄。"]'),
('yuding-27','茅','李嶠','唐','御定全唐诗','yuding','','[]','楚甸供王日，衡陽入貢年。麏包青野外，鴟嘯綺楹前。',48,'御定全唐詩/json/060.json','["楚甸供王日，衡陽入貢年。麏包青野外，鴟嘯綺楹前。", "堯帝成茨罷，殷湯祭雨旋。方期大君錫，不懼小巫捐。"]'),
('yuding-28','荷','李嶠','唐','御定全唐诗','yuding','','[]','新溜滿澄陂，圓荷影若規。風來香氣遠，日落蓋陰移。',48,'御定全唐詩/json/060.json','["新溜滿澄陂，圓荷影若規。風來香氣遠，日落蓋陰移。", "魚戲排緗葉，龜浮見綠池。魏朝難接采，楚服但同披。"]'),
('yuding-29','萍','李嶠','唐','御定全唐诗','yuding','','[]','二月虹初見，三春蟻正浮。青蘋含吹轉，紫蒂帶波流。',48,'御定全唐詩/json/060.json','["二月虹初見，三春蟻正浮。青蘋含吹轉，紫蒂帶波流。", "屢逐明神薦，常隨旅客游。既能甜似蜜，還繞楚王舟。"]'),
('yuding-30','菱','李嶠','唐','御定全唐诗','yuding','','[]','鉅野韶光暮，東平春溜通。影搖江浦月，香引棹歌風。',48,'御定全唐詩/json/060.json','["鉅野韶光暮，東平春溜通。影搖江浦月，香引棹歌風。", "日色翻池上，潭花發鏡中。五湖多賞樂，千里望難窮。"]'),
('yuding-31','瓜','李嶠','唐','御定全唐诗','yuding','','[]','欲識東陵味，青門五色瓜。龍蹄遠珠履，女臂動金花。',48,'御定全唐詩/json/060.json','["欲識東陵味，青門五色瓜。龍蹄遠珠履，女臂動金花。", "六子方呈瑞，三仙實可嘉。終朝奉絺綌，謁帝佇非賒。"]'),
('yuding-32','松','李嶠','唐','御定全唐诗','yuding','','[]','鬱鬱高岩表，森森幽澗陲。鶴棲君子樹，風拂大夫枝。',48,'御定全唐詩/json/060.json','["鬱鬱高岩表，森森幽澗陲。鶴棲君子樹，風拂大夫枝。", "百尺條陰合，千年蓋影披。歲寒終不改，勁節幸君知。"]'),
('yuding-33','桂','李嶠','唐','御定全唐诗','yuding','','[]','未殖銀宮裏，寧移玉殿幽。枝生無限月，花滿自然秋。',48,'御定全唐詩/json/060.json','["未殖銀宮裏，寧移玉殿幽。枝生無限月，花滿自然秋。", "俠客條為馬，仙人葉作舟。願君期道術，攀折可淹留。"]'),
('yuding-34','槐','李嶠','唐','御定全唐诗','yuding','','[]','暮律移寒火，春宮長舊栽。葉生馳道側，花落鳳庭隈。',48,'御定全唐詩/json/060.json','["暮律移寒火，春宮長舊栽。葉生馳道側，花落鳳庭隈。", "烈士懷忠觸，鴻儒訪業來。何當赤墀下，疏幹擬三台。"]'),
('yuding-35','柳','李嶠','唐','御定全唐诗','yuding','','[]','楊柳鬱氤氳，金堤總翠氛。庭前花類雪，樓際葉如雲。',48,'御定全唐詩/json/060.json','["楊柳鬱氤氳，金堤總翠氛。庭前花類雪，樓際葉如雲。", "列宿分龍影，芳池寫鳳文。短簫何以奏，攀折為思君。"]'),
('yuding-36','桐','李嶠','唐','御定全唐诗','yuding','','[]','孤秀嶧陽岑，亭亭出眾林。春光雜鳳影，秋月弄圭陰。',48,'御定全唐詩/json/060.json','["孤秀嶧陽岑，亭亭出眾林。春光雜鳳影，秋月弄圭陰。", "高映龍門迥，雙依玉井深。不因將入爨，誰謂作鳴琴。"]'),
('yuding-37','桃','李嶠','唐','御定全唐诗','yuding','','[]','獨有成蹊處，穠華髮井傍。山風凝笑臉，朝露泫啼妝。',48,'御定全唐詩/json/060.json','["獨有成蹊處，穠華髮井傍。山風凝笑臉，朝露泫啼妝。", "隱士顏應改，仙人路漸長。還欣上林苑，千歲奉君王。"]'),
('yuding-38','李','李嶠','唐','御定全唐诗','yuding','','[]','潘嶽閒居日，王戎戲陌辰。蝶遊芳徑馥，鶯囀弱枝新。',48,'御定全唐詩/json/060.json','["潘嶽閒居日，王戎戲陌辰。蝶遊芳徑馥，鶯囀弱枝新。", "葉暗青房晚，花明玉井春。方知有靈幹，特用表真人。"]'),
('yuding-39','梨','李嶠','唐','御定全唐诗','yuding','','[]','擅美玄光側，傳芳瀚海中。鳳文疏象郡，花影麗新豐。',48,'御定全唐詩/json/060.json','["擅美玄光側，傳芳瀚海中。鳳文疏象郡，花影麗新豐。", "色對瑤池紫，甘依大穀紅。若令逢漢主，還冀識張公。"]'),
('yuding-40','梅','李嶠','唐','御定全唐诗','yuding','','[]','大庾斂寒光，南枝獨早芳。雪含朝暝色，風引去來香。',48,'御定全唐詩/json/060.json','["大庾斂寒光，南枝獨早芳。雪含朝暝色，風引去來香。", "妝面回青鏡，歌塵起畫梁。若能遙止渴，何暇泛瓊漿。"]'),
('yuding-41','橘','李嶠','唐','御定全唐诗','yuding','','[]','萬里盤根植，千秋布葉繁。既榮潘子賦，方重陸生言。',48,'御定全唐詩/json/060.json','["萬里盤根植，千秋布葉繁。既榮潘子賦，方重陸生言。", "玉花含霜動，金衣逐吹翻。願辭湘水曲，長茂上林園。"]'),
('yuding-42','鳳','李嶠','唐','御定全唐诗','yuding','','[]','有鳥居丹穴，其名曰鳳凰。九苞應靈瑞，五色成文章。',48,'御定全唐詩/json/060.json','["有鳥居丹穴，其名曰鳳凰。九苞應靈瑞，五色成文章。", "屢向秦樓側，頻過洛水陽。鳴岐今日見，阿合佇來翔。"]'),
('yuding-43','鶴','李嶠','唐','御定全唐诗','yuding','','[]','黃鶴遠聯翩，從鸞下紫煙。翱翔一萬里，來去幾千年。',48,'御定全唐詩/json/060.json','["黃鶴遠聯翩，從鸞下紫煙。翱翔一萬里，來去幾千年。", "已憩青田側，時遊丹禁前。莫言空警露，猶冀一聞天。"]'),
('yuding-44','烏','李嶠','唐','御定全唐诗','yuding','','[]','日路朝飛急，霜台夕影寒。聯翩依月樹，迢遞繞風竿。',48,'御定全唐詩/json/060.json','["日路朝飛急，霜台夕影寒。聯翩依月樹，迢遞繞風竿。", "白首何年改，青琴此夜彈。靈台如可托，千里向長安。"]'),
('yuding-45','鵲','李嶠','唐','御定全唐诗','yuding','','[]','不分荊山抵，甘從石印飛。危巢畏風急，繞樹覺星稀。',48,'御定全唐詩/json/060.json','["不分荊山抵，甘從石印飛。危巢畏風急，繞樹覺星稀。", "喜逐行人至，愁隨織女歸。倘遊明鏡裏，朝夕動光輝。"]'),
('yuding-46','雁','李嶠','唐','御定全唐诗','yuding','','[]','春暉滿朔方，歸雁發衡陽。望月驚弦影，排雲結陣行。',48,'御定全唐詩/json/060.json','["春暉滿朔方，歸雁發衡陽。望月驚弦影，排雲結陣行。", "往還倦南北，朝夕苦風霜。寄語能鳴侶，相隨入帝鄉。"]'),
('yuding-47','鳧','李嶠','唐','御定全唐诗','yuding','','[]','颯遝睢陽涘，浮游漢水隈。錢飛出井見，鶴引入琴哀。',48,'御定全唐詩/json/060.json','["颯遝睢陽涘，浮游漢水隈。錢飛出井見，鶴引入琴哀。", "李陵賦詩罷，王喬曳舄來。何當歸太液，翱集動成雷。"]'),
('yuding-48','鶯','李嶠','唐','御定全唐诗','yuding','','[]','芳樹雜花紅，群鶯亂曉空。聲分折楊吹，嬌韻落梅風。',48,'御定全唐詩/json/060.json','["芳樹雜花紅，群鶯亂曉空。聲分折楊吹，嬌韻落梅風。", "寫囀清弦裏，遷喬暗木中。友生若可冀，幽谷響還通。"]'),
('yuding-49','雉','李嶠','唐','御定全唐诗','yuding','','[]','白雉振朝聲，飛來表太平。楚郊疑鳳出，陳寶若雞鳴。',48,'御定全唐詩/json/060.json','["白雉振朝聲，飛來表太平。楚郊疑鳳出，陳寶若雞鳴。", "童子懷仁至，中郎作賦成。冀君看飲啄，耿介獨含情。"]'),
('yuding-50','燕','李嶠','唐','御定全唐诗','yuding','','[]','天女伺辰至，玄衣澹碧空。差池沐時雨，頡頏舞春風。',48,'御定全唐詩/json/060.json','["天女伺辰至，玄衣澹碧空。差池沐時雨，頡頏舞春風。", "相賀雕闌側，雙飛翠幕中。勿驚留爪去，猶冀識吳宮。"]'),
('yuding-51','雀','李嶠','唐','御定全唐诗','yuding','','[]','大廈初成日，嘉賓集杏梁。銜書表周瑞，入幕應王祥。',48,'御定全唐詩/json/060.json','["大廈初成日，嘉賓集杏梁。銜書表周瑞，入幕應王祥。", "暮宿江城裏，朝游漣水傍。願齊鴻鵠至，希逐鳳凰翔。"]'),
('yuding-52','龍','李嶠','唐','御定全唐诗','yuding','','[]','銜燭耀幽都，含章擬鳳雛。西秦飲渭水，東洛薦河圖。',48,'御定全唐詩/json/060.json','["銜燭耀幽都，含章擬鳳雛。西秦飲渭水，東洛薦河圖。", "帶火移星陸，升雲出鼎湖。希逢聖人步，庭闕正晨趨。"]'),
('yuding-53','麟','李嶠','唐','御定全唐诗','yuding','','[]','漢祀應祥開，魯郊西狩回。奇音中鐘呂，成角喻英才。',48,'御定全唐詩/json/060.json','["漢祀應祥開，魯郊西狩回。奇音中鐘呂，成角喻英才。", "畫像臨仙閣，藏書入帝台。若驚能吐哺，為待鳳凰來。"]'),
('yuding-54','象','李嶠','唐','御定全唐诗','yuding','','[]','郁林開郡畢，維揚作貢初。萬推方演夢，惠子正焚書。',48,'御定全唐詩/json/060.json','["郁林開郡畢，維揚作貢初。萬推方演夢，惠子正焚書。", "執燧奔吳戰，量舟入魏墟。六牙行致遠，千葉奉高居。"]'),
('yuding-55','馬','李嶠','唐','御定全唐诗','yuding','','[]','天馬本來東，嘶驚禦史驄。蒼龍遙逐日，紫燕迥追風。',48,'御定全唐詩/json/060.json','["天馬本來東，嘶驚禦史驄。蒼龍遙逐日，紫燕迥追風。", "明月來鞍上，浮雲落蓋中。得隨穆天子，何假唐成公。"]'),
('yuding-56','牛','李嶠','唐','御定全唐诗','yuding','','[]','齊歌初入相，燕陣早橫功。欲向桃林下，先過梓樹中。',48,'御定全唐詩/json/060.json','["齊歌初入相，燕陣早橫功。欲向桃林下，先過梓樹中。", "在吳頻喘月，奔夢屢驚風。不用五丁士，如何九折通。"]'),
('yuding-57','豹','李嶠','唐','御定全唐诗','yuding','','[]','車法肇宗周，鼷文闡大猷。還將君子變，來蘊太公籌。',48,'御定全唐詩/json/060.json','["車法肇宗周，鼷文闡大猷。還將君子變，來蘊太公籌。", "委質超羊鞟，飛名列虎侯。若令逢雨露，長隱南山幽。"]'),
('yuding-58','熊','李嶠','唐','御定全唐诗','yuding','','[]','導洛宜陽右，乘春別館前。昭儀忠漢日，太傅翊周年。',48,'御定全唐詩/json/060.json','["導洛宜陽右，乘春別館前。昭儀忠漢日，太傅翊周年。", "列射三侯滿，興師七步旋。莫言舒紫褥，猶異飲清泉。"]'),
('yuding-59','鹿','李嶠','唐','御定全唐诗','yuding','','[]','涿鹿聞中冀，秦原辟帝畿。柰花開舊苑，萍葉藹前詩。',48,'御定全唐詩/json/060.json','["涿鹿聞中冀，秦原辟帝畿。柰花開舊苑，萍葉藹前詩。", "道士乘仙日，先生折角時。方懷丈夫志，抗首別心期。"]'),
('yuding-60','羊','李嶠','唐','御定全唐诗','yuding','','[]','絕飲懲澆俗，行驅夢逸材。仙人擁石去，童子馭車來。',48,'御定全唐詩/json/060.json','["絕飲懲澆俗，行驅夢逸材。仙人擁石去，童子馭車來。", "夜玉含星動，晨氈映雪開。莫言鴻漸力，長牧上林隈。"]'),
('yuding-61','兔','李嶠','唐','御定全唐诗','yuding','','[]','上蔡應初擊，平岡遠不稀。目隨槐葉長，形逐桂條飛。',48,'御定全唐詩/json/060.json','["上蔡應初擊，平岡遠不稀。目隨槐葉長，形逐桂條飛。", "漢月澄秋色，梁園映雪輝。唯當感純孝，郛郭引兵威。"]'),
('yuding-0','人日侍宴大明宮恩賜彩縷人勝應制','李嶠','唐','御定全唐诗','yuding','','[]','鳳城景色已含韶，人日風光倍覺饒。桂吐半輪迎此夜，',40,'御定全唐詩/json/061.json','["鳳城景色已含韶，人日風光倍覺饒。桂吐半輪迎此夜，", "愧奉登高搖彩翰，欣逢禦氣上丹霄。"]'),
('yuding-1','奉和初春幸太平公主南莊應制','李嶠','唐','御定全唐诗','yuding','','[]','主家山第接雲開，天子春遊動地來。羽騎參差花外轉，',40,'御定全唐詩/json/061.json','["主家山第接雲開，天子春遊動地來。羽騎參差花外轉，", "鸞輅已辭烏鵲渚，簫聲猶繞鳳凰台。"]'),
('yuding-2','太平公主山亭侍宴應制','李嶠','唐','御定全唐诗','yuding','','[]','黃金瑞榜絳河隈，白玉仙輿紫禁來。碧樹青岑雲外聳，',40,'御定全唐詩/json/061.json','["黃金瑞榜絳河隈，白玉仙輿紫禁來。碧樹青岑雲外聳，", "遽惜歡娛歌吹晚，揮戈更卻曜靈回。"]'),
('yuding-3','奉和拜洛應制','李嶠','唐','御定全唐诗','yuding','','[]','七萃鑾輿動，千年瑞檢開。文如龜負出，圖似鳳銜來。',60,'御定全唐詩/json/061.json','["七萃鑾輿動，千年瑞檢開。文如龜負出，圖似鳳銜來。", "殷薦三神享，明禋萬國陪。周旗黃鳥集，漢幄紫雲回。", "日暮鉤陳轉，清歌上帝台。"]'),
('yuding-4','奉和幸大薦福寺應制','李嶠','唐','御定全唐诗','yuding','','[]','雁沼開香域，鸚林降彩旃。還窺圖鳳宇，更坐躍龍川。',72,'御定全唐詩/json/061.json','["雁沼開香域，鸚林降彩旃。還窺圖鳳宇，更坐躍龍川。", "桂輿朝群辟，蘭宮列四禪。半空銀合斷，分砌寶繩連。", "甘雨蘇燋澤，慈雲動沛篇。獨慚賢作礪，空喜福成田。"]'),
('yuding-5','奉和幸長安故城未央宮應制','李嶠','唐','御定全唐诗','yuding','','[]','舊宮賢相築，新苑聖君來。運改城隍變，年深棟宇摧。',72,'御定全唐詩/json/061.json','["舊宮賢相築，新苑聖君來。運改城隍變，年深棟宇摧。", "後池無複水，前殿久成灰。莫辨祈風觀，空傳承露杯。", "宸心千載合，睿律九韻開。今日聯章處，猶疑上柏台。"]'),
('yuding-6','奉和幸望春宮送朔方總管張仁亶','李嶠','唐','御定全唐诗','yuding','','[]','玉塞征驕子，金符命老臣。三軍張武旆，萬乘餞行輪。',72,'御定全唐詩/json/061.json','["玉塞征驕子，金符命老臣。三軍張武旆，萬乘餞行輪。", "猛氣淩玄朔，崇恩降紫宸。投醪還結士，辭第本忘身。", "露下鷹初擊，風高雁欲賓。方銷塞北祲，還靖漠南塵。"]'),
('yuding-7','奉和幸三會寺應制','李嶠','唐','御定全唐诗','yuding','','[]','故台蒼頡裏，新邑紫泉居。歲在開金寺，時來降玉輿。',72,'御定全唐詩/json/061.json','["故台蒼頡裏，新邑紫泉居。歲在開金寺，時來降玉輿。", "龍形雖近刹，鳥跡尚留書。竹是蒸青外，池仍點墨餘。", "天文光聖草，寶思合真如。謬奉千齡日，欣陪十地初。"]'),
('yuding-8','奉和天樞成宴夷夏群僚應制','李嶠','唐','御定全唐诗','yuding','','[]','轍跡光西崦，勳庸紀北燕。何如萬方會，頌德九門前。',96,'御定全唐詩/json/061.json','["轍跡光西崦，勳庸紀北燕。何如萬方會，頌德九門前。", "灼灼臨黃道，迢迢入紫煙。仙盤正下露，高柱欲承天。", "山類叢雲起，珠疑大火懸。聲流塵作劫，業固海成田。", "帝澤傾堯酒，宸歌掩舜弦。欣逢下生日，還睹上皇年。"]'),
('yuding-9','皇帝上禮撫事述懷','李嶠','唐','御定全唐诗','yuding','','[]','配極輝光遠，承天顧托隆。負圖濟多難，脫履歸成功。',120,'御定全唐詩/json/061.json','["配極輝光遠，承天顧托隆。負圖濟多難，脫履歸成功。", "聖道昭永錫，邕言讓在躬。還推萬方重，咸仰四門聰。", "恭已忘自逸，因人體至公。垂旒滄海晏，解網法星空。", "雲散天五色，春還日再中。稱觴合纓弁，率舞應絲桐。", "凱樂深居鎬，傳歌盛飲豐。小臣濫簪筆，無以頌唐風。"]'),
('yuding-10','奉和幸韋嗣立山莊侍宴應制','李嶠','唐','御定全唐诗','yuding','','[]','南洛師臣契，東岩王佐居。幽情遺紱冕，宸眷屬樵漁。',120,'御定全唐詩/json/061.json','["南洛師臣契，東岩王佐居。幽情遺紱冕，宸眷屬樵漁。", "制下峒山蹕，恩回灞水輿。松門駐旌蓋，薜幄引簪裾。", "石磴平黃陸，煙樓半紫虛。雲霞仙路近，琴酒俗塵疏。", "喬木千齡外，懸泉百丈餘。崖深經煉藥，穴古舊藏書。", "樹宿摶風鳥，池潛縱壑魚。甯知天子貴，尚憶武侯廬。"]'),
('yuding-11','倡婦行','李嶠','唐','御定全唐诗','yuding','','[]','十年倡家婦，三秋邊地人。紅妝樓上歇，白髮隴頭新。',96,'御定全唐詩/json/061.json','["十年倡家婦，三秋邊地人。紅妝樓上歇，白髮隴頭新。", "夜夜風霜苦，年年征戍頻。山西長落日，塞北久無春。", "團扇辭恩寵，回文贈苦辛。胡兵屢攻戰，漢使絕和親。", "消息如瓶井，沉浮似路塵。空餘千里月，照妾兩眉嚬。"]'),
('yuding-12','餞薛大夫護邊','李嶠','唐','御定全唐诗','yuding','','[]','荒隅時未通，副相下臨戎。授律星芒動，分兵月暈空。',72,'御定全唐詩/json/061.json','["荒隅時未通，副相下臨戎。授律星芒動，分兵月暈空。", "犀皮擁青橐，象齒飾雕弓。決勝三河勇，長驅六郡雄。", "登山窺代北，屈指計遼東。佇見燕然上，抽毫頌武功。"]'),
('yuding-13','和杜學士旅次淮口阻風','李嶠','唐','御定全唐诗','yuding','','[]','夕吹生寒浦，清淮上暝潮。迎風欲舉棹，觸浪反停橈。',72,'御定全唐詩/json/061.json','["夕吹生寒浦，清淮上暝潮。迎風欲舉棹，觸浪反停橈。", "淼漫煙波闊，參差林岸遙。日沉丹氣斂，天敞白雲銷。", "水雁銜蘆葉，沙鷗隱荻苗。客行殊未已，川路幾迢迢。"]'),
('yuding-14','送光祿劉主簿之洛','李嶠','唐','御定全唐诗','yuding','','[]','函穀雙崤右，伊川二陝東。仙舟窅將隔，芳斝暫雲同。',72,'御定全唐詩/json/061.json','["函穀雙崤右，伊川二陝東。仙舟窅將隔，芳斝暫雲同。", "朋席餘歡盡，文房舊侶空。他鄉千里月，岐路九秋風。", "背櫪嘶班馬，分洲叫斷鴻。別後青山外，相望白雲中。"]'),
('yuding-15','送駱奉禮從軍','李嶠','唐','御定全唐诗','yuding','','[]','玉塞邊烽舉，金壇廟略申。羽書資銳筆，戎幕引英賓。',72,'御定全唐詩/json/061.json','["玉塞邊烽舉，金壇廟略申。羽書資銳筆，戎幕引英賓。", "劍動三軍氣，衣飄萬里塵。琴尊留別賞，風景惜離晨。", "笛梅含晚吹，營柳帶餘春。希君勒石返，歌舞入城闉。"]'),
('yuding-16','王屋山第之側雜構小亭，暇日與群公同游','李嶠','唐','御定全唐诗','yuding','','[]','桂亭依絕巘，蘭榭俯回溪。綺棟魚鱗出，雕甍鳳羽棲。',84,'御定全唐詩/json/061.json','["桂亭依絕巘，蘭榭俯回溪。綺棟魚鱗出，雕甍鳳羽棲。", "引泉聊漲沼，鑿磴且通蹊。席上山花落，簾前野樹低。", "弋林開曙景，釣渚發晴霓。狎水驚梁雁，臨風聽楚雞。", "複看題柳葉，彌喜蔭桐圭。"]'),
('yuding-17','奉和杜員外扈從教閱','李嶠','唐','御定全唐诗','yuding','','[]','杪冬嚴殺氣，窮紀送頹光。薄狩三農隙，大閱五戎場。',120,'御定全唐詩/json/061.json','["杪冬嚴殺氣，窮紀送頹光。薄狩三農隙，大閱五戎場。", "菜田初起燒，蘭野正開防。夾岸虹旗轉，分朋獸罟張。", "燕弧帶曉月，吳劍動秋霜。原啟前禽路，山縈後騎行。", "雲區墜日羽，星苑斃天狼。禮振軍容肅，威宣武節揚。", "神心體殷祝，靈兆葉姬祥。幸陪仙駕末，欣采翰林芳。"]'),
('yuding-18','軍師凱旋自邕州順流舟中','李嶠','唐','御定全唐诗','yuding','','[]','鳴鞞入嶂口，泛舸曆川湄。尚想江陵陣，猶疑下瀨師。',96,'御定全唐詩/json/061.json','["鳴鞞入嶂口，泛舸曆川湄。尚想江陵陣，猶疑下瀨師。", "岸回帆影疾，風逆鼓聲遲。萍葉沾蘭槳，林花拂桂旗。", "弓鳴蒼隼落，劍動白猿悲。芳樹吟羌管，幽篁入楚詞。", "全軍多勝策，無戰在明時。寄謝山東妙，長纓徒自欺。"]'),
('yuding-19','夏晚九成宮呈同僚','李嶠','唐','御定全唐诗','yuding','','[]','碣館分襄野，平臺架射峰。英藩信煒燁，勝地本從容。',156,'御定全唐詩/json/061.json','["碣館分襄野，平臺架射峰。英藩信煒燁，勝地本從容。", "林引梧庭鳳，泉歸竹沼龍。小軒恒共處，長阪屬相從。", "野席蘭琴奏，山台桂酒醲。一枰移晝景，六著盡宵鐘。", "枚藻清詞律，鄒談耀辯鋒。結歡良有裕，聯寀愧無庸。", "暫悅丘中賞，還希物外蹤。風煙遠近至，魚鳥去來逢。", "月澗橫千丈，雲崖列萬重。樹紅山果熟，崖綠水苔濃。", "願以西園柳，長間北岩松。"]'),
('yuding-20','田假限疾不獲還莊載想田園兼思親友率成短韻用寫長懷贈杜幽素','李嶠','唐','御定全唐诗','yuding','','[]','游宦勞牽網，風塵久化衣。跡馳東苑路，望阻北岩扉。',180,'御定全唐詩/json/061.json','["游宦勞牽網，風塵久化衣。跡馳東苑路，望阻北岩扉。", "及此承休告，聊將狎遁肥。十旬俄委疾，三徑且殊歸。", "茂陵窅難即，靈台暫可依。疲痾旅城寺，延想屬郊畿。", "夕夢園林是，晨瞻邑裏非。綠疇良已穢，清濠曠不追。", "野花何處落，山月幾秋輝。彼美符商政，優遊絕漢機。", "高情物累遣，逸氣煙霞飛。樂道方無悶，懷賢獨有違。", "尊虛舊園酒，琴靜故人徽。夏沼蓮初發，秋田麥稍稀。", "何當攜手去，歲暮采芳菲。"]'),
('yuding-21','劉侍讀見和山邸十篇重申此贈','李嶠','唐','御定全唐诗','yuding','','[]','神嶽瑤池圃，仙宮玉樹林。乘時警天禦，清暑滌宸襟。',216,'御定全唐詩/json/061.json','["神嶽瑤池圃，仙宮玉樹林。乘時警天禦，清暑滌宸襟。", "梁駕陪玄賞，淄庭掩翠岑。對岩龍岫出，分壑雁池深。", "簷迥松蘿映，窗高石鏡臨。落泉奔澗響，驚吹助猿吟。", "野氣迷涼燠，山花雜古今。英藩盛賓侶，勝景想招尋。", "踐徑披蘭葉，攀崖引桂陰。穆生時泛醴，鄒子或調琴。", "雉翳分場合，魚鉤向浦沉。朝游極斜景，夕宴待橫參。", "顧己慚鉛鍔，叨名齒玳簪。暫依朱邸館，還暢白雲心。", "丘壑信多美，煙霞得所欽。寓言攄宿志，竊吹簡知音。", "獎價逾珍石，酬文重振金。方從仁智所，攜手濯清潯。"]'),
('yuding-22','晚秋喜雨','李嶠','唐','御定全唐诗','yuding','','[]','積陽躔首夏，隆旱屆徂秋。炎威振皇服，歊景暴神州。',240,'御定全唐詩/json/061.json','["積陽躔首夏，隆旱屆徂秋。炎威振皇服，歊景暴神州。", "氣滌朝川朗，光澄夕照浮。草木委林甸，禾黍悴原疇。", "國懼流金眚，人深懸磬憂。紫宸兢履薄，丹扆念推溝。", "望肅壇場祀，冤申囹圄囚。禦車遷玉殿，薦菲撤瓊羞。", "濟窘邦儲發，蠲窮井賦優。服閑雲驥屏，冗術土龍修。", "睿感通三極，天誠貫六幽。夏祈良未擬，商禱詎為儔。", "穴蟻禎符應，山蛇毒影收。騰雲八際滿，飛雨四溟周。", "聚靄籠仙闕，連霏繞畫樓。旱陂仍積水，涸沼更通流。", "晚穗萎還結，寒苗瘁複抽。九農歡歲阜，萬宇慶時休。", "野洽如坻詠，途喧擊壤謳。幸聞東李道，欣奉北場遊。"]'),
('yuding-23','中秋月二首','李嶠','唐','御定全唐诗','yuding','','[]','盈缺青冥外，東風萬古吹。何人種丹桂，不長出輪枝。',48,'御定全唐詩/json/061.json','["盈缺青冥外，東風萬古吹。何人種丹桂，不長出輪枝。", "圓魄上寒空，皆言四海同。安知千裏外，不有雨兼風。"]'),
('yuding-24','侍宴桃花園詠桃花應制','李嶠','唐','御定全唐诗','yuding','','[]','歲去無言忽憔悴，時來含笑吐氛氳。',32,'御定全唐詩/json/061.json','["歲去無言忽憔悴，時來含笑吐氛氳。", "不能擁路迷仙客，故欲開蹊待聖君。"]'),
('yuding-25','奉和聖制幸韋嗣立山莊應制','李嶠','唐','御定全唐诗','yuding','','[]','萬騎千官擁帝車，八龍三馬訪仙家。',32,'御定全唐詩/json/061.json','["萬騎千官擁帝車，八龍三馬訪仙家。", "鳳凰原上開青壁，鸚鵡杯中弄紫霞。"]'),
('yuding-26','游苑遇雪應制','李嶠','唐','御定全唐诗','yuding','','[]','散漫祥雲逐聖回，飄颻瑞雪繞天來。',32,'御定全唐詩/json/061.json','["散漫祥雲逐聖回，飄颻瑞雪繞天來。", "不能落後爭飛絮，故欲迎前賽早梅。"]'),
('yuding-27','送司馬先生','李嶠','唐','御定全唐诗','yuding','','[]','蓬閣桃源兩處分，人間海上不相聞。',32,'御定全唐詩/json/061.json','["蓬閣桃源兩處分，人間海上不相聞。", "一朝琴裏悲黃鶴，何日山頭望白雲。"]'),
('yuding-28','風','李嶠','唐','御定全唐诗','yuding','','[]','解落三秋葉，能開二月花。過江千尺浪，入竹萬竿斜。',24,'御定全唐詩/json/061.json','["解落三秋葉，能開二月花。過江千尺浪，入竹萬竿斜。"]'),
('yuding-29','上清暉合遇雪','李嶠','唐','御定全唐诗','yuding','','[]','千鐘聖酒禦筵披，六出祥英亂繞枝。',32,'御定全唐詩/json/061.json','["千鐘聖酒禦筵披，六出祥英亂繞枝。", "即此神仙對瓊圃，何須轍跡向瑤池。"]'),
('yuding-30','石淙','李嶠','唐','御定全唐诗','yuding','','[]','羽蓋龍旗下絕冥，蘭除薜幄坐雲扃。鳥和百籟疑調管，',40,'御定全唐詩/json/061.json','["羽蓋龍旗下絕冥，蘭除薜幄坐雲扃。鳥和百籟疑調管，", "自然碧洞窺仙境，何必丹丘是福庭。"]'),
('yuding-0','南海亂石山作','杜審言','唐','御定全唐诗','yuding','','[]','漲海積稽天，群山高嶪地。相傳稱亂石，圖典失其事。',120,'御定全唐詩/json/062.json','["漲海積稽天，群山高嶪地。相傳稱亂石，圖典失其事。", "懸危悉可驚，大小都不類。乍將雲島極，還與星河次。", "上聳忽如飛，下臨仍欲墜。朝暾赩丹紫，夜魄炯青翠。", "穹崇霧雨蓄，幽隱靈仙閟。萬尋掛鶴巢，千丈垂猿臂。", "昔去景風涉，今來姑洗至。觀此得詠歌，長時想精異。"]'),
('yuding-1','送和西蕃使','杜審言','唐','御定全唐诗','yuding','','[]','使出鳳凰池，京師陽春晚。聖朝尚邊策，詔諭兵戈偃。',72,'御定全唐詩/json/062.json','["使出鳳凰池，京師陽春晚。聖朝尚邊策，詔諭兵戈偃。", "拜手明光殿，搖心上林苑。種落逾青羌，關山度赤阪。", "疆場及無事，雅歌而餐飯。寧獨錫和戎，更當封定遠。"]'),
('yuding-2','蓬萊三殿侍宴奉敕詠終南山應制','杜審言','唐','御定全唐诗','yuding','','[]','北斗掛城邊，南山倚殿前。雲標金闕迥，樹杪玉堂懸。',48,'御定全唐詩/json/062.json','["北斗掛城邊，南山倚殿前。雲標金闕迥，樹杪玉堂懸。", "半嶺通佳氣，中峰繞瑞煙。小臣持獻壽，長此戴堯天。"]'),
('yuding-3','望春亭侍游應詔','杜審言','唐','御定全唐诗','yuding','','[]','帝出明光殿，天臨太液池。堯樽隨步輦，舜樂繞行麾。',48,'御定全唐詩/json/062.json','["帝出明光殿，天臨太液池。堯樽隨步輦，舜樂繞行麾。", "萬壽禎祥獻，三春景物滋。小臣同酌海，歌頌答無為。"]'),
('yuding-4','宿羽亭侍宴應制','杜審言','唐','御定全唐诗','yuding','','[]','步輦千門出，離宮二月開。風光新柳報，宴賞落花催。',48,'御定全唐詩/json/062.json','["步輦千門出，離宮二月開。風光新柳報，宴賞落花催。", "碧水搖空閣，青山繞吹台。聖情留晚興，歌管送餘杯。"]'),
('yuding-5','歲夜安樂公主滿月侍宴應制','杜審言','唐','御定全唐诗','yuding','','[]','戚裏生昌胤，天杯宴重臣。畫樓初滿月，香殿早迎春。',48,'御定全唐詩/json/062.json','["戚裏生昌胤，天杯宴重臣。畫樓初滿月，香殿早迎春。", "睿作堯君寶，孫謀梁國珍。明朝元會日，萬壽樂章陳。"]'),
('yuding-6','奉和七夕侍宴兩儀殿應制','杜審言','唐','御定全唐诗','yuding','','[]','一年銜別怨，七夕始言歸。斂淚開星靨，微步動雲衣。',48,'御定全唐詩/json/062.json','["一年銜別怨，七夕始言歸。斂淚開星靨，微步動雲衣。", "天回兔欲落，河曠鵲停飛。那堪盡此夜，複往弄殘機。"]'),
('yuding-7','大酺','杜審言','唐','御定全唐诗','yuding','','[]','聖後乘幹日，皇明禦曆辰。紫宮初啟坐，蒼璧正臨春。',48,'御定全唐詩/json/062.json','["聖後乘幹日，皇明禦曆辰。紫宮初啟坐，蒼璧正臨春。", "雷雨垂膏澤，金錢贈下人。詔酺歡賞遍，交泰睹惟新。"]'),
('yuding-8','賦得妾薄命','杜審言','唐','御定全唐诗','yuding','','[]','草綠長門掩，苔青永巷幽。寵移新愛奪，淚落故情留。',48,'御定全唐詩/json/062.json','["草綠長門掩，苔青永巷幽。寵移新愛奪，淚落故情留。", "啼鳥驚殘夢，飛花攪獨愁。自憐春色罷，團扇複迎秋。"]'),
('yuding-9','和韋承慶過義陽公主山池五首','杜審言','唐','御定全唐诗','yuding','','[]','野興城中發，朝英物外求。情懸朱紱望，契動赤泉遊。',240,'御定全唐詩/json/062.json','["野興城中發，朝英物外求。情懸朱紱望，契動赤泉遊。", "海燕巢書閣，山雞舞畫樓。雨餘清晚夏，共坐北岩幽。", "徑轉危峰逼，橋回缺岸妨。玉泉移酒味，石髓換粳香。", "綰霧青絲弱，牽風紫蔓長。猶言宴樂少，別向後池塘。", "攜琴繞碧沙，搖筆弄青霞。杜若幽庭草，芙蓉曲沼花。", "宴游成野客，形勝得仙家。往往留仙步，登攀日易斜。", "攢石當軒倚，懸泉度牖飛。鹿麛沖妓席，鶴子曳童衣。", "園果嘗難遍，池蓮摘未稀。捲簾唯待月，應在醉中歸。", "賞玩期他日，高深愛此時。池分八水背，峰作九山疑。", "地靜魚偏逸，人閑鳥欲欺。青溪留別興，更與白雲期。"]'),
('yuding-10','和晉陵陸丞早春遊望','杜審言','唐','御定全唐诗','yuding','','[]','獨有宦遊人，偏驚物候新。雲霞出海曙，梅柳渡江春。',48,'御定全唐詩/json/062.json','["獨有宦遊人，偏驚物候新。雲霞出海曙，梅柳渡江春。", "淑氣催黃鳥，晴光轉綠蘋。忽聞歌古調，歸思欲沾巾。"]'),
('yuding-11','秋夜宴臨津鄭明府宅','杜審言','唐','御定全唐诗','yuding','','[]','行止皆無地，招尋獨有君。酒中堪累月，身外即浮雲。',48,'御定全唐詩/json/062.json','["行止皆無地，招尋獨有君。酒中堪累月，身外即浮雲。", "露白宵鐘徹，風清曉漏聞。坐攜餘興往，還似未離群。"]'),
('yuding-12','和康五庭芝望月有懷','杜審言','唐','御定全唐诗','yuding','','[]','明月高秋迥，愁人獨夜看。暫將弓並曲，翻與扇俱團。',48,'御定全唐詩/json/062.json','["明月高秋迥，愁人獨夜看。暫將弓並曲，翻與扇俱團。", "霧濯清輝苦，風飄素影寒。羅衣一此鑒，頓使別離難。"]'),
('yuding-13','登襄陽城','杜審言','唐','御定全唐诗','yuding','','[]','旅客三秋至，層城四望開。楚山橫地出，漢水接天回。',48,'御定全唐詩/json/062.json','["旅客三秋至，層城四望開。楚山橫地出，漢水接天回。", "冠蓋非新裏，章華即舊台。習池風景異，歸路滿塵埃。"]'),
('yuding-14','旅寓安南','杜審言','唐','御定全唐诗','yuding','','[]','交趾殊風候，寒遲暖複催。仲冬山果熟，正月野花開。',48,'御定全唐詩/json/062.json','["交趾殊風候，寒遲暖複催。仲冬山果熟，正月野花開。", "積雨生昏霧，輕霜下震雷。故鄉逾萬里，客思倍從來。"]'),
('yuding-15','春日懷歸','杜審言','唐','御定全唐诗','yuding','','[]','心是傷歸望，春歸異往年。河山鑒魏闕，桑梓憶秦川。',48,'御定全唐詩/json/062.json','["心是傷歸望，春歸異往年。河山鑒魏闕，桑梓憶秦川。", "花雜芳園鳥，風和綠野煙。更懷歡賞地，車馬婁橋邊。"]'),
('yuding-16','代張侍禦傷美人','杜審言','唐','御定全唐诗','yuding','','[]','二八泉扉掩，帷屏寵愛空。淚痕宵夜燭，愁緒亂春風。',48,'御定全唐詩/json/062.json','["二八泉扉掩，帷屏寵愛空。淚痕宵夜燭，愁緒亂春風。", "巧笑人疑在，新妝曲未終。應憐脂粉氣，留著舞衣中。"]'),
('yuding-17','送高郎中北使','杜審言','唐','御定全唐诗','yuding','','[]','北狄願和親，東京發使臣。馬銜邊地雪，衣染異方塵。',48,'御定全唐詩/json/062.json','["北狄願和親，東京發使臣。馬銜邊地雪，衣染異方塵。", "歲月催行旅，恩榮變苦辛。歌鐘期重錫，拜手落花春。"]'),
('yuding-18','都尉山亭','杜審言','唐','御定全唐诗','yuding','','[]','紫藤縈葛藟，綠刺罥薔薇。下釣看魚躍，探巢畏鳥飛。',48,'御定全唐詩/json/062.json','["紫藤縈葛藟，綠刺罥薔薇。下釣看魚躍，探巢畏鳥飛。", "葉疏荷已晚，枝亞果新肥。勝跡都無限，只應伴月歸。"]'),
('yuding-19','夏日過鄭七山齋','杜審言','唐','御定全唐诗','yuding','','[]','共有樽中好，言尋穀口來。薜蘿山徑入，荷芰水亭開。',48,'御定全唐詩/json/062.json','["共有樽中好，言尋穀口來。薜蘿山徑入，荷芰水亭開。", "日氣含殘雨，雲陰送晚雷。洛陽鐘鼓至，車馬系遲回。"]'),
('yuding-20','送崔融','杜審言','唐','御定全唐诗','yuding','','[]','君王行出將，書記遠從征。祖帳連河闕，軍麾動洛城。',48,'御定全唐詩/json/062.json','["君王行出將，書記遠從征。祖帳連河闕，軍麾動洛城。", "旌旃朝朔氣，笳吹夜邊聲。坐覺煙塵掃，秋風古北平。"]'),
('yuding-21','經行嵐州','杜審言','唐','御定全唐诗','yuding','','[]','北地春光晚，邊城氣候寒。往來花不發，新舊雪仍殘。',48,'御定全唐詩/json/062.json','["北地春光晚，邊城氣候寒。往來花不發，新舊雪仍殘。", "水作琴中聽，山疑畫裏看。自驚牽遠役，艱險促征鞍。"]'),
('yuding-22','重九日宴江陰','杜審言','唐','御定全唐诗','yuding','','[]','蟋蟀期歸晚，茱萸節候新。降霜青女月，送酒白衣人。',48,'御定全唐詩/json/062.json','["蟋蟀期歸晚，茱萸節候新。降霜青女月，送酒白衣人。", "高興要長壽，卑棲隔近臣。龍沙即此地，舊俗坐為鄰。"]'),
('yuding-23','除夜有懷','杜審言','唐','御定全唐诗','yuding','','[]','故節當歌守，新年把燭迎。冬氛戀虯箭，春色候雞鳴。',48,'御定全唐詩/json/062.json','["故節當歌守，新年把燭迎。冬氛戀虯箭，春色候雞鳴。", "興盡聞壺覆，宵闌見鬥橫。還將萬億壽，更謁九重城。"]'),
('yuding-24','晦日宴游','杜審言','唐','御定全唐诗','yuding','','[]','日晦隨蓂莢，春情著杏花。解紳宜就水，張幕會連沙。',48,'御定全唐詩/json/062.json','["日晦隨蓂莢，春情著杏花。解紳宜就水，張幕會連沙。", "歌管風輕度，池台日半斜。更看金穀騎，爭向石崇家。"]'),
('yuding-25','七夕','杜審言','唐','御定全唐诗','yuding','','[]','白露含明月，青霞斷絳河。天街七襄轉，閣道二神過。',48,'御定全唐詩/json/062.json','["白露含明月，青霞斷絳河。天街七襄轉，閣道二神過。", "袨服鏘環佩，香筵拂綺羅。年年今夜盡，機杼別情多。"]'),
('yuding-26','守歲侍宴應制','杜審言','唐','御定全唐诗','yuding','','[]','季冬除夜接新年，帝子王孫捧禦筵。宮闕星河低拂樹，',40,'御定全唐詩/json/062.json','["季冬除夜接新年，帝子王孫捧禦筵。宮闕星河低拂樹，", "欲向正元歌萬壽，暫留歡賞寄春前。"]'),
('yuding-27','大酺','杜審言','唐','御定全唐诗','yuding','','[]','毗陵震澤九州通，士女歡娛萬國同。伐鼓撞鐘驚海上，',40,'御定全唐詩/json/062.json','["毗陵震澤九州通，士女歡娛萬國同。伐鼓撞鐘驚海上，", "火德雲官逢道泰，天長地久屬年豐。"]'),
('yuding-28','春日京中有懷','杜審言','唐','御定全唐诗','yuding','','[]','今年游寓獨游秦，愁思看春不當春。上林苑裏花徒發，',40,'御定全唐詩/json/062.json','["今年游寓獨游秦，愁思看春不當春。上林苑裏花徒發，", "寄語洛城風日道，明年春色倍還人。"]'),
('yuding-29','扈從出長安應制','杜審言','唐','御定全唐诗','yuding','','[]','分野都畿列，時乘六禦均。京師舊西幸，洛道此東巡。',120,'御定全唐詩/json/062.json','["分野都畿列，時乘六禦均。京師舊西幸，洛道此東巡。", "文物驅三統，聲名走百神。龍旗縈漏夕，鳳輦拂鉤陳。", "撫跡地靈古，遊情皇鑒新。山追散馬日，水憶釣魚人。", "禹食傳中使，堯樽遍下臣。省方稱國阜，問道識風淳。", "歲晚天行吉，年豐景從親。歡娛包歷代，宇宙忽疑春。"]'),
('yuding-30','春日江津游望','杜審言','唐','御定全唐诗','yuding','','[]','旅客搖邊思，春江弄晚晴。煙銷垂柳弱，霧卷落花輕。',72,'御定全唐詩/json/062.json','["旅客搖邊思，春江弄晚晴。煙銷垂柳弱，霧卷落花輕。", "飛棹乘空下，回流向日平。鳥啼移幾處，蝶舞亂相迎。", "忽歎人皆濁，堤防水至清。谷王常不讓，深可戒中盈。"]'),
('yuding-31','泛舟送鄭卿入京','杜審言','唐','御定全唐诗','yuding','','[]','帝坐蓬萊殿，恩追社稷臣。長安遙向日，宗伯正乘春。',72,'御定全唐詩/json/062.json','["帝坐蓬萊殿，恩追社稷臣。長安遙向日，宗伯正乘春。", "相宅開基地，傾都送別人。行舟縈淥水，列戟滿紅塵。", "酒助歡娛洽，風催景氣新。此時光乃命，誰為惜無津。"]'),
('yuding-32','度石門山','杜審言','唐','御定全唐诗','yuding','','[]','石門千仞斷，迸水落遙空。道束懸崖半，橋欹絕澗中。',120,'御定全唐詩/json/062.json','["石門千仞斷，迸水落遙空。道束懸崖半，橋欹絕澗中。", "仰攀人屢息，直下騎才通。泥擁奔蛇徑，雲埋伏獸叢。", "星躔牛鬥北，地脈象牙東。開塞隨行變，高深觸望同。", "江聲連驟雨，日氣抱殘虹。未改朱明律，先含白露風。", "堅貞深不憚，險澀諒難窮。有異登臨賞，徒為造化功。"]'),
('yuding-33','贈崔融二十韻','杜審言','唐','御定全唐诗','yuding','','[]','十年俱薄宦，萬里各他方。雲天斷書劄，風土異炎涼。',240,'御定全唐詩/json/062.json','["十年俱薄宦，萬里各他方。雲天斷書劄，風土異炎涼。", "太息幽蘭紫，勞歌奇樹黃。日疑懷叔度，夜似憶真長。", "北使從江表，東歸在洛陽。相逢慰疇昔，相對敘存亡。", "草深窮巷毀，竹盡故園荒。雅節君彌固，衰顏餘自傷。", "人事盈虛改，交遊寵辱妨。雀羅爭去翟，鶴氅競尋王。", "思極歡娛至，朋情詎可忘。琴樽橫宴席，岩穀臥詞場。", "連騎追佳賞，城中及路傍。三川宿雨霽，四月晚花芳。", "複此開懸榻，寧唯入後堂。興酣鴝鵒舞，言洽鳳凰翔。", "高選俄遷職，嚴程已飭裝。撫躬銜道義，攜手戀輝光。", "玉振先推美，金銘舊所防。忽嗟離別易，行役共時康。"]'),
('yuding-34','贈蘇味道','杜審言','唐','御定全唐诗','yuding','','[]','北地寒應苦，南庭戍未歸。邊聲亂羌笛，朔氣卷戎衣。',96,'御定全唐詩/json/062.json','["北地寒應苦，南庭戍未歸。邊聲亂羌笛，朔氣卷戎衣。", "雨雪關山暗，風霜草木稀。胡兵戰欲盡，虜騎獵猶肥。", "雁塞何時入，龍城幾度圍。據鞍雄劍動，插筆羽書飛。", "輿駕還京邑，朋游滿帝畿。方期來獻凱，歌舞共春輝。"]'),
('yuding-35','和李大夫嗣真奉使存撫河東','杜審言','唐','御定全唐诗','yuding','','[]','六位乾坤動，三微歷數遷。謳歌移火德，圖讖在金天。',480,'御定全唐詩/json/062.json','["六位乾坤動，三微歷數遷。謳歌移火德，圖讖在金天。", "子月開階統，房星受命年。禎符龍馬出，寶籙鳳凰傳。", "地即交風雨，都仍蔔澗瀍。明堂唯禦極，清廟乃尊先。", "不宰神功運，無為大象懸。八荒平物土，四海接人煙。", "已屬群生泰，猶言至道偏。璽書傍問俗，旌節近推賢。", "秩比司空位，官臨禦史員。雄詞執刀筆，直諫罷樓船。", "國有大臣器，朝加小會筵。將行備禮樂，送別仰神仙。", "城闕周京轉，關河陝服連。稍觀汾水曲，俄指絳台前。", "姑射聊長望，平陽遂宛然。舜耕餘草木，禹鑿舊山川。", "昔出諸侯上，無何霸業全。中軍歸戰敵，外府絕兵權。", "隱隱帝鄉遠，瞻瞻肅命虔。西河偃風俗，東壁掛星躔。", "井邑枌榆社，陵園松柏田。榮光晴掩代，佳氣曉侵燕。", "雨霈鴻私滌，風行睿旨宣。煢嫠訪疾苦，屠釣采貞堅。", "人樂逢刑措，時康洽賞延。賜逾秦氏級，恩倍漢家錢。", "擁傳咸翹首，稱觴競比肩。拜迎彌道路，舞詠溢郊鄽。", "殺氣西衡白，窮陰北暝玄。飛霜遙渡海，殘月迥臨邊。", "緬邈朝廷問，周流朔塞旋。興來探馬策，俊發抱龍泉。", "學總八千卷，文傾三百篇。澄清得使者，作頌有人焉。", "莫以崇班閡，而雲勝托捐。偉材何磊落，陋質幾翩翾。", "江海寧為讓，巴渝轉自牽。一聞歌聖道，助曲荷陶甄。"]'),
('yuding-36','贈蘇綰書記','杜審言','唐','御定全唐诗','yuding','','[]','知君書記本翩翩，為許從戎赴朔邊。',32,'御定全唐詩/json/062.json','["知君書記本翩翩，為許從戎赴朔邊。", "紅粉樓中應計日，燕支山下莫經年。"]'),
('yuding-37','渡湘江','杜審言','唐','御定全唐诗','yuding','','[]','遲日園林悲昔遊，今春花鳥作邊愁。',32,'御定全唐詩/json/062.json','["遲日園林悲昔遊，今春花鳥作邊愁。", "獨憐京國人南竄，不似湘江水北流。"]'),
('yuding-38','戲贈趙使君美人','杜審言','唐','御定全唐诗','yuding','','[]','紅粉青娥映楚雲，桃花馬上石榴裙。',32,'御定全唐詩/json/062.json','["紅粉青娥映楚雲，桃花馬上石榴裙。", "羅敷獨向東方去，謾學他家作使君。"]'),
('yuding-0','三婦豔','董思恭','唐','御定全唐诗','yuding','','[]','大婦裁紈素，中婦弄明璫。小婦多姿態，登樓紅粉妝。',36,'御定全唐詩/json/063.json','["大婦裁紈素，中婦弄明璫。小婦多姿態，登樓紅粉妝。", "丈人且安坐，初日漸流光。"]'),
('yuding-1','感懷','董思恭','唐','御定全唐诗','yuding','','[]','野郊愴新別，河橋非舊餞。慘日映峰沉，愁雲隨蓋轉。',60,'御定全唐詩/json/063.json','["野郊愴新別，河橋非舊餞。慘日映峰沉，愁雲隨蓋轉。", "哀笳時斷續，悲旌乍舒卷。望望情何極，浪浪淚空泫。", "無複昔時人，芳春共誰遣。"]'),
('yuding-2','《守歲二首','董思恭','唐','御定全唐诗','yuding','','[]','暮景斜芳殿，年華麗綺宮。寒辭去冬雪，暖帶入春風。',96,'御定全唐詩/json/063.json','["暮景斜芳殿，年華麗綺宮。寒辭去冬雪，暖帶入春風。", "階馥舒梅素，盤花卷燭紅。共歡新故歲，迎送一宵中。", "歲陰窮暮紀，獻節啟新芳。冬盡今宵促，年開明日長。", "冰銷出鏡水，梅散入風香。對此歡終宴，傾壺待曙光。"]'),
('yuding-3','昭君怨二首','董思恭','唐','御定全唐诗','yuding','','[]','新年猶尚小，那堪遠聘秦。裾衫沾馬汗，眉黛染胡塵。',96,'御定全唐詩/json/063.json','["新年猶尚小，那堪遠聘秦。裾衫沾馬汗，眉黛染胡塵。", "舉眼無相識，路逢皆異人。唯有梅將李，猶帶故鄉春。", "琵琶馬上彈，行路曲中難。漢月正南遠，燕山直北寒。", "髻鬟風拂亂，眉黛雪沾殘。斟酌紅顏改，徒勞握鏡看。"]'),
('yuding-4','詠日','董思恭','唐','御定全唐诗','yuding','','[]','滄海十枝暉，懸圃重輪慶。蕣華髮晨楹，菱彩翻朝鏡。',48,'御定全唐詩/json/063.json','["滄海十枝暉，懸圃重輪慶。蕣華髮晨楹，菱彩翻朝鏡。", "忽遇驚風飄，自有浮雲映。更也人皆仰，無待揮戈正。"]'),
('yuding-5','詠月','董思恭','唐','御定全唐诗','yuding','','[]','北堂未安寢，西園聊騁望。玉戶照羅幃，珠軒明綺障。',48,'御定全唐詩/json/063.json','["北堂未安寢，西園聊騁望。玉戶照羅幃，珠軒明綺障。", "別客長安道，思婦高樓上。所願君莫違，清風時可訪。"]'),
('yuding-6','詠星','董思恭','唐','御定全唐诗','yuding','','[]','歷歷東井舍，昭昭右掖垣。雲際龍文出，池中鳥色翻。',48,'御定全唐詩/json/063.json','["歷歷東井舍，昭昭右掖垣。雲際龍文出，池中鳥色翻。", "流輝下月路，墜影入河源。方知潁川集，別有太丘門。"]'),
('yuding-7','詠風','董思恭','唐','御定全唐诗','yuding','','[]','蕭蕭度閶闔，習習下庭闈。花蝶自飄舞，蘭蕙生光輝。',48,'御定全唐詩/json/063.json','["蕭蕭度閶闔，習習下庭闈。花蝶自飄舞，蘭蕙生光輝。", "相烏正舉翼，退鷁已驚飛。方從列子禦，更逐浮雲歸。"]'),
('yuding-8','詠雲','董思恭','唐','御定全唐诗','yuding','','[]','帝鄉白雲起，飛蓋上天衢。帶月綺羅映，從風枝葉敷。',48,'御定全唐詩/json/063.json','["帝鄉白雲起，飛蓋上天衢。帶月綺羅映，從風枝葉敷。", "參差過層閣，倏忽下蒼梧。因風望既遠，安得久踟躕。"]'),
('yuding-9','詠雪','董思恭','唐','御定全唐诗','yuding','','[]','天山飛雪度，言是落花朝。惜哉不我與，蕭索從風飄。',48,'御定全唐詩/json/063.json','["天山飛雪度，言是落花朝。惜哉不我與，蕭索從風飄。", "鮮潔淩紈素，紛糅下枝條。良時竟何在，坐見容華銷。"]'),
('yuding-10','詠露','董思恭','唐','御定全唐诗','yuding','','[]','夜色凝仙掌，晨甘下帝庭。不覺九秋至，遠向三危零。',48,'御定全唐詩/json/063.json','["夜色凝仙掌，晨甘下帝庭。不覺九秋至，遠向三危零。", "蘆渚花初白，葵園葉尚青。晞陽一灑惠，方願益滄溟。"]'),
('yuding-11','詠霧','董思恭','唐','御定全唐诗','yuding','','[]','蒼山寂已暮，翠觀黯將沉。終南晨豹隱，巫峽夜猿吟。',48,'御定全唐詩/json/063.json','["蒼山寂已暮，翠觀黯將沉。終南晨豹隱，巫峽夜猿吟。", "天寒氣不歇，景晦色方深。待訪公超市，將予赴華陰。"]'),
('yuding-12','詠虹','董思恭','唐','御定全唐诗','yuding','','[]','春暮萍生早，日落雨飛餘。橫彩分長漢，倒色媚清渠。',48,'御定全唐詩/json/063.json','["春暮萍生早，日落雨飛餘。橫彩分長漢，倒色媚清渠。", "梁前朝影出，橋上晚光舒。願逐旌旗轉，飄飄侍直廬。"]'),
('yuding-13','詠桃','董思恭','唐','御定全唐诗','yuding','','[]','禁苑春光麗，花蹊幾樹裝。綴條深淺色，點露參差光。',48,'御定全唐詩/json/063.json','["禁苑春光麗，花蹊幾樹裝。綴條深淺色，點露參差光。", "向日分千笑，迎風共一香。如何仙嶺側，獨秀隱遙芳。"]'),
('yuding-14','詠李','董思恭','唐','御定全唐诗','yuding','','[]','盤根植瀛渚，交幹橫倚天。舒華光四海，卷葉蔭山川。',24,'御定全唐詩/json/063.json','["盤根植瀛渚，交幹橫倚天。舒華光四海，卷葉蔭山川。"]'),
('yuding-15','詠弓','董思恭','唐','御定全唐诗','yuding','','[]','上弦明月半，激箭流星遠。落雁帶書驚，啼猿映枝轉。',24,'御定全唐詩/json/063.json','["上弦明月半，激箭流星遠。落雁帶書驚，啼猿映枝轉。"]'),
('yuding-16','詠琵琶','董思恭','唐','御定全唐诗','yuding','','[]','半月無雙影，金花有四時。摧藏千里態，掩抑幾重悲。',60,'御定全唐詩/json/063.json','["半月無雙影，金花有四時。摧藏千里態，掩抑幾重悲。", "促節縈紅袖，清音滿翠帷。駛彈風響急，緩曲釧聲遲。", "空餘關隴恨，因此代相思。"]'),
('yuding-17','經廬岳回望江州想洛川有作','劉允濟','唐','御定全唐诗','yuding','','[]','龜山帝始營，龍門禹初鑿。出入經變化，俯仰憑寥廓。',577,'御定全唐詩/json/063.json','["龜山帝始營，龍門禹初鑿。出入經變化，俯仰憑寥廓。", "未若茲山功，連延並巫霍。東北疏艮象，西南距坤絡。", "宏阜自郁盤，高標複回薄。勢入柴桑渚，陰開彭蠡壑。", "九江杳無際，七澤紛相錯。雲雨散吳會，風波騰鄬鄀。", "跡隨造化久，利與乾坤博。肸蚃精氣通，紛綸潛怪作。", "石渠忽見踐，金房安可托。地入天子都，岩有仙人藥。", "二門幾迢遞，三宮何倏爚。咫尺窮杳冥，跬步皆恬漠。", "仙才驚羽翰，幽居靜龍蠖。明牧振雄詞，棣華殊灼灼。", "盛葉匡西夏，深謀贊禹亳。黃雲覆鼎飛，絳氣橫川躍。", "佐曆符賢運，人期茂天爵。禮樂富垂髫，詩書成舞勺。", "清輝靖岩電，利器騰霜鍔。遊聖挹衢尊，鄰畿恭木鐸。", "岩仞包武侯，波瀾控文若。旋聞刈薪楚，遽睹升葵藿。", "稷契序揆圖，良平公輔略。重地資出守，英藩諒求瘼。", "豫章觀偉材，江州訪靈崿。陽岫曉氛氳，陰崖暮蕭索。", "潛伏屢鯨奔，雄飛更鷙搏。驚cb透煙霞，騰猿亂枝格。", "故園有歸夢，他山飛賞樂。帝鄉徒可遊，湟澗終旅泊。", "景物觀淮海，雲霄望河洛。城闕紫微星，圖書玄扈合。", "神功多粉繢，元氣猶斟酌。丞相下南宮，將軍趨北落。", "橫簪並附蟬，列鼎俱調鶴。四郊時迷路，五月先投龠。", "池榭宣瓊管，風花亂珠箔。舊游勞夢寐，新知無悅樂。", "天寒欲贈言，歲暮期交約。夜琴清玉柱，秋灰變緹幕。", "風雲動翰林，宮徵調文鑰。言泉激為浪，思緒飛成繳。", "千里輝珠璣，五采含丹雘。鐘鼓旋驚鷃，瑾瑜俄抵鵲。", "竊價慚庸怠，叨聲逾寂莫。長望限南溟，居然翳東郭。"]'),
('yuding-18','詠琴','劉允濟','唐','御定全唐诗','yuding','','[]','昔在龍門側，誰想鳳鳴時。雕琢今為器，宮商不自持。',48,'御定全唐詩/json/063.json','["昔在龍門側，誰想鳳鳴時。雕琢今為器，宮商不自持。", "巴人緩疏節，楚客弄繁絲。欲作高張引，翻成下調悲。"]'),
('yuding-19','怨情','劉允濟','唐','御定全唐诗','yuding','','[]','玉關芳信斷，蘭閨錦字新。愁來好自抑，念切已含嚬。',48,'御定全唐詩/json/063.json','["玉關芳信斷，蘭閨錦字新。愁來好自抑，念切已含嚬。", "虛牖風驚夢，空床月厭人。歸期倘可促，勿度柳園春。"]'),
('yuding-20','《見道邊死人','劉允濟','唐','御定全唐诗','yuding','','[]','淒涼徒見日，冥寞詎知年。魂兮不可問，應為直如弦。',24,'御定全唐詩/json/063.json','["淒涼徒見日，冥寞詎知年。魂兮不可問，應為直如弦。"]'),
('yuding-21','九日登玄武山旅眺','邵大震','唐','御定全唐诗','yuding','','[]','九月九日望遙空，秋水秋天生夕風。',32,'御定全唐詩/json/063.json','["九月九日望遙空，秋水秋天生夕風。", "寒雁一向南去遠，遊人幾度菊花叢。"]'),
('yuding-22','軍中行路難','辛常伯','唐','御定全唐诗','yuding','','[]','君不見封狐雄虺自成群，憑深負固結妖氛。',313,'御定全唐詩/json/063.json','["君不見封狐雄虺自成群，憑深負固結妖氛。", "玉璽分兵征惡少，金壇授律動將軍。將軍擁麾宣廟略，", "閣道岧嶢起戍樓，劍門遙裔俯靈丘。邛關九折無平路，", "杳杳丘陵出，蒼蒼林薄遠。途危紫蓋峰，路澀青泥阪。", "去去指哀牢，行行入不毛。絕壁千里險，連山四望高。", "中外分區宇，夷夏殊風土。交址枕南荒，昆彌臨北戶。", "川原饒毒霧，溪穀多霪雨。行潦四時流，崩查千歲古。", "漂梗飛蓬不暫安，捫蘿引葛陟危巒。昔時聞道從軍樂，", "南中南斗映星河，秦關秦塞阻煙波。三春邊地風光少，", "向月彎繁弱，連星轉太阿。重義輕生懷一顧，", "灞城隅，滇池水，天涯望轉積，地際行無已。", "徒覺炎涼節物非，不知關山千萬里。棄置勿重陳，", "絳節紅旗分日羽，丹心白刃酬明主。但令一被君王知，", "無複歸雲憑短翰，空餘望日想長安。"]'),
('yuding-0','奉和聖制夏日游石淙山','姚崇','唐','御定全唐诗','yuding','','[]','二室三塗光地險，均霜揆日處天中。石泉石鏡恒留月，',40,'御定全唐詩/json/064.json','["二室三塗光地險，均霜揆日處天中。石泉石鏡恒留月，", "別有祥煙伴佳氣，能隨輕輦共蔥蔥。"]'),
('yuding-1','故洛陽城侍宴應制','姚崇','唐','御定全唐诗','yuding','','[]','遊豫停仙蹕，登臨對晚晴。川鳧連倒影，岩鳥應虛聲。',48,'御定全唐詩/json/064.json','["遊豫停仙蹕，登臨對晚晴。川鳧連倒影，岩鳥應虛聲。", "野奏風成曲，山居雲作纓。今朝丘壑上，高興小蓬瀛。"]'),
('yuding-2','春日洛陽城侍宴','姚崇','唐','御定全唐诗','yuding','','[]','南山開寶曆，北渚對芳蹊。的曆風梅度，參差露草低。',48,'御定全唐詩/json/064.json','["南山開寶曆，北渚對芳蹊。的曆風梅度，參差露草低。", "堯樽臨上席，舜樂下前溪。任重由來醉，乘酣志轉迷。"]'),
('yuding-3','秋夜望月','姚崇','唐','御定全唐诗','yuding','','[]','明月有餘鑒，羈人殊未安。桂含秋樹晚，波入夜池寒。',48,'御定全唐詩/json/064.json','["明月有餘鑒，羈人殊未安。桂含秋樹晚，波入夜池寒。", "灼灼雲枝淨，光光草露團。所思迷所在，長望獨長歎。"]'),
('yuding-4','夜渡江','姚崇','唐','御定全唐诗','yuding','','[]','夜渚帶浮煙，蒼茫晦遠天。舟輕不覺動，纜急始知牽。',48,'御定全唐詩/json/064.json','["夜渚帶浮煙，蒼茫晦遠天。舟輕不覺動，纜急始知牽。", "聽草遙尋岸，聞香暗識蓮。唯看孤帆影，常似客心懸。"]'),
('yuding-5','奉和聖制龍池篇','姚崇','唐','御定全唐诗','yuding','','[]','恭聞帝裏生靈沼，應報明君鼎業新。既協翠泉光寶命，',40,'御定全唐詩/json/064.json','["恭聞帝裏生靈沼，應報明君鼎業新。既協翠泉光寶命，", "獨有前池一小雁，叨承舊惠入天津。"]'),
('yuding-6','句','姚崇','唐','御定全唐诗','yuding','','[]','扇掩將雛曲，釵承墮馬鬟。（見《海錄碎事》，',21,'御定全唐詩/json/064.json','["扇掩將雛曲，釵承墮馬鬟。（見《海錄碎事》，"]'),
('yuding-7','奉和禦制璟與張說源幹曜同日上官命宴都堂賜詩應制','宋璟','唐','御定全唐诗','yuding','','[]','丞相邦之重，非賢諒不居。老臣慵且憊，何德以當諸。',96,'御定全唐詩/json/064.json','["丞相邦之重，非賢諒不居。老臣慵且憊，何德以當諸。", "厚秩先為忝，崇班複此除。太常陳禮樂，中掖降簪裾。", "聖酒山河潤，仙文象緯舒。冒恩懷寵錫，陳力省空虛。", "郭隗慚無駿，馮諼愧有魚。不知周勃者，榮幸定何如。"]'),
('yuding-8','奉和聖制同二相已下群官樂遊園宴','宋璟','唐','御定全唐诗','yuding','','[]','侍飲終酺會，承恩續勝遊。戴天惟慶倖，選地即殊尤。',72,'御定全唐詩/json/064.json','["侍飲終酺會，承恩續勝遊。戴天惟慶倖，選地即殊尤。", "北向祗雙闕，南臨賞一丘。曲江新溜暖，上苑雜花稠。", "亹亹韶弦屢，戔戔賁帛周。醉歸填畛陌，榮耀接軒裘。"]'),
('yuding-9','奉和聖制送張說巡邊','宋璟','唐','御定全唐诗','yuding','','[]','帝道薄存兵，王師尚有征。是關司馬法，爰命總戎行。',120,'御定全唐詩/json/064.json','["帝道薄存兵，王師尚有征。是關司馬法，爰命總戎行。", "畫閫崇威信，分麾盛寵榮。聚觀方結轍，出祖遂傾城。", "聖酒江河潤，天詞象緯明。德風邊草偃，勝氣朔雲平。", "宰國推良器，為軍挹壯聲。至和常得體，不戰即亡精。", "以智泉寧竭，其徐海自清。遲還廟堂坐，贈別故人情。"]'),
('yuding-10','奉和聖制答張說扈從南出雀鼠谷','宋璟','唐','御定全唐诗','yuding','','[]','秦地雄西夏，並州近北胡。禹行山啟路，舜在邑為都。',72,'御定全唐詩/json/064.json','["秦地雄西夏，並州近北胡。禹行山啟路，舜在邑為都。", "忽視寒暄隔，深思險易殊。四時宗伯敘，六義宰臣鋪。", "征作宮常應，星環日每紆。盛哉逢道合，良以致亨衢。"]'),
('yuding-11','蒲津迎駕','宋璟','唐','御定全唐诗','yuding','','[]','回鑾下蒲阪，飛旆指秦京。洛上黃雲送，關中紫氣迎。',72,'御定全唐詩/json/064.json','["回鑾下蒲阪，飛旆指秦京。洛上黃雲送，關中紫氣迎。", "霞朝看馬色，月曉聽雞鳴。防拒連山險，長橋壓水準。", "省方知化洽，察俗覺時清。天下長無事，空餘襟帶名。"]'),
('yuding-12','送蘇尚書赴益州','宋璟','唐','御定全唐诗','yuding','','[]','我望風煙接，君行霰雪飛。園亭若有送，楊柳最依依。',24,'御定全唐詩/json/064.json','["我望風煙接，君行霰雪飛。園亭若有送，楊柳最依依。"]'),
('yuding-0','初春行宮侍宴應制','蘇味道','唐','御定全唐诗','yuding','','[]','溫液吐涓涓，跳波急應弦。簪裾承睿賞，花柳發韶年。',48,'御定全唐詩/json/065.json','["溫液吐涓涓，跳波急應弦。簪裾承睿賞，花柳發韶年。", "聖酒千鐘洽，宸章七曜懸。微臣從此醉，還似夢鈞天。"]'),
('yuding-1','單于川對雨二首','蘇味道','唐','御定全唐诗','yuding','','[]','崇朝遘行雨，薄晚屯密雲。緣階起素沫，竟水聚圓文。',96,'御定全唐詩/json/065.json','["崇朝遘行雨，薄晚屯密雲。緣階起素沫，竟水聚圓文。", "河柳低未舉，山花落已芬。清尊久不薦，淹留遂待君。", "飛雨欲迎旬，浮雲已送春。還從濯枝後，來應洗兵辰。", "氣合龍祠外，聲過鯨海濱。伐邢知有屬，已見靜邊塵。"]'),
('yuding-2','正月十五夜','蘇味道','唐','御定全唐诗','yuding','','[]','火樹銀花合，星橋鐵鎖開。暗塵隨馬去，明月逐人來。',48,'御定全唐詩/json/065.json','["火樹銀花合，星橋鐵鎖開。暗塵隨馬去，明月逐人來。", "游伎皆穠李，行歌盡落梅。金吾不禁夜，玉漏莫相催。"]'),
('yuding-3','詠霧','蘇味道','唐','御定全唐诗','yuding','','[]','氤氳起洞壑，遙裔匝平疇。乍似含龍劍，還疑映蜃樓。',48,'御定全唐詩/json/065.json','["氤氳起洞壑，遙裔匝平疇。乍似含龍劍，還疑映蜃樓。", "拂林隨雨密，度徑帶煙浮。方謝公超步，終從彥輔遊。"]'),
('yuding-4','詠虹','蘇味道','唐','御定全唐诗','yuding','','[]','紆餘帶星渚，窈窕架天潯。空因壯士見，還共美人沉。',48,'御定全唐詩/json/065.json','["紆餘帶星渚，窈窕架天潯。空因壯士見，還共美人沉。", "逸照含良玉，神花藻瑞金。獨留長劍彩，終負昔賢心。"]'),
('yuding-5','詠霜','蘇味道','唐','御定全唐诗','yuding','','[]','金祇暮律盡，玉女暝氛歸。孕冷隨鐘徹，飄華逐劍飛。',48,'御定全唐詩/json/065.json','["金祇暮律盡，玉女暝氛歸。孕冷隨鐘徹，飄華逐劍飛。", "帶日浮寒影，乘風進晚威。自有貞筠質，寧將庶草腓。"]'),
('yuding-6','詠井','蘇味道','唐','御定全唐诗','yuding','','[]','玲瓏映玉檻，澄澈瀉銀床。流聲集孔雀，帶影出羵羊。',48,'御定全唐詩/json/065.json','["玲瓏映玉檻，澄澈瀉銀床。流聲集孔雀，帶影出羵羊。", "桐落秋蛙散，桃舒春錦芳。帝力終何有，機心庶此忘。"]'),
('yuding-7','詠石','蘇味道','唐','御定全唐诗','yuding','','[]','濟北甄神貺，河西濯錦文。聲應天池雨，影觸岱宗雲。',48,'御定全唐詩/json/065.json','["濟北甄神貺，河西濯錦文。聲應天池雨，影觸岱宗雲。", "燕歸猶可候，羊起自成群。何當握靈髓，高枕絕囂氛。"]'),
('yuding-8','奉和受圖溫洛應制','蘇味道','唐','御定全唐诗','yuding','','[]','綠綺膺河檢，清壇俯洛濱。天旋俄制蹕，孝享屬嚴禋。',60,'御定全唐詩/json/065.json','["綠綺膺河檢，清壇俯洛濱。天旋俄制蹕，孝享屬嚴禋。", "陟配光三祖，懷柔洎百神。霧開中道日，雪斂屬車塵。", "預奉咸英奏，長歌億萬春。"]'),
('yuding-9','使嶺南聞崔馬二禦史並拜台郎','蘇味道','唐','御定全唐诗','yuding','','[]','振鷺齊飛日，遷鶯遠聽聞。明光共待漏，清鑒各披雲。',72,'御定全唐詩/json/065.json','["振鷺齊飛日，遷鶯遠聽聞。明光共待漏，清鑒各披雲。", "喜得廊廟舉，嗟為台閣分。故林懷柏悅，新幄阻蘭熏。", "冠去神羊影，車迎瑞雉群。遠從南斗外，遙仰列星文。"]'),
('yuding-10','贈封禦史入台','蘇味道','唐','御定全唐诗','yuding','','[]','故事推三獨，茲辰對兩闈。夕鴉共鳴舞，屈草接芳菲。',72,'御定全唐詩/json/065.json','["故事推三獨，茲辰對兩闈。夕鴉共鳴舞，屈草接芳菲。", "盛府持清橐，殊章動繡衣。風連台閣起，霜就簡書飛。", "凜凜當朝色，行行滿路威。惟當擊隼去，複睹落雕歸。"]'),
('yuding-11','始背洛城秋郊矚目奉懷台中諸侍禦','蘇味道','唐','御定全唐诗','yuding','','[]','薄遊忝霜署，直指戒冰心。荔浦方南紀，蘅皋暫北臨。',96,'御定全唐詩/json/065.json','["薄遊忝霜署，直指戒冰心。荔浦方南紀，蘅皋暫北臨。", "山晴關塞斷，川暮廣城陰。場圃通圭甸，溝塍礙石林。", "野童來捃拾，田叟去謳吟。蟋蟀秋風起，蒹葭晚露深。", "帝城猶鬱鬱，征傳幾駸駸。回憶披書地，勞歌謝所欽。"]'),
('yuding-12','九江口南濟北接蘄春南與潯陽岸','蘇味道','唐','御定全唐诗','yuding','','[]','江路一悠哉，滔滔九派來。遠潭昏似霧，前浦沸成雷。',96,'御定全唐詩/json/065.json','["江路一悠哉，滔滔九派來。遠潭昏似霧，前浦沸成雷。", "鱗介多潛育，漁商幾溯洄。風搖蜀柿下，日照楚萍開。", "近漱湓城曲，斜吹蠡澤隈。錫龜猶入貢，浮獸罷為災。", "津吏揮橈疾，郵童整傳催。歸心詎可問，為視落潮回。"]'),
('yuding-13','和武三思於天中寺尋複禮上人之作','蘇味道','唐','御定全唐诗','yuding','','[]','藩戚三雍暇，禪居二室隈。忽聞從桂苑，移步踐花台。',120,'御定全唐詩/json/065.json','["藩戚三雍暇，禪居二室隈。忽聞從桂苑，移步踐花台。", "敏學推多藝，高談屬辯才。是非寧滯著，空有掠嫌猜。", "五行幽機暢，三蕃妙鍵開。味同甘露灑，香似逆風來。", "砌古留方石，池清辨燒灰。人尋鶴洲返，月逐虎溪回。", "企躅瞻飛蓋，攀遊想渡杯。願陪為善樂，從此去塵埃。"]'),
('yuding-14','嵩山石淙侍宴應制','蘇味道','唐','御定全唐诗','yuding','','[]','雕輿藻衛擁千官，仙洞靈溪訪九丹。隱曖源花迷近路，',40,'御定全唐詩/json/065.json','["雕輿藻衛擁千官，仙洞靈溪訪九丹。隱曖源花迷近路，", "天洛宸襟有餘興，裴回周矖駐歸鑾。"]'),
('yuding-0','古劍篇','郭震','唐','御定全唐诗','yuding','','[]','君不見昆吾鐵冶飛炎煙，紅光紫氣俱赫然。',91,'御定全唐詩/json/066.json','["君不見昆吾鐵冶飛炎煙，紅光紫氣俱赫然。", "良工鍛煉凡幾年，鑄得寶劍名龍泉。龍泉顏色如霜雪，", "正逢天下無風塵，幸得周防君子身。精光黯黯青蛇色，", "何言中路遭棄捐，零落漂淪古獄邊。雖複塵埋無所用，"]'),
('yuding-1','塞上','郭震','唐','御定全唐诗','yuding','','[]','塞外虜塵飛，頻年出武威。死生隨玉劍，辛苦向金微。',48,'御定全唐詩/json/066.json','["塞外虜塵飛，頻年出武威。死生隨玉劍，辛苦向金微。", "久戍人將老，長征馬不肥。仍聞酒泉郡，已合數重圍。"]'),
('yuding-2','寄劉校書','郭震','唐','御定全唐诗','yuding','','[]','俗吏三年何足論，每將榮辱在朝昏。才微易向風塵老，',40,'御定全唐詩/json/066.json','["俗吏三年何足論，每將榮辱在朝昏。才微易向風塵老，", "回首漢家丞相府，昨來誰得掃重門。"]'),
('yuding-3','同徐員外除太子舍人寓直之作','郭震','唐','御定全唐诗','yuding','','[]','太子擅元良，宮臣命偉長。除榮辭會府，直宿總書坊。',72,'御定全唐詩/json/066.json','["太子擅元良，宮臣命偉長。除榮辭會府，直宿總書坊。", "露濕幽岩桂，風吹便坐桑。閣連雲一色，池帶月重光。", "葉死蘭無氣，荷枯水不香。遙聞秋興作，言是晉中郎。"]'),
('yuding-4','春江曲','郭震','唐','御定全唐诗','yuding','','[]','江水春沉沉，上有雙竹林。竹葉壞水色，郎亦壞人心。',24,'御定全唐詩/json/066.json','["江水春沉沉，上有雙竹林。竹葉壞水色，郎亦壞人心。"]'),
('yuding-5','王昭君三首','郭震','唐','御定全唐诗','yuding','','[]','自嫁單于國，長銜漢掖悲。容顏日憔悴，有甚畫圖時。',72,'御定全唐詩/json/066.json','["自嫁單于國，長銜漢掖悲。容顏日憔悴，有甚畫圖時。", "厭踐冰霜域，嗟為邊塞人。思從漠南獵，一見漢家塵。", "聞有南河信，傳言殺畫師。始知君念重，更肯惜蛾眉。"]'),
('yuding-6','子夜四時歌六首：春歌','郭震','唐','御定全唐诗','yuding','','[]','陌頭楊柳枝，已被春風吹。妾心正斷絕，君懷那得知。',48,'御定全唐詩/json/066.json','["陌頭楊柳枝，已被春風吹。妾心正斷絕，君懷那得知。", "青樓含日光，綠池起風色。贈子同心花，殷勤此何極。"]'),
('yuding-7','子夜四時歌六首：秋歌','郭震','唐','御定全唐诗','yuding','','[]','邀歡空佇立，望美頻回顧。何時複采菱，江中密相遇。',48,'御定全唐詩/json/066.json','["邀歡空佇立，望美頻回顧。何時複采菱，江中密相遇。", "辟惡茱萸囊，延年菊花酒。與子結綢繆，丹心此何有。"]'),
('yuding-8','子夜四時歌六首：冬歌','郭震','唐','御定全唐诗','yuding','','[]','北極嚴氣升，南至溫風謝。調絲競短歌，拂枕憐長夜。',48,'御定全唐詩/json/066.json','["北極嚴氣升，南至溫風謝。調絲競短歌，拂枕憐長夜。", "帷橫雙翡翠，被卷兩鴛鴦。婉態不自得，宛轉君王床。"]'),
('yuding-9','二月樂游詩','郭震','唐','御定全唐诗','yuding','','[]','二月芳遊始，開軒望曉池。綠蘭日吐葉，紅蕊向盈枝。',48,'御定全唐詩/json/066.json','["二月芳遊始，開軒望曉池。綠蘭日吐葉，紅蕊向盈枝。", "柳色行將改，君心幸莫移。陽春遽多意，唯願兩人知。"]'),
('yuding-10','十月樂游詩','郭震','唐','御定全唐诗','yuding','','[]','十月嚴陰盛，霜氣下玉台。羅衣羞自解，綺帳待君開。',48,'御定全唐詩/json/066.json','["十月嚴陰盛，霜氣下玉台。羅衣羞自解，綺帳待君開。", "銀箭更籌緩，金爐香氣來。愁仍夜未幾，已使炭成灰。"]'),
('yuding-11','螢','郭震','唐','御定全唐诗','yuding','','[]','秋風凜凜月依依，飛過高梧影裏時。',32,'御定全唐詩/json/066.json','["秋風凜凜月依依，飛過高梧影裏時。", "暗處若教同眾類，世間爭得有人知。"]'),
('yuding-12','蛩','郭震','唐','御定全唐诗','yuding','','[]','愁殺離家未達人，一聲聲到枕前聞。',32,'御定全唐詩/json/066.json','["愁殺離家未達人，一聲聲到枕前聞。", "苦吟莫向朱門裏，滿耳笙歌不聽君。"]'),
('yuding-13','雲','郭震','唐','御定全唐诗','yuding','','[]','聚散虛空去複還，野人閑處倚筇看。',32,'御定全唐詩/json/066.json','["聚散虛空去複還，野人閑處倚筇看。", "不知身是無根物，蔽月遮星作萬端。"]'),
('yuding-14','野井','郭震','唐','御定全唐诗','yuding','','[]','縱無汲引味清澄，冷浸寒空月一輪。',32,'御定全唐詩/json/066.json','["縱無汲引味清澄，冷浸寒空月一輪。", "鑿處若教當要路，為君常濟往來人。"]'),
('yuding-15','米囊花','郭震','唐','御定全唐诗','yuding','','[]','開花空道勝於草，結實何曾濟得民。',32,'御定全唐詩/json/066.json','["開花空道勝於草，結實何曾濟得民。", "卻笑野田禾與黍，不聞弦管過青春。"]'),
('yuding-16','惜花','郭震','唐','御定全唐诗','yuding','','[]','豔拂衣襟蕊拂杯，繞枝閑共蝶徘徊。',32,'御定全唐詩/json/066.json','["豔拂衣襟蕊拂杯，繞枝閑共蝶徘徊。", "春風滿目還惆悵，半欲離披半未開。"]'),
('yuding-17','蓮花','郭震','唐','御定全唐诗','yuding','','[]','臉膩香熏似有情，世間何物比輕盈。',32,'御定全唐詩/json/066.json','["臉膩香熏似有情，世間何物比輕盈。", "湘妃雨後來池看，碧玉盤中弄水晶。"]'),
('yuding-0','弘農清岩曲有磐石可坐，宋十一每拂拭待餘，寄詩贈之','田遊岩','唐','御定全唐诗','yuding','','[]','信彼稱靈石，居然狎遁棲。裴回承翠巘，斌駁帶深溪。',72,'御定全唐詩/json/067.json','["信彼稱靈石，居然狎遁棲。裴回承翠巘，斌駁帶深溪。", "夕陰起層岫，清景半虹霓。風來應嘯阮，波動可琴嵇。", "僕也潁陽客，望彼空思齊。儻見山人至，簪蒿且杖藜。"]'),
('yuding-1','和宋之問下山歌','王無競','唐','御定全唐诗','yuding','','[]','日雲暮兮下嵩山，路連綿兮樹石間。',32,'御定全唐詩/json/067.json','["日雲暮兮下嵩山，路連綿兮樹石間。", "出谷口兮見明月，心裴回兮不能還。"]'),
('yuding-2','北使長城','王無競','唐','御定全唐诗','yuding','','[]','秦世築長城，長城無極已。暴兵四十萬，興工九千里。',108,'御定全唐詩/json/067.json','["秦世築長城，長城無極已。暴兵四十萬，興工九千里。", "死人如亂麻，白骨相撐委。殫弊未雲悟，窮毒豈知止。", "胡塵未北滅，楚兵遽東起。六國複囂囂，兩龍鬥觺觺。", "卯金竟握讖，反璧俄淪祀。仁義寢邦國，狙暴行終始。", "一旦咸陽宮，翻為漢朝市。"]'),
('yuding-3','鳳台曲','王無競','唐','御定全唐诗','yuding','','[]','鳳台何逶迤，嬴女管參差。一旦彩雲至，身去無還期。',48,'御定全唐詩/json/067.json','["鳳台何逶迤，嬴女管參差。一旦彩雲至，身去無還期。", "遺曲此臺上，世人多學吹。一吹一落淚，至今憐玉姿。"]'),
('yuding-4','銅雀台','王無競','唐','御定全唐诗','yuding','','[]','北登銅雀上，西望青松郭。繐帳空蒼蒼，陵田紛漠漠。',72,'御定全唐詩/json/067.json','["北登銅雀上，西望青松郭。繐帳空蒼蒼，陵田紛漠漠。", "平生事已變，歌吹宛猶昨。長袖拂玉塵，遺情結羅幕。", "妾怨在朝露，君恩豈中薄。高臺奏曲終，曲終淚橫落。"]'),
('yuding-5','巫山','王無競','唐','御定全唐诗','yuding','','[]','神女向高唐，巫山下夕陽。裴回行作雨，婉孌逐荊王。',48,'御定全唐詩/json/067.json','["神女向高唐，巫山下夕陽。裴回行作雨，婉孌逐荊王。", "電影江前落，雷聲峽外長。朝雲無處所，台館曉蒼蒼。"]'),
('yuding-6','和宋之問下山歌','賈曾','唐','御定全唐诗','yuding','','[]','良遊晼晚兮月呈光，錦路逶迤兮山路長。',36,'御定全唐詩/json/067.json','["良遊晼晚兮月呈光，錦路逶迤兮山路長。", "王孫不留兮歲將晏，嵩岩仙草兮為誰芳。"]'),
('yuding-7','孝和皇帝挽歌','賈曾','唐','御定全唐诗','yuding','','[]','新命千齡啟，鴻圖累聖餘。天行應潛躍，帝出受圖書。',48,'御定全唐詩/json/067.json','["新命千齡啟，鴻圖累聖餘。天行應潛躍，帝出受圖書。", "禮若傳堯舊，功疑複夏初。夢游長不返，何國是華胥。"]'),
('yuding-8','奉和春日出苑矚目應令','賈曾','唐','御定全唐诗','yuding','','[]','銅龍曉辟問安回，金輅春遊博望開。渭北晴光搖草樹，',40,'御定全唐詩/json/067.json','["銅龍曉辟問安回，金輅春遊博望開。渭北晴光搖草樹，", "臣在東周獨留滯，忻逢睿藻日邊來。"]'),
('yuding-9','有所思','賈曾','唐','御定全唐诗','yuding','','[]','洛陽城東桃李花，飛來飛去落誰家。幽閨女兒愛顏色，',48,'御定全唐詩/json/067.json','["洛陽城東桃李花，飛來飛去落誰家。幽閨女兒愛顏色，", "故人不共洛陽東，今來空對落花風。年年歲歲花相似，"]'),
('yuding-10','祭汾陰樂章','賈曾','唐','御定全唐诗','yuding','','[]','蠲我漸饎，潔我膋薌。有豆孔碩，為羞既臧。',40,'御定全唐詩/json/067.json','["蠲我漸饎，潔我膋薌。有豆孔碩，為羞既臧。", "至誠無昧，精意惟芳。神其醉止，欣欣樂康。"]'),
('yuding-11','使至汴州喜逢宋之問','李夔','唐','御定全唐诗','yuding','','[]','阮籍蓬池上，孤韻竹林才。巨源從吏道，正擁使車來。',48,'御定全唐詩/json/067.json','["阮籍蓬池上，孤韻竹林才。巨源從吏道，正擁使車來。", "相逢且交臂，相命且銜杯。醉後長歌畢，餘聲繞吹台。"]'),
('yuding-12','祭汾陰樂章','崔玄童','唐','御定全唐诗','yuding','','[]','聿修嚴配，展事禋宗。祥符寶鼎，禮備黃琮。',40,'御定全唐詩/json/067.json','["聿修嚴配，展事禋宗。祥符寶鼎，禮備黃琮。", "祝詞以信，明德惟聰。介茲景福，永永無窮。"]'),
('yuding-13','祭汾陰樂章','何鸞','唐','御定全唐诗','yuding','','[]','樂奏雲闋，禮章載虔。禋宗於地，昭假於天。',40,'御定全唐詩/json/067.json','["樂奏雲闋，禮章載虔。禋宗於地，昭假於天。", "惟馨薦矣，既醉歆焉。神之降福，永永萬年。"]'),
('yuding-14','祭汾陰樂章','蔣挺','唐','御定全唐诗','yuding','','[]','維歲之吉，維辰之良。聖君紱冕，肅事壇場。',40,'御定全唐詩/json/067.json','["維歲之吉，維辰之良。聖君紱冕，肅事壇場。", "大禮已備，大樂斯張。神其醉止，降福無疆。"]'),
('yuding-0','關山月','崔融1','唐','御定全唐诗','yuding','','[]','月生西海上，氣逐邊風壯。萬里度關山，蒼茫非一狀。',48,'御定全唐詩/json/068.json','["月生西海上，氣逐邊風壯。萬里度關山，蒼茫非一狀。", "漢兵開郡國，胡馬窺亭障。夜夜聞悲笳，征人起南望。"]'),
('yuding-1','擬古','崔融1','唐','御定全唐诗','yuding','','[]','飲馬臨濁河，濁河深不測。河水日東注，河源乃西極。',120,'御定全唐詩/json/068.json','["飲馬臨濁河，濁河深不測。河水日東注，河源乃西極。", "思君正如此，誰為生羽翼。日夕大川陰，雲霞千里色。", "所思在何處，宛在機中織。離夢當有魂，愁容定無力。", "夙齡負奇志，中夜三歎息。拔劍斬長榆，彎弓射小棘。", "班張固非擬，衛霍行可即。寄謝閨中人，努力加飧食。"]'),
('yuding-2','西征軍行遇風','崔融1','唐','御定全唐诗','yuding','','[]','北風卷塵沙，左右不相識。颯颯吹萬里，昏昏同一色。',120,'御定全唐詩/json/068.json','["北風卷塵沙，左右不相識。颯颯吹萬里，昏昏同一色。", "馬煩莫敢進，人急未遑食。草木春更悲，天景晝相匿。", "夙齡慕忠義，雅尚存孤直。覽史懷浸驕，讀詩歎孔棘。", "及茲戎旅地，忝從書記職。兵氣騰北荒，軍聲振西極。", "坐覺威靈遠，行看氛祲息。愚臣何以報，倚馬申微力。"]'),
('yuding-3','塞垣行','崔融1','唐','御定全唐诗','yuding','','[]','疾風卷溟海，萬里揚沙礫。仰望不見天，昏昏竟朝夕。',132,'御定全唐詩/json/068.json','["疾風卷溟海，萬里揚沙礫。仰望不見天，昏昏竟朝夕。", "是時軍兩進，東拒複西敵。蔽山張旗鼓，間道潛鋒鏑。", "精騎突曉圍，奇兵襲暗壁。十月邊塞寒，四山冱陰積。", "雨雪雁南飛，風塵景西迫。昔我事討論，未嘗怠經籍。", "一朝棄筆硯，十年操矛戟。豈要黃河誓，須勒燕山石。", "可嗟牧羊臣，海外久為客。"]'),
('yuding-4','登東陽沈隱侯八詠樓','崔融1','唐','御定全唐诗','yuding','','[]','旦登西北樓，樓峻石墉厚。宛生長定□，俯壓三江口。',120,'御定全唐詩/json/068.json','["旦登西北樓，樓峻石墉厚。宛生長定□，俯壓三江口。", "排階銜鳥衡，交疏過牛鬥。左右會稽鎮，出入具區藪。", "越岩森其前，浙江漫其後。此地實東陽，由來山水鄉。", "隱侯有遺詠，落簡尚餘芳。具物昔未改，斯人今已亡。", "粵余忝藩左，束發事文場。悵不見夫子，神期遙相望。"]'),
('yuding-5','從軍行','崔融1','唐','御定全唐诗','yuding','','[]','穹廬雜種亂金方，武將神兵下玉堂。天子旌旗過細柳，',64,'御定全唐詩/json/068.json','["穹廬雜種亂金方，武將神兵下玉堂。天子旌旗過細柳，", "漠漠邊塵飛眾鳥，昏昏朔氣聚群羊。依稀蜀杖迷新竹，", "坐看戰壁為平土，近待軍營作破羌。"]'),
('yuding-6','和宋之問寒食題黃梅臨江驛','崔融1','唐','御定全唐诗','yuding','','[]','春分自淮北，寒食渡江南。忽見潯陽水，疑是宋家潭。',48,'御定全唐詩/json/068.json','["春分自淮北，寒食渡江南。忽見潯陽水，疑是宋家潭。", "明主閽難叫，孤臣逐未堪。遙思故園陌，桃李正酣酣。"]'),
('yuding-7','留別杜審言並呈洛中舊游','崔融1','唐','御定全唐诗','yuding','','[]','斑鬢今為別，紅顏昨共遊。年年春不待，處處酒相留。',48,'御定全唐詩/json/068.json','["斑鬢今為別，紅顏昨共遊。年年春不待，處處酒相留。", "駐馬西橋上，回車南陌頭。故人從此隔，風月坐悠悠。"]'),
('yuding-8','詠寶劍','崔融1','唐','御定全唐诗','yuding','','[]','寶劍出昆吾，龜龍夾采珠。五精初獻術，千戶競淪都。',48,'御定全唐詩/json/068.json','["寶劍出昆吾，龜龍夾采珠。五精初獻術，千戶競淪都。", "匣氣沖牛斗，山形轉轆轤。欲知天下貴，持此問風胡。"]'),
('yuding-9','吳中好風景','崔融1','唐','御定全唐诗','yuding','','[]','洛渚問吳潮，吳門想洛橋。夕煙楊柳岸，春水木蘭橈。',48,'御定全唐詩/json/068.json','["洛渚問吳潮，吳門想洛橋。夕煙楊柳岸，春水木蘭橈。", "城邑高樓近，星辰北斗遙。無因生羽翼，輕舉托還飆。"]'),
('yuding-10','則天皇後挽歌二首','崔融1','唐','御定全唐诗','yuding','','[]','宵陳虛禁夜，夕臨空山陰。日月昏尺景，天地慘何心。',96,'御定全唐詩/json/068.json','["宵陳虛禁夜，夕臨空山陰。日月昏尺景，天地慘何心。", "紫殿金鋪澀，黃陵玉座深。鏡奩長不啟，聖主淚沾巾。", "前殿臨朝罷，長陵合葬歸。山川不可望，文物盡成非。", "陰月霾中道，軒星落太微。空餘天子孝，松上景雲飛。"]'),
('yuding-11','戶部尚書崔公挽歌','崔融1','唐','御定全唐诗','yuding','','[]','八座圖書委，三台章奏盈。舉杯常有勸，曳履忽無聲。',48,'御定全唐詩/json/068.json','["八座圖書委，三台章奏盈。舉杯常有勸，曳履忽無聲。", "市若荊州罷，池如薛縣平。空餘濟南劍，天子署高名。"]'),
('yuding-12','韋長史挽詞','崔融1','唐','御定全唐诗','yuding','','[]','日落桑榆下，寒生松柏中。冥冥多苦霧，切切有悲風。',48,'御定全唐詩/json/068.json','["日落桑榆下，寒生松柏中。冥冥多苦霧，切切有悲風。", "京兆新阡辟，扶陽甲第空。郭門從此去，荊棘漸蒙籠。"]'),
('yuding-13','和梁王眾傳張光祿是王子晉後身','崔融1','唐','御定全唐诗','yuding','','[]','聞有沖天客，披雲下帝畿。三年上賓去，千載忽來歸。',120,'御定全唐詩/json/068.json','["聞有沖天客，披雲下帝畿。三年上賓去，千載忽來歸。", "昔偶浮丘伯，今同丁令威。中郎才貌是，柱史姓名非。", "祗召趨龍闕，承恩拜虎闈。丹成金鼎獻，酒至玉杯揮。", "天仗分旄節，朝容間羽衣。舊壇何處所，新廟坐光輝。", "漢主存仙要，淮南愛道機。朝朝緱氏鶴，長向洛城飛。"]'),
('yuding-14','哭蔣詹事儼','崔融1','唐','御定全唐诗','yuding','','[]','江上有長離，從容盛羽儀。一鳴百獸舞，一舉群鳥隨。',240,'御定全唐詩/json/068.json','["江上有長離，從容盛羽儀。一鳴百獸舞，一舉群鳥隨。", "應我聖明代，巢君阿閣垂。鉤陳侍帷扆，環衛奉旌麾。", "雅量滄海納，完才廟廊施。養親光孝道，事主竭忠規。", "貞節既已固，殊榮良不訾。朝游雲漢省，夕宴芙蓉池。", "汲黯言當直，陳平智本奇。功成喜身退，時往惜年馳。", "鎮國山基毀，中天柱石頹。將軍空有頌，刺史獨留碑。", "蕪漫藏書壁，荒涼懸劍枝。昔餘參下位，數載忝牽羈。", "置榻恩逾重，迎門禮自卑。竹林常接興，黍穀每逢吹。", "逸翰金相發，清談玉柄揮。不輕文舉少，深歎子雲疲。", "遺愛猶如在，殘編尚可窺。即今流水曲，何處俗人知。"]'),
('yuding-15','嵩山石淙侍宴應制','崔融1','唐','御定全唐诗','yuding','','[]','洞口仙岩類削成，泉香石冷晝含清。龍旗畫月中天下，',40,'御定全唐詩/json/068.json','["洞口仙岩類削成，泉香石冷晝含清。龍旗畫月中天下，", "今朝出豫臨懸圃，明日陪游向赤城。"]'),
('yuding-16','塞上寄內','崔融1','唐','御定全唐诗','yuding','','[]','旅魂驚塞北，歸望斷河西。春風若可寄，暫為繞蘭閨。',24,'御定全唐詩/json/068.json','["旅魂驚塞北，歸望斷河西。春風若可寄，暫為繞蘭閨。"]'),
('yuding-0','侍從途中口號應制','閻朝隱','唐','御定全唐诗','yuding','','[]','疵賤出山東，忠貞任土風。因敷河朔藻，得奉洛陽宮。',48,'御定全唐詩/json/069.json','["疵賤出山東，忠貞任土風。因敷河朔藻，得奉洛陽宮。", "一顧侍御史，再顧給事中。常願粉肌骨，特答造化功。"]'),
('yuding-1','奉和聖制夏日游石淙山','閻朝隱','唐','御定全唐诗','yuding','','[]','金台隱隱陵黃道，玉輦亭亭下絳雰。千種岡巒千種樹，',40,'御定全唐詩/json/069.json','["金台隱隱陵黃道，玉輦亭亭下絳雰。千種岡巒千種樹，", "五百里內賢人聚，願陪閶闔侍天文。"]'),
('yuding-2','鸚鵡貓兒篇','閻朝隱','唐','御定全唐诗','yuding','','[]','霹靂引，豐隆鳴，猛獸噫氣蛇吼聲。鸚鵡鳥，',146,'御定全唐詩/json/069.json','["霹靂引，豐隆鳴，猛獸噫氣蛇吼聲。鸚鵡鳥，", "此何為兮，好貌好音。彷彷兮徉徉，似妖姬躧步兮動羅裳；", "趨趨兮蹌蹌，若處子回眸兮登玉堂。爰有獸也，安其忍，", "鉤爪鋸牙也，宵行晝伏無以當。遇之兮忘味，摶擊騰擲也，", "嘉喜堂前景福內，合歡殿上明光裏。雲母屏風文彩合，", "朝有賢兮朝有德，賢為君兮德為飾，千年萬歲兮心轉憶。"]'),
('yuding-3','三日曲水侍宴應制','閻朝隱','唐','御定全唐诗','yuding','','[]','三月重三日，千春續萬春。聖澤如東海，天文似北辰。',48,'御定全唐詩/json/069.json','["三月重三日，千春續萬春。聖澤如東海，天文似北辰。", "荷葉珠盤淨，蓮花寶蓋新。陛下制萬國，臣作水心人。"]'),
('yuding-4','奉和九日幸臨渭亭，登高應制得筵字','閻朝隱','唐','御定全唐诗','yuding','','[]','九九侍神仙，高高坐半天。文章二曜動，氣色五星連。',48,'御定全唐詩/json/069.json','["九九侍神仙，高高坐半天。文章二曜動，氣色五星連。", "簪紱趨皇極，笙歌接禦筵。願因茱菊酒，相守百千年。"]'),
('yuding-5','奉和送金城公主適西蕃應制','閻朝隱','唐','御定全唐诗','yuding','','[]','甥舅重親地，君臣厚義鄉。還將貴公主，嫁與耨檀王。',48,'御定全唐詩/json/069.json','["甥舅重親地，君臣厚義鄉。還將貴公主，嫁與耨檀王。", "鹵簿山河暗，琵琶道路長。回瞻父母國，日出在東方。"]'),
('yuding-6','奉和立春遊苑迎春應制','閻朝隱','唐','御定全唐诗','yuding','','[]','管鑰周移寰極裏，乘輿望幸鬥城闉。草根未結青絲縷，',40,'御定全唐詩/json/069.json','["管鑰周移寰極裏，乘輿望幸鬥城闉。草根未結青絲縷，", "願得長繩系取日，光臨天子萬年春。"]'),
('yuding-7','奉和聖制春日幸望春宮應制','閻朝隱','唐','御定全唐诗','yuding','','[]','句芒人面乘兩龍，道是春神衛九重。彩勝年年逢七日，',40,'御定全唐詩/json/069.json','["句芒人面乘兩龍，道是春神衛九重。彩勝年年逢七日，", "醉倒君前情未盡，願因歌舞自為容。"]'),
('yuding-8','夜宴安樂公主新宅','閻朝隱','唐','御定全唐诗','yuding','','[]','鳳凰鳴舞樂昌年，蠟炬開花夜管弦。',32,'御定全唐詩/json/069.json','["鳳凰鳴舞樂昌年，蠟炬開花夜管弦。", "半醉徐擊珊瑚樹，已聞鐘漏曉聲傳。"]'),
('yuding-9','餞唐永昌','閻朝隱','唐','御定全唐诗','yuding','','[]','洛陽難理若棼絲，椎破連環定不疑。',32,'御定全唐詩/json/069.json','["洛陽難理若棼絲，椎破連環定不疑。", "鸚鵡休言秦地樂，回頭一顧一相思。"]'),
('yuding-10','明月歌','閻朝隱','唐','御定全唐诗','yuding','','[]','梅花雪白柳葉黃，雲霧四起月蒼蒼。箭水泠泠刻漏長。',40,'御定全唐詩/json/069.json','["梅花雪白柳葉黃，雲霧四起月蒼蒼。箭水泠泠刻漏長。", "揮玉指，拂羅裳，為君一奏楚明光。"]'),
('yuding-11','採蓮女','閻朝隱','唐','御定全唐诗','yuding','','[]','採蓮女，採蓮舟，春日春江碧水流。蓮衣承玉釧，',22,'御定全唐詩/json/069.json','["採蓮女，採蓮舟，春日春江碧水流。蓮衣承玉釧，"]'),
('yuding-12','奉和登驪山應制','閻朝隱','唐','御定全唐诗','yuding','','[]','龍行踏絳氣，天半語相聞。混沌疑初判，洪荒若始分。',24,'御定全唐詩/json/069.json','["龍行踏絳氣，天半語相聞。混沌疑初判，洪荒若始分。"]'),
('yuding-13','奉和九日幸臨渭亭登高應制得月字','韋元旦','唐','御定全唐诗','yuding','','[]','雲物開千里，天行乘九月。絲言丹鳳池，旆轉蒼龍闕。',48,'御定全唐詩/json/069.json','["雲物開千里，天行乘九月。絲言丹鳳池，旆轉蒼龍闕。", "灞水歡娛地，秦京遊俠窟。欣承解慍詞，聖酒黃花發。"]'),
('yuding-14','奉和送金城公主適西蕃應制','韋元旦','唐','御定全唐诗','yuding','','[]','柔遠安夷俗，和親重漢年。軍容旌節送，國命錦車傳。',48,'御定全唐詩/json/069.json','["柔遠安夷俗，和親重漢年。軍容旌節送，國命錦車傳。", "琴曲悲千里，簫聲戀九天。唯應西海月，來就掌珠圓。"]'),
('yuding-15','餞唐州高使君赴任','韋元旦','唐','御定全唐诗','yuding','','[]','桐柏膺新命，芝蘭惜舊遊。鳴皋夜鶴在，遷木早鶯求。',48,'御定全唐詩/json/069.json','["桐柏膺新命，芝蘭惜舊遊。鳴皋夜鶴在，遷木早鶯求。", "傳擁淮源路，尊空灞水流。落花紛送遠，春色引離憂。"]'),
('yuding-16','早朝','韋元旦','唐','御定全唐诗','yuding','','[]','震維芳月季，宸極眾星尊。佩玉朝三陛，鳴珂度九門。',72,'御定全唐詩/json/069.json','["震維芳月季，宸極眾星尊。佩玉朝三陛，鳴珂度九門。", "挈壺分早漏，伏檻耀初暾。北倚蒼龍闕，西臨紫鳳垣。", "詞庭草欲奏，溫室樹無言。鱗翰空為忝，長懷聖主恩。"]'),
('yuding-17','奉和立春遊苑迎春應制','韋元旦','唐','御定全唐诗','yuding','','[]','灞涘長安恒近日，殷正臘月早迎新。池魚戲葉仍含凍，',40,'御定全唐詩/json/069.json','["灞涘長安恒近日，殷正臘月早迎新。池魚戲葉仍含凍，", "年年斗柄東無限，願挹瓊觴壽北辰。"]'),
('yuding-18','奉和聖制春日幸望春宮應制','韋元旦','唐','御定全唐诗','yuding','','[]','九重樓閣半山霞，四望韶陽春未賒。侍蹕妍歌臨灞涘，',40,'御定全唐詩/json/069.json','["九重樓閣半山霞，四望韶陽春未賒。侍蹕妍歌臨灞涘，", "景色歡娛長若此，承恩不醉不還家。"]'),
('yuding-19','奉和人日宴大明宮恩賜彩縷人勝應制','韋元旦','唐','御定全唐诗','yuding','','[]','鸞鳳旌旗拂曉陳，魚龍角抵大明辰。青韶既肇人為日，',40,'御定全唐詩/json/069.json','["鸞鳳旌旗拂曉陳，魚龍角抵大明辰。青韶既肇人為日，", "垂旒一慶宜年酒，朝野俱歡薦壽新。"]'),
('yuding-20','奉和幸安樂公主山莊應制','韋元旦','唐','御定全唐诗','yuding','','[]','銀河南渚帝城隅，帝輦平明出九衢。刻鳳蟠螭淩桂邸，',40,'御定全唐詩/json/069.json','["銀河南渚帝城隅，帝輦平明出九衢。刻鳳蟠螭淩桂邸，", "仙榜承恩爭既醉，方知朝野更歡娛。"]'),
('yuding-21','興慶池侍宴應制','韋元旦','唐','御定全唐诗','yuding','','[]','滄池漭沆帝城邊，殊勝昆明鑿漢年。夾岸旌旗疏輦道，',40,'御定全唐詩/json/069.json','["滄池漭沆帝城邊，殊勝昆明鑿漢年。夾岸旌旗疏輦道，", "宴樂已深魚藻詠，承恩更欲奏甘泉。"]'),
('yuding-22','夜宴安樂公主宅','韋元旦','唐','御定全唐诗','yuding','','[]','主第新成銀作榜，賓筵廣宴玉為樓。',32,'御定全唐詩/json/069.json','["主第新成銀作榜，賓筵廣宴玉為樓。", "壺觴既卜仙人夜，歌舞宜停織女秋。"]'),
('yuding-23','奉和初春幸太平公主南莊應制','邵升','唐','御定全唐诗','yuding','','[]','沁園佳麗奪蓬瀛，翠壁紅泉繞上京。二聖忽從鸞殿幸，',40,'御定全唐詩/json/069.json','["沁園佳麗奪蓬瀛，翠壁紅泉繞上京。二聖忽從鸞殿幸，", "無路乘槎窺漢渚，徒知訪卜就君平。"]'),
('yuding-24','奉和送金城公主適西蕃應制','唐遠悊','唐','御定全唐诗','yuding','','[]','皇恩眷下人，割愛遠和親。少女風游兌，姮娥月去秦。',48,'御定全唐詩/json/069.json','["皇恩眷下人，割愛遠和親。少女風游兌，姮娥月去秦。", "龍笛迎金榜，驪歌送錦輪。那堪桃李色，移向虜庭春。"]'),
('yuding-0','汾陰後土祠作','李適','唐','御定全唐诗','yuding','','[]','昔予讀舊史，遍睹漢世君。武皇實稽古，建茲百代勳。',120,'御定全唐詩/json/070.json','["昔予讀舊史，遍睹漢世君。武皇實稽古，建茲百代勳。", "號令垂懋典，舊經備闕文。西巡曆九嶷，舳艫被江濱。", "勒兵十八萬，旌旗何紛紛。朅來茂陵下，英聲不復聞。", "我行歲方晏，極望山河分。神光終冥漠，鼎氣獨氛氳。", "攬涕步脽上，登高見彼汾。雄圖今安在，飛飛有白雲。"]'),
('yuding-1','答宋十一崖口五渡見贈','李適','唐','御定全唐诗','yuding','','[]','聞君訪遠山，躋險造幽絕。眇然青雲境，觀奇彌年月。',120,'御定全唐詩/json/070.json','["聞君訪遠山，躋險造幽絕。眇然青雲境，觀奇彌年月。", "登嶺亦溯溪，孤舟事沿越。崿嶂傳彩翠，崖磴互欹缺。", "石林上攢叢，金澗下明滅。捫壁窺丹井，梯苔瞰乳穴。", "忽枉岩中贈，對玩未嘗輟。殷勤獨往事，委曲煉藥說。", "邀餘名山期，從爾泛海澨。歲晏秉宿心，斯言非徒設。"]'),
('yuding-2','餞許州宋司馬赴任','李適','唐','御定全唐诗','yuding','','[]','昔吾遊箕山，朅來涉潁水。複有許由廟，迢迢白雲裏。',48,'御定全唐詩/json/070.json','["昔吾遊箕山，朅來涉潁水。複有許由廟，迢迢白雲裏。", "聞君佐繁昌，臨風悵懷此。儻到平輿泉，寄謝幹將裏。"]'),
('yuding-3','奉和聖制九日侍宴應制得高字','李適','唐','御定全唐诗','yuding','','[]','禁苑秋光入，宸游霽色高。萸房頒彩笥，菊蕊薦香醪。',48,'御定全唐詩/json/070.json','["禁苑秋光入，宸游霽色高。萸房頒彩笥，菊蕊薦香醪。", "後騎縈堤柳，前旌拂禦桃。王枚俱得從，淺淺愧飛毫。"]'),
('yuding-4','游禁苑幸臨渭亭遇雪應制','李適','唐','御定全唐诗','yuding','','[]','長樂喜春歸，披香瑞雪霏。花從銀閣度，絮繞玉窗飛。',48,'御定全唐詩/json/070.json','["長樂喜春歸，披香瑞雪霏。花從銀閣度，絮繞玉窗飛。", "寫曜銜天藻，呈祥拂禦衣。上林紛可望，無處不光輝。"]'),
('yuding-5','奉和九日登慈恩寺浮圖應制','李適','唐','御定全唐诗','yuding','','[]','鳳輦乘朝霽，鸚林對晚秋。天文貝葉寫，聖澤菊花浮。',48,'御定全唐詩/json/070.json','["鳳輦乘朝霽，鸚林對晚秋。天文貝葉寫，聖澤菊花浮。", "塔似神功造，龕疑佛影留。幸陪清漢蹕，欣奉淨居遊。"]'),
('yuding-6','侍宴長寧公主東莊應制','李適','唐','御定全唐诗','yuding','','[]','鳳樓紆睿幸，龍舸暢宸襟。歌舞平陽第，園亭沁水林。',48,'御定全唐詩/json/070.json','["鳳樓紆睿幸，龍舸暢宸襟。歌舞平陽第，園亭沁水林。", "山花添聖酒，澗竹繞熏琴。願奉瑤池駕，千春侍德音。"]'),
('yuding-7','奉和送金城公主適西蕃應制','李適','唐','御定全唐诗','yuding','','[]','絳河從遠聘，青海赴和親。月作臨邊曉，花為度隴春。',48,'御定全唐詩/json/070.json','["絳河從遠聘，青海赴和親。月作臨邊曉，花為度隴春。", "主歌悲顧鶴，帝策重安人。獨有瓊簫去，悠悠思錦輪。"]'),
('yuding-8','安樂公主移入新宅','李適','唐','御定全唐诗','yuding','','[]','星橋他日創，仙榜此時開。馬向鋪錢埒，簫聞奏玉台。',48,'御定全唐詩/json/070.json','["星橋他日創，仙榜此時開。馬向鋪錢埒，簫聞奏玉台。", "人疑衛叔美，客似長卿才。借問游天使，誰能取石回。"]'),
('yuding-9','奉和幸望春宮送朔方軍大總管張仁亶','李適','唐','御定全唐诗','yuding','','[]','地限驕南牧，天臨餞北征。解衣延寵命，橫劍總威名。',48,'御定全唐詩/json/070.json','["地限驕南牧，天臨餞北征。解衣延寵命，橫劍總威名。", "豹略恭宸旨，雄文動睿情。坐觀膜拜入，朝夕受降城。"]'),
('yuding-10','人日宴大明宮恩賜彩縷人勝應制','李適','唐','御定全唐诗','yuding','','[]','朱城待鳳韶年至，碧殿疏龍淑氣來。寶帳金屏人已帖，',40,'御定全唐詩/json/070.json','["朱城待鳳韶年至，碧殿疏龍淑氣來。寶帳金屏人已帖，", "向夕憑高風景麗，天文垂耀象昭回。"]'),
('yuding-11','奉和春日幸望春宮應制','李適','唐','御定全唐诗','yuding','','[]','玉輦金輿天上來，花園四望錦屏開。輕絲半拂朱門柳，',40,'御定全唐詩/json/070.json','["玉輦金輿天上來，花園四望錦屏開。輕絲半拂朱門柳，", "聖詞今日光輝滿，漢主秋風莫道才。"]'),
('yuding-12','奉和立春遊苑迎春','李適','唐','御定全唐诗','yuding','','[]','金輿翠輦迎嘉節，御苑仙宮待獻春。淑氣初銜梅色淺，',40,'御定全唐詩/json/070.json','["金輿翠輦迎嘉節，御苑仙宮待獻春。淑氣初銜梅色淺，", "稍覺披香歌吹近，龍驂日暮下城闉。"]'),
('yuding-13','帝幸興慶池戲競渡應制','李適','唐','御定全唐诗','yuding','','[]','拂露金輿丹旆轉，淩晨黼帳碧池開。南山倒影從雲落，',40,'御定全唐詩/json/070.json','["拂露金輿丹旆轉，淩晨黼帳碧池開。南山倒影從雲落，", "橫汾宴鎬歡無極，歌舞年年聖壽杯。"]'),
('yuding-14','侍宴安樂公主莊應制','李適','唐','御定全唐诗','yuding','','[]','平陽金榜鳳凰樓，沁水銀河鸚鵡洲。彩仗遙臨丹壑裏，',40,'御定全唐詩/json/070.json','["平陽金榜鳳凰樓，沁水銀河鸚鵡洲。彩仗遙臨丹壑裏，", "貴主稱觴萬年壽，還輕漢武濟汾遊。"]'),
('yuding-15','侍宴安樂公主新宅應制','李適','唐','御定全唐诗','yuding','','[]','銀河半倚鳳凰台，玉酒相傳鸚鵡杯。',32,'御定全唐詩/json/070.json','["銀河半倚鳳凰台，玉酒相傳鸚鵡杯。", "若見君平須借問，仙槎一去幾時來。"]'),
('yuding-16','餞唐永昌赴任東都','李適','唐','御定全唐诗','yuding','','[]','聞道飛鳧向洛陽，翩翩矯翮度文昌。',32,'御定全唐詩/json/070.json','["聞道飛鳧向洛陽，翩翩矯翮度文昌。", "因聲寄意三花樹，少室岩前幾過香。"]'),
('yuding-0','奉和聖制立春日侍宴內殿出剪綵花應制','劉憲','唐','御定全唐诗','yuding','','[]','上林宮館好，春光獨早知。剪花疑始發，刻燕似新窺。',48,'御定全唐詩/json/071.json','["上林宮館好，春光獨早知。剪花疑始發，刻燕似新窺。", "色濃輕雪點，香淺嫩風吹。此日叨陪侍，恩榮得數枝。"]'),
('yuding-1','奉和人日清暉閣宴群臣遇雪應制','劉憲','唐','御定全唐诗','yuding','','[]','輿輦乘人日，登臨上鳳京。風尋歌曲颺，雪向舞行縈。',48,'御定全唐詩/json/071.json','["輿輦乘人日，登臨上鳳京。風尋歌曲颺，雪向舞行縈。", "千官隨興合，萬福與時並。承恩長若此，微賤幸升平。"]'),
('yuding-2','奉和七夕宴兩儀殿應制','劉憲','唐','御定全唐诗','yuding','','[]','秋吹過雙闕，星仙動二靈。更深移月鏡，河淺度雲輧。',48,'御定全唐詩/json/071.json','["秋吹過雙闕，星仙動二靈。更深移月鏡，河淺度雲輧。", "殿上呼方朔，人間失武丁。天文茲夜裏，光映紫微庭。"]'),
('yuding-3','奉和九月九日聖制登慈恩寺浮圖應制','劉憲','唐','御定全唐诗','yuding','','[]','飛塔雲霄半，清晨羽旆遊。登臨憑季月，寥廓見中州。',48,'御定全唐詩/json/071.json','["飛塔雲霄半，清晨羽旆遊。登臨憑季月，寥廓見中州。", "禦酒新寒退，天文瑞景留。辟邪將獻壽，茲日奉千秋。"]'),
('yuding-4','閏九月九日幸總持寺登浮圖應制','劉憲','唐','御定全唐诗','yuding','','[]','重陽登閏序，上界葉時巡。駐輦天花落，開筵妓樂陳。',48,'御定全唐詩/json/071.json','["重陽登閏序，上界葉時巡。駐輦天花落，開筵妓樂陳。", "城端刹柱見，雲表露盤新。臨睨光輝滿，飛文動睿神。"]'),
('yuding-5','侍宴長寧公主東莊','劉憲','唐','御定全唐诗','yuding','','[]','公主林亭地，清晨降玉輿。畫橋飛渡水，仙閣湧臨虛。',48,'御定全唐詩/json/071.json','["公主林亭地，清晨降玉輿。畫橋飛渡水，仙閣湧臨虛。", "晴新看蛺蝶，夏早摘芙蕖。文酒娛游盛，忻叨侍從餘。"]'),
('yuding-6','奉和送金城公主入西蕃應制','劉憲','唐','御定全唐诗','yuding','','[]','外館逾河右，行營指路岐。和親悲遠嫁，忍愛泣將離。',48,'御定全唐詩/json/071.json','["外館逾河右，行營指路岐。和親悲遠嫁，忍愛泣將離。", "旌旆羌風引，軒車漢月隨。那堪馬上曲，時向管中吹。"]'),
('yuding-7','奉和聖制登驪山高頂寓目應制','劉憲','唐','御定全唐诗','yuding','','[]','驪阜鎮皇都，鑾游眺八區。原隰旌門裏，風雲扆座隅。',48,'御定全唐詩/json/071.json','["驪阜鎮皇都，鑾游眺八區。原隰旌門裏，風雲扆座隅。", "直城如斗柄，官樹似星榆。從臣詞賦末，濫得上天衢。"]'),
('yuding-8','奉和幸白鹿觀應制','劉憲','唐','御定全唐诗','yuding','','[]','玄遊乘落暉，仙宇藹霏微。石樑縈澗轉，珠旆掃壇飛。',48,'御定全唐詩/json/071.json','["玄遊乘落暉，仙宇藹霏微。石樑縈澗轉，珠旆掃壇飛。", "芝童薦膏液，松鶴舞驂騑。還似瑤池上，歌成周馭歸。"]'),
('yuding-9','折楊柳','劉憲','唐','御定全唐诗','yuding','','[]','沙塞三河道，金閨二月春。碧煙楊柳色，紅粉綺羅人。',48,'御定全唐詩/json/071.json','["沙塞三河道，金閨二月春。碧煙楊柳色，紅粉綺羅人。", "露葉憐啼臉，風花思舞巾。攀持君不見，為聽曲中新。"]'),
('yuding-10','奉和立春日內出彩花樹應制','劉憲','唐','御定全唐诗','yuding','','[]','禁苑韶年此日歸，東郊道上轉青旗。柳色梅芳何處所，',40,'御定全唐詩/json/071.json','["禁苑韶年此日歸，東郊道上轉青旗。柳色梅芳何處所，", "欲識王游布陽氣，為觀天藻競春暉。"]'),
('yuding-11','奉和春日幸望春宮應制','劉憲','唐','御定全唐诗','yuding','','[]','暮春春色最便妍，苑裏花開列禦筵。商山積翠臨城起，',40,'御定全唐詩/json/071.json','["暮春春色最便妍，苑裏花開列禦筵。商山積翠臨城起，", "歡娛節物今如此，願奉宸遊億萬年。"]'),
('yuding-12','奉和幸安樂公主山莊應制','劉憲','唐','御定全唐诗','yuding','','[]','主家別墅帝城隈，無勞海上覓蓬萊。遝石懸流平地起，',40,'御定全唐詩/json/071.json','["主家別墅帝城隈，無勞海上覓蓬萊。遝石懸流平地起，", "此日風光與形勝，只言作伴聖詞來。"]'),
('yuding-13','興慶池侍宴應制','劉憲','唐','御定全唐诗','yuding','','[]','蒼龍闕下天泉池，軒駕來游簫管吹。緣堤夏筱縈不散，',40,'御定全唐詩/json/071.json','["蒼龍闕下天泉池，軒駕來游簫管吹。緣堤夏筱縈不散，", "自然東海神仙處，何用西昆轍跡疲。"]'),
('yuding-14','奉和幸大薦福寺應制','劉憲','唐','御定全唐诗','yuding','','[]','地靈傳景福，天駕儼鉤陳。佳哉藩邸舊，赫矣梵宮新。',72,'御定全唐詩/json/071.json','["地靈傳景福，天駕儼鉤陳。佳哉藩邸舊，赫矣梵宮新。", "香塔魚山下，禪堂雁水濱。珠幡映白日，鏡殿寫青春。", "甚歡延故吏，大覺拯生人。幸承歌頌末，長奉屬車塵。"]'),
('yuding-15','奉和幸三會寺應制','劉憲','唐','御定全唐诗','yuding','','[]','岧嶢倉史台，敞朗紺園開。戒旦壺人集，翻霜羽騎來。',72,'御定全唐詩/json/071.json','["岧嶢倉史台，敞朗紺園開。戒旦壺人集，翻霜羽騎來。", "下輦登三襲，褰旒望九垓。林披館陶榜，水浸昆明灰。", "網戶飛花綴，幡竿度鳥回。豫遊仙唱動，瀟灑出塵埃。"]'),
('yuding-16','奉和幸長安故城未央宮應制','劉憲','唐','御定全唐诗','yuding','','[]','漢宮千祀外，軒駕一來遊。夷蕩長如此，威靈不復留。',72,'御定全唐詩/json/071.json','["漢宮千祀外，軒駕一來遊。夷蕩長如此，威靈不復留。", "憑高睿賞發，懷古聖情周。寒向南山斂，春過北渭浮。", "土功昔雲盛，人英今所求。幸聽熏風曲，方知霸道羞。"]'),
('yuding-17','奉和幸禮部尚書竇希玠宅應制','劉憲','唐','御定全唐诗','yuding','','[]','北斗樞機任，西京肺腑親。疇昔王門下，今茲禦幸辰。',72,'御定全唐詩/json/071.json','["北斗樞機任，西京肺腑親。疇昔王門下，今茲禦幸辰。", "恩光山水被，聖作管弦新。繞坐熏紅藥，當軒暗綠筠。", "摘荷才早夏，聽鳥尚餘春。行漏今徒晚，風煙起觀津。"]'),
('yuding-18','奉和聖制幸望春宮送朔方大總管張仁亶','劉憲','唐','御定全唐诗','yuding','','[]','命將擇耆年，圖功勝必全。光輝萬乘餞，威武二庭宣。',72,'御定全唐詩/json/071.json','["命將擇耆年，圖功勝必全。光輝萬乘餞，威武二庭宣。", "中衢橫鼓角，曠野蔽旌旃。推食天廚至，投醪禦酒傳。", "涼風過雁苑，殺氣下雞田。分閫恩何極，臨岐動睿篇。"]'),
('yuding-19','奉和幸韋嗣立山莊侍宴應制','劉憲','唐','御定全唐诗','yuding','','[]','東山有謝安，枉道降鳴鑾。緹騎分初日，霓旌度曉寒。',96,'御定全唐詩/json/071.json','["東山有謝安，枉道降鳴鑾。緹騎分初日，霓旌度曉寒。", "雲蹕岩間下，虹橋澗底盤。幽棲俄以屆，聖矚宛餘歡。", "崖懸飛溜直，岸轉綠潭寬。桂華堯酒泛，松響舜琴彈。", "明主恩斯極，賢臣節更殫。不才叨侍從，詠德以濡翰。"]'),
('yuding-20','人日玩雪應制','劉憲','唐','御定全唐诗','yuding','','[]','勝日登臨雲葉起，芳風搖盪雪花飛。',32,'御定全唐詩/json/071.json','["勝日登臨雲葉起，芳風搖盪雪花飛。", "呈暉幸得承金鏡，颺彩還將奉玉衣。"]'),
('yuding-21','上巳日祓禊渭濱應制','劉憲','唐','御定全唐诗','yuding','','[]','桃花欲落柳條長，沙頭水上足風光。',32,'御定全唐詩/json/071.json','["桃花欲落柳條長，沙頭水上足風光。", "此時禦蹕來遊處，願奉年年祓禊觴。"]'),
('yuding-22','苑中遇雪應制','劉憲','唐','御定全唐诗','yuding','','[]','龍驂曉入望春宮，正逢春雪舞東風。',32,'御定全唐詩/json/071.json','["龍驂曉入望春宮，正逢春雪舞東風。", "花光並灑天文上，寒氣行消禦酒中。"]'),
('yuding-23','夜宴安樂公主新宅','劉憲','唐','御定全唐诗','yuding','','[]','層軒洞戶旦新披，度曲飛觴夜不疲。',32,'御定全唐詩/json/071.json','["層軒洞戶旦新披，度曲飛觴夜不疲。", "綺綴玲瓏河色曉，珠簾隱映月華窺。"]'),
('yuding-24','奉和聖制幸韋嗣立山莊','劉憲','唐','御定全唐诗','yuding','','[]','非吏非隱晉尚書，一丘一壑降乘輿。',32,'御定全唐詩/json/071.json','["非吏非隱晉尚書，一丘一壑降乘輿。", "天藻緣情兩曜合，山卮獻壽萬年餘。"]'),
('yuding-25','餞唐永昌','劉憲','唐','御定全唐诗','yuding','','[]','始見郎官拜洛陽，旋聞近侍發雕章。',32,'御定全唐詩/json/071.json','["始見郎官拜洛陽，旋聞近侍發雕章。", "緒言已勖期年政，綺字當生滿路光。"]'),
('yuding-0','晦日置酒林亭','高正臣','唐','御定全唐诗','yuding','','[]','正月符嘉節，三春玩物華。忘懷寄尊酒，陶性狎山家。',48,'御定全唐詩/json/072.json','["正月符嘉節，三春玩物華。忘懷寄尊酒，陶性狎山家。", "柳翠含煙葉，梅芳帶雪花。光陰不相借，遲遲落景斜。"]'),
('yuding-1','晦日重宴','高正臣','唐','御定全唐诗','yuding','','[]','芳辰重遊衍，乘景共追隨。班荊陪舊識，傾蓋得新知。',48,'御定全唐詩/json/072.json','["芳辰重遊衍，乘景共追隨。班荊陪舊識，傾蓋得新知。", "水葉分蓮沼，風花落柳枝。自符河朔趣，甯羨高陽池。"]'),
('yuding-2','晦日宴高氏林亭','崔知賢','唐','御定全唐诗','yuding','','[]','上月河陽地，芳辰景物華。綿蠻變時鳥，照曜起春霞。',48,'御定全唐詩/json/072.json','["上月河陽地，芳辰景物華。綿蠻變時鳥，照曜起春霞。", "柳搖風處色，梅散日前花。淹留洛城晚，歌吹石崇家。"]'),
('yuding-3','上元夜效小庾體','崔知賢','唐','御定全唐诗','yuding','','[]','今夜啟城闉，結伴戲芳春。鼓聲撩亂動，風光觸處新。',48,'御定全唐詩/json/072.json','["今夜啟城闉，結伴戲芳春。鼓聲撩亂動，風光觸處新。", "月下多遊騎，燈前饒看人。歡樂無窮已，歌舞達明晨。"]'),
('yuding-4','三月三日宴王明府山亭','崔知賢','唐','御定全唐诗','yuding','','[]','京洛皇居，芳禊春餘。影媚元巳，和風上除。雲開翠帟，',35,'御定全唐詩/json/072.json','["京洛皇居，芳禊春餘。影媚元巳，和風上除。雲開翠帟，", "沿波式宴，其樂只且。"]'),
('yuding-5','三月三日宴王明府山亭','席元明','唐','御定全唐诗','yuding','','[]','日惟上巳，時亨有巢。中尊引桂，芳筵藉茅。書僮橐筆，',35,'御定全唐詩/json/072.json','["日惟上巳，時亨有巢。中尊引桂，芳筵藉茅。書僮橐筆，", "同人聚飲，千載神交。"]'),
('yuding-6','晦日宴高氏林亭','韓仲宣','唐','御定全唐诗','yuding','','[]','欲知行有樂，芳尊對物華。地接安仁縣，園是季倫家。',48,'御定全唐詩/json/072.json','["欲知行有樂，芳尊對物華。地接安仁縣，園是季倫家。", "柳處雲疑葉，梅間雪似花。日落歸途遠，留興伴煙霞。"]'),
('yuding-7','晦日重宴','韓仲宣','唐','御定全唐诗','yuding','','[]','鳳苑先吹晚，龍樓夕照披。陳遵已投轄，山公正坐池。',48,'御定全唐詩/json/072.json','["鳳苑先吹晚，龍樓夕照披。陳遵已投轄，山公正坐池。", "落日催金奏，飛霞送玉卮。此時陪綺席，不醉欲何為。"]'),
('yuding-8','上元夜效小庾體','韓仲宣','唐','御定全唐诗','yuding','','[]','他鄉月夜人，相伴看燈輪。光隨九華出，影共百枝新。',48,'御定全唐詩/json/072.json','["他鄉月夜人，相伴看燈輪。光隨九華出，影共百枝新。", "歌鐘盛北裏，車馬沸南鄰。今宵何處好，惟有洛城春。"]'),
('yuding-9','三月三日宴王明府山亭','韓仲宣','唐','御定全唐诗','yuding','','[]','河濱上巳，洛汭春華。碧池涵日，翠斝澄霞。溝垂細柳，',35,'御定全唐詩/json/072.json','["河濱上巳，洛汭春華。碧池涵日，翠斝澄霞。溝垂細柳，", "熟記行樂，淹留景斜。"]'),
('yuding-10','晦日宴高氏林亭','周彥昭','唐','御定全唐诗','yuding','','[]','勝地臨雞浦，高會偶龍池。禦柳驚春色，仙筇掩月華。',48,'御定全唐詩/json/072.json','["勝地臨雞浦，高會偶龍池。禦柳驚春色，仙筇掩月華。", "門邀千里馭，杯泛九光霞。日落山亭晚，雷送七香車。"]'),
('yuding-11','晦日宴高氏林亭','高球','唐','御定全唐诗','yuding','','[]','溫洛年光早，皇州景望華。連鑣尋上路，乘興入山家。',48,'御定全唐詩/json/072.json','["溫洛年光早，皇州景望華。連鑣尋上路，乘興入山家。", "輕苔網危石，春水架平沙。賞極林塘暮，處處起煙霞。"]'),
('yuding-12','三月三日宴王明府山亭','高球','唐','御定全唐诗','yuding','','[]','洛城春禊，元巳芳年。季倫園裏，逸少亭前。曲中舉白，',35,'御定全唐詩/json/072.json','["洛城春禊，元巳芳年。季倫園裏，逸少亭前。曲中舉白，", "未淹歡趣，林溪夕煙。"]'),
('yuding-13','晦日宴高氏林亭','弓嗣初','唐','御定全唐诗','yuding','','[]','上序春暉麗，中園物候華。高才盛文雅，逸興滿煙霞。',48,'御定全唐詩/json/072.json','["上序春暉麗，中園物候華。高才盛文雅，逸興滿煙霞。", "參差金穀樹，皎鏡碧塘沙。蕭散林亭晚，倒載欲還家。"]'),
('yuding-14','晦日重宴','弓嗣初','唐','御定全唐诗','yuding','','[]','年華藹芳隰，春溜滿新池。促賞依三友，延歡寄一卮。',48,'御定全唐詩/json/072.json','["年華藹芳隰，春溜滿新池。促賞依三友，延歡寄一卮。", "鳥聲隨管變，花影逐風移。行樂方無極，淹留惜晚曦。"]'),
('yuding-15','三月三日宴王明府山亭','高瑾','唐','御定全唐诗','yuding','','[]','暮春元巳，春服初裁。童冠八九，於洛之隈。',60,'御定全唐詩/json/072.json','["暮春元巳，春服初裁。童冠八九，於洛之隈。", "河堤草變，鞏樹花開。逸人談發，仙禦舟來。", "間關黃鳥，瀺灂丹腮。樂飲命席，優哉悠哉。"]'),
('yuding-16','晦日宴高氏林亭','高瑾','唐','御定全唐诗','yuding','','[]','試入山亭望，言是石崇家。二月風光起，三春桃李華。',48,'御定全唐詩/json/072.json','["試入山亭望，言是石崇家。二月風光起，三春桃李華。", "鶯吟上喬木，雁往息平沙。相看會取醉，甯知還路賒。"]'),
('yuding-17','晦日重宴','高瑾','唐','御定全唐诗','yuding','','[]','忽聞鶯響谷，于此命相知。正開彭澤酒，來向高陽池。',48,'御定全唐詩/json/072.json','["忽聞鶯響谷，于此命相知。正開彭澤酒，來向高陽池。", "柳葉風前弱，梅花影處危。賞洽林亭晚，落照下參差。"]'),
('yuding-18','上元夜效小庾體','高瑾','唐','御定全唐诗','yuding','','[]','初年三五夜，相知一兩人。連鑣出巷口，飛轂下池漘。',48,'御定全唐詩/json/072.json','["初年三五夜，相知一兩人。連鑣出巷口，飛轂下池漘。", "燈光恰似月，人面並如春。遨遊終未已，相歡待日輪。"]'),
('yuding-19','晦日宴高氏林亭','王茂時','唐','御定全唐诗','yuding','','[]','踐勝尋良會，乘春玩物華。還隨張放友，來向石崇家。',48,'御定全唐詩/json/072.json','["踐勝尋良會，乘春玩物華。還隨張放友，來向石崇家。", "止水分岩鏡，閒庭枕浦沙。未極林泉賞，參差落照斜。"]'),
('yuding-20','晦日宴高氏林亭','徐皓','唐','御定全唐诗','yuding','','[]','綺筵乘暇景，瓊醑對年華。門多金埒騎，路引璧人車。',48,'御定全唐詩/json/072.json','["綺筵乘暇景，瓊醑對年華。門多金埒騎，路引璧人車。", "蘋早猶藏葉，梅殘正落花。藹藹林亭晚，餘興促流霞。"]'),
('yuding-21','晦日宴高氏林亭','長孫正隱','唐','御定全唐诗','yuding','','[]','晦晚屬煙霞，遨遊重歲華。歌鐘雖戚裏，林藪是山家。',48,'御定全唐詩/json/072.json','["晦晚屬煙霞，遨遊重歲華。歌鐘雖戚裏，林藪是山家。", "細雨猶開日，深池不漲沙。淹留迷處所，岩岫幾重花。"]'),
('yuding-22','上元夜效小庾體同用春字','長孫正隱','唐','御定全唐诗','yuding','','[]','薄晚嘯遊人，車馬亂驅塵。月光三五夜，燈焰一重春。',48,'御定全唐詩/json/072.json','["薄晚嘯遊人，車馬亂驅塵。月光三五夜，燈焰一重春。", "煙雲迷北闕，簫管識南鄰。洛城終不閉，更出小平津。"]'),
('yuding-23','晦日宴高氏林亭','高紹','唐','御定全唐诗','yuding','','[]','嘯侶入山家，臨春玩物華。葛弦調綠水，桂醑酌丹霞。',48,'御定全唐詩/json/072.json','["嘯侶入山家，臨春玩物華。葛弦調綠水，桂醑酌丹霞。", "岸柳開新葉，庭梅落早花。興洽林亭晚，方還倒載車。"]'),
('yuding-24','晦日宴高氏林亭','郎餘令','唐','御定全唐诗','yuding','','[]','三春休晦節，九谷泛年華。半晴餘細雨，全晚澹殘霞。',48,'御定全唐詩/json/072.json','["三春休晦節，九谷泛年華。半晴餘細雨，全晚澹殘霞。", "尊開疏竹葉，管應落梅花。興闌相顧起，流水送香車。"]'),
('yuding-25','晦日宴高氏林亭','陳嘉言','唐','御定全唐诗','yuding','','[]','公子申敬愛，攜朋玩物華。人是平陽客，地即石崇家。',48,'御定全唐詩/json/072.json','["公子申敬愛，攜朋玩物華。人是平陽客，地即石崇家。", "水文生舊浦，風色滿新花。日暮連歸騎，長川照晚霞。"]'),
('yuding-26','晦日重宴','陳嘉言','唐','御定全唐诗','yuding','','[]','高門引冠蓋，下客抱支離。綺席珍羞滿，文場翰藻摛。',48,'御定全唐詩/json/072.json','["高門引冠蓋，下客抱支離。綺席珍羞滿，文場翰藻摛。", "蓂華雕上月，柳色藹春池。日斜歸戚裏，連騎勒金羈。"]'),
('yuding-27','上元夜效小庾體','陳嘉言','唐','御定全唐诗','yuding','','[]','今夜可憐春，河橋多麗人。寶馬金為絡，香車玉作輪。',48,'御定全唐詩/json/072.json','["今夜可憐春，河橋多麗人。寶馬金為絡，香車玉作輪。", "聯手窺潘掾，分頭看洛神。重城自不掩，出向小平津。"]'),
('yuding-28','晦日宴高氏林亭','周彥暉','唐','御定全唐诗','yuding','','[]','砌蓂收晦魄，津柳競年華。既狎忘筌友，方淹投轄車。',48,'御定全唐詩/json/072.json','["砌蓂收晦魄，津柳競年華。既狎忘筌友，方淹投轄車。", "綺筵回舞雪，瓊醑泛流霞。雲低上天晚，絲雨帶風斜。"]'),
('yuding-29','晦日重宴','周彥暉','唐','御定全唐诗','yuding','','[]','春華歸柳樹，俯景落蓂枝。置驛銅街右，開筵玉浦陲。',48,'御定全唐詩/json/072.json','["春華歸柳樹，俯景落蓂枝。置驛銅街右，開筵玉浦陲。", "林煙含障密，竹雨帶珠危。興闌巾倒戴，山公下習池。"]'),
('yuding-30','晦日宴高氏林亭','高嶠','唐','御定全唐诗','yuding','','[]','飛觀寫春望，開宴坐汀沙。積溜含苔色，晴空蕩日華。',48,'御定全唐詩/json/072.json','["飛觀寫春望，開宴坐汀沙。積溜含苔色，晴空蕩日華。", "歌入平陽第，舞對石崇家。莫慮能騎馬，投轄自停車。"]'),
('yuding-31','晦日重宴','高嶠','唐','御定全唐诗','yuding','','[]','駕言尋鳳侶，乘歡俯雁池。班荊逢舊識，斟桂喜深知。',48,'御定全唐詩/json/072.json','["駕言尋鳳侶，乘歡俯雁池。班荊逢舊識，斟桂喜深知。", "紫蘭方出徑，黃鶯未囀枝。別有陶春日，青天雲霧披。"]'),
('yuding-32','晦日宴高氏林亭','劉友賢','唐','御定全唐诗','yuding','','[]','春來日漸賒，琴酒逐年華。欲向文通徑，先游武子家。',48,'御定全唐詩/json/072.json','["春來日漸賒，琴酒逐年華。欲向文通徑，先游武子家。", "池碧新流滿，岩紅落照斜。興闌情未盡，步步惜風花。"]'),
('yuding-33','晦日宴高氏林亭','周思鈞','唐','御定全唐诗','yuding','','[]','早春驚柳穟，初晦掩蓂華。騎出平陽裏，筵開衛尉家。',48,'御定全唐詩/json/072.json','["早春驚柳穟，初晦掩蓂華。騎出平陽裏，筵開衛尉家。", "竹影含雲密，池紋帶雨斜。重惜林亭晚，上路滿煙霞。"]'),
('yuding-34','晦日重宴','周思鈞','唐','御定全唐诗','yuding','','[]','綺筵乘晦景，高宴下陽池。濯雨梅香散，含風柳色移。',48,'御定全唐詩/json/072.json','["綺筵乘晦景，高宴下陽池。濯雨梅香散，含風柳色移。", "輕塵依扇落，流水入弦危。勿顧林亭晚，方歡雲霧披。"]'),
('yuding-0','祭汾陰樂章','蘇頲','唐','御定全唐诗','yuding','','[]','禮物斯具，樂章乃陳。誰其作主，皇考聖真。',40,'御定全唐詩/json/073.json','["禮物斯具，樂章乃陳。誰其作主，皇考聖真。", "對越在天，聖明佐神。窅然汾上，厚澤如春。"]'),
('yuding-1','奉和聖制行次成皋途經先聖擒建德之所感而成詩應制','蘇頲','唐','御定全唐诗','yuding','','[]','漢東不執象，河朔方鬥龍。夏滅漸甯亂，唐興終奮庸。',72,'御定全唐詩/json/073.json','["漢東不執象，河朔方鬥龍。夏滅漸甯亂，唐興終奮庸。", "皇威正赫赫，兵氣何匈匈。用武三川震，歸淳六代醲。", "成皋睹王業，天下致人雍。即此巡于岱，曾孫受命封。"]'),
('yuding-2','奉和聖制登蒲州逍遙樓應制','蘇頲','唐','御定全唐诗','yuding','','[]','在昔堯舜禹，遺塵成典謨。聖皇東巡狩，況乃經此都。',72,'御定全唐詩/json/073.json','["在昔堯舜禹，遺塵成典謨。聖皇東巡狩，況乃經此都。", "樓觀紛迤邐，河山幾縈紆。緬懷祖宗業，相繼文武圖。", "尚德既無險，觀風諒有孚。豈如汾水上，簫鼓事遊娛。"]'),
('yuding-3','奉和聖制過晉陽宮應制','蘇頲','唐','御定全唐诗','yuding','','[]','隋運與天絕，生靈厭氛昏。聖期在寧亂，士馬興太原。',144,'御定全唐詩/json/073.json','["隋運與天絕，生靈厭氛昏。聖期在寧亂，士馬興太原。", "立極萬邦推，登庸四海尊。慶膺神武帝，業付皇曾孫。", "緬慕封唐道，追惟歸沛魂。詔書感先義，典禮巡舊藩。", "高殿彩雲合，春旗祥風翻。率西見汾水，奔北空塞垣。", "款曲童兒佐，依遲故老言。裏頒慈惠賞，家受複除恩。", "下輦崇三教，建碑當九門。孝思敦至美，億載奉開元。"]'),
('yuding-4','奉和姚令公溫湯舊館永懷故人盧公之作','蘇頲','唐','御定全唐诗','yuding','','[]','樹德豈孤邁，降神良並出。偉茲廊廟楨，調彼鹽梅實。',96,'御定全唐詩/json/073.json','["樹德豈孤邁，降神良並出。偉茲廊廟楨，調彼鹽梅實。", "正悅虞垂舉，翻悲鄭僑卒。同心不可忘，交臂何為失。", "清路荷前幸，明時稱右弼。曾聯野外游，尚記帷中密。", "新慟情莫遣，舊遊詞更述。空令還辱和，長歎知音日。"]'),
('yuding-5','和杜主簿春日有所思','蘇頲','唐','御定全唐诗','yuding','','[]','朝上高樓上，俯見洛陽陌。搖盪吹花風，落英紛已積。',72,'御定全唐詩/json/073.json','["朝上高樓上，俯見洛陽陌。搖盪吹花風，落英紛已積。", "美人不共此，芳好空所惜。攬鏡塵網滋，當窗苔蘚碧。", "緬懷在雲漢，良願暌枕席。翻似無見時，如何久為客。"]'),
('yuding-6','餞郢州李使君','蘇頲','唐','御定全唐诗','yuding','','[]','楚有章華台，遙遙雲夢澤。複聞擁符傳，及是收圖籍。',72,'御定全唐詩/json/073.json','["楚有章華台，遙遙雲夢澤。複聞擁符傳，及是收圖籍。", "佳政在離人，能聲寄侯伯。離懷朔風起，試望秋陰積。", "中路淒以寒，群山靄將夕。傷心聊把袂，怊悵麒麟客。"]'),
('yuding-7','餞唐州高使君赴任','蘇頲','唐','御定全唐诗','yuding','','[]','永日奏文時，東風搖盪夕。浩然思樂事，翻複餞征客。',48,'御定全唐詩/json/073.json','["永日奏文時，東風搖盪夕。浩然思樂事，翻複餞征客。", "淮水春流清，楚山暮雲白。勿言行路遠，所貴專城伯。"]'),
('yuding-8','曉濟膠川南入密界','蘇頲','唐','御定全唐诗','yuding','','[]','飲馬膠川上，傍膠南趣密。林遙飛鳥遲，雲去晴山出。',48,'御定全唐詩/json/073.json','["飲馬膠川上，傍膠南趣密。林遙飛鳥遲，雲去晴山出。", "落暉隱桑柘，秋原被花實。慘然遊子寒，風露將蕭瑟。"]'),
('yuding-9','夜發三泉即事','蘇頲','唐','御定全唐诗','yuding','','[]','暗發三泉山，窮秋聽騷屑。北林夜鳴雨，南望曉成雪。',180,'御定全唐詩/json/073.json','["暗發三泉山，窮秋聽騷屑。北林夜鳴雨，南望曉成雪。", "只詠北風涼，詎知南土熱。沙溪忽沸渭，石道乍明滅。", "宛若銀磧橫，複如瑤台結。指程賦所戀，遇虞不遑歇。", "重纊濡莫解，懸旌凍猶揭。下奔泥棧榰，上覯雲梯設。", "搏頰羸馬頓，回眸惴人跌。憧憧往復還，心注思逾切。", "冉冉年將病，力困衰怠竭。天彭信方隅，地勢誠鬥絕。", "忝曳尚書履，叨兼使臣節。京坻有歲饒，亭障無邊孽。", "歸奏丹墀左，騫能俟來哲。"]'),
('yuding-10','小園納涼即事','蘇頲','唐','御定全唐诗','yuding','','[]','煩暑避蒸郁，居閑習高明。長風自遠來，層閣有餘清。',48,'御定全唐詩/json/073.json','["煩暑避蒸郁，居閑習高明。長風自遠來，層閣有餘清。", "散灑納涼氣，蕭條遺世情。奈何誇大隱，終日系塵纓。"]'),
('yuding-11','昆明池晏坐答王兵部珣三韻見示','蘇頲','唐','御定全唐诗','yuding','','[]','畫舸疾如飛，遙遙泛夕暉。石鯨吹浪隱，玉女步塵歸。',36,'御定全唐詩/json/073.json','["畫舸疾如飛，遙遙泛夕暉。石鯨吹浪隱，玉女步塵歸。", "獨有銜恩處，明珠在釣磯。"]'),
('yuding-12','奉和聖制春台望應制','蘇頲','唐','御定全唐诗','yuding','','[]','壯麗天之府，神明王者宅。大君乘飛龍，登彼複懷昔。',132,'御定全唐詩/json/073.json','["壯麗天之府，神明王者宅。大君乘飛龍，登彼複懷昔。", "圓闕朱光焰，橫山翠微積。河汧流作表，縣聚開成陌。", "即舊在皇家，維新具物華。雲連所上居恒屬，", "暴嬴國此嘗圖霸，霸業後仁先以詐。東破諸侯西入秦，", "事往覆輈經遠喻，春還按蹕憑高賦。戎觀愛力深惟省，", "伯夷位事愚臣忝，喜奏聲成鳳鳥來。"]'),
('yuding-13','長相思','蘇頲','唐','御定全唐诗','yuding','','[]','君不見天津橋下東流水，南望龍門北朝市。',43,'御定全唐詩/json/073.json','["君不見天津橋下東流水，南望龍門北朝市。", "楊柳青青宛地垂，桃紅李白花參差。花參差，柳堪結，"]'),
('yuding-14','蜀城哭台州樂安少府','蘇頲','唐','御定全唐诗','yuding','','[]','遠遊躋劍閣，長想屬天臺。萬里隔三載，此邦餘重來。',277,'御定全唐詩/json/073.json','["遠遊躋劍閣，長想屬天臺。萬里隔三載，此邦餘重來。", "音容曠不睹，夢寐殊悠哉。邊郡饒藉藉，晚庭正回回。", "喜傳上都封，因促傍吏開。向悟海鹽客，已而梁木摧。", "變衣寢門外，揮涕少城隈。卻記分明得，猶持委曲猜。", "師儒昔訓獎，仲季時童孩。服義題書篋，邀歡泛酒杯。", "暫令風雨散，仍迫歲時回。其道惟正直，其人信美偲。", "白頭還作尉，黃綬固非才。可歎懸蛇疾，先貽問鵩災。", "故鄉閉窮壤，宿草生寒荄。零落九原去，蹉跎四序催。", "曩期冬贈橘，今哭夏成梅。執禮誰為賵，居常不徇財。", "北登嵔gF阪，東望姑蘇台。天路本懸絕，江波複溯洄。", "念孤心易斷，追往恨艱裁。不遂卿將伯，孰雲陳與雷。", "吾衰亦如此，夫子複何哀。"]'),
('yuding-15','立春日侍宴內出剪綵花應制','蘇頲','唐','御定全唐诗','yuding','','[]','曉入宜春苑，穠芳吐禁中。剪刀因裂素，妝粉為開紅。',48,'御定全唐詩/json/073.json','["曉入宜春苑，穠芳吐禁中。剪刀因裂素，妝粉為開紅。", "彩異驚流雪，香饒點便風。裁成識天意，萬物與花同。"]'),
('yuding-16','春日芙蓉園侍宴應制','蘇頲','唐','御定全唐诗','yuding','','[]','禦道紅旗出，芳園翠輦遊。繞花開水殿，架竹起山樓。',48,'御定全唐詩/json/073.json','["禦道紅旗出，芳園翠輦遊。繞花開水殿，架竹起山樓。", "荷芰輕熏幄，魚龍出負舟。甯知穆天子，空賦白雲秋。"]'),
('yuding-17','奉和聖制人日清暉閣宴群臣遇雪應制','蘇頲','唐','御定全唐诗','yuding','','[]','樓觀空煙裏，初年瑞雪過。苑花齊玉樹，池水作銀河。',48,'御定全唐詩/json/073.json','["樓觀空煙裏，初年瑞雪過。苑花齊玉樹，池水作銀河。", "七日祥圖啟，千春禦賞多。輕飛傳彩勝，天上奉熏歌。"]'),
('yuding-18','奉和七夕宴兩儀殿應制','蘇頲','唐','御定全唐诗','yuding','','[]','靈媛乘秋發，仙裝警夜催。月光窺欲渡，河色辨應來。',48,'御定全唐詩/json/073.json','["靈媛乘秋發，仙裝警夜催。月光窺欲渡，河色辨應來。", "機石天文寫，針樓禦賞開。竊觀棲鳥至，疑向鵲橋回。"]'),
('yuding-19','奉和九日幸臨渭亭登高應制得時字','蘇頲','唐','御定全唐诗','yuding','','[]','嘉會宜長日，高筵順動時。曉光雲外洗，晴色雨餘滋。',48,'御定全唐詩/json/073.json','["嘉會宜長日，高筵順動時。曉光雲外洗，晴色雨餘滋。", "降鶴因韶德，吹花入禦詞。願陪陽數節，億萬九秋期。"]'),
('yuding-20','游禁苑幸臨渭亭遇雪應制','蘇頲','唐','御定全唐诗','yuding','','[]','平明敞帝居，霰雪下淩虛。寫月含珠綴，從風薄綺疏。',48,'御定全唐詩/json/073.json','["平明敞帝居，霰雪下淩虛。寫月含珠綴，從風薄綺疏。", "年驚花絮早，春夜管弦初。已屬雲天外，欣承霈澤餘。"]'),
('yuding-21','奉和送金城公主適西蕃應制','蘇頲','唐','御定全唐诗','yuding','','[]','帝女出天津，和戎轉罽輪。川經斷腸望，地與析支鄰。',48,'御定全唐詩/json/073.json','["帝女出天津，和戎轉罽輪。川經斷腸望，地與析支鄰。", "奏曲風嘶馬，銜悲月伴人。旋知偃兵革，長是漢家親。"]'),
('yuding-22','奉和聖制登驪山高頂寓目應制','蘇頲','唐','御定全唐诗','yuding','','[]','仙蹕禦層氛，高高積翠分。岩聲中谷應，天語半空聞。',48,'御定全唐詩/json/073.json','["仙蹕禦層氛，高高積翠分。岩聲中谷應，天語半空聞。", "豐樹連黃葉，函關入紫雲。聖圖恢宇縣，歌賦小橫汾。"]'),
('yuding-23','幸白鹿觀應制','蘇頲','唐','御定全唐诗','yuding','','[]','碧虛清吹下，藹藹入仙宮。松磴攀雲絕，花源接澗空。',48,'御定全唐詩/json/073.json','["碧虛清吹下，藹藹入仙宮。松磴攀雲絕，花源接澗空。", "受符邀羽使，傳訣注香童。詎似閒居日，徒聞有順風。"]'),
('yuding-24','題壽安王主簿池館','蘇頲','唐','御定全唐诗','yuding','','[]','洛邑通馳道，韓郊在屬城。館將花雨映，潭與竹聲清。',48,'御定全唐詩/json/073.json','["洛邑通馳道，韓郊在屬城。館將花雨映，潭與竹聲清。", "賢俊鸞棲棘，賓游馬佩衡。願言隨狎鳥，從此濯吾纓。"]'),
('yuding-25','扈從溫泉奉和姚令公喜雪','蘇頲','唐','御定全唐诗','yuding','','[]','清道豐人望，乘時漢主遊。恩暉隨霰下，慶澤與雲浮。',48,'御定全唐詩/json/073.json','["清道豐人望，乘時漢主遊。恩暉隨霰下，慶澤與雲浮。", "泉暖驚銀磧，花寒愛玉樓。鼎臣今有問，河伯且應留。"]'),
('yuding-26','秋社日崇讓園宴得新字','蘇頲','唐','御定全唐诗','yuding','','[]','鳴爵三農稔，句龍百代神。運昌叨輔弼，時泰喜黎民。',48,'御定全唐詩/json/073.json','["鳴爵三農稔，句龍百代神。運昌叨輔弼，時泰喜黎民。", "樹缺池光近，雲開日影新。生全應有地，長願樂交親。"]'),
('yuding-27','奉和魏僕射秋日還鄉有懷之作','蘇頲','唐','御定全唐诗','yuding','','[]','南宮夙拜罷，東道晝游初。飲餞傾冠蓋，傳呼問裏閭。',48,'御定全唐詩/json/073.json','["南宮夙拜罷，東道晝游初。飲餞傾冠蓋，傳呼問裏閭。", "樹悲懸劍所，溪想釣璜餘。明發輝光至，增榮駟馬車。"]'),
('yuding-28','武擔山寺','蘇頲','唐','御定全唐诗','yuding','','[]','武擔獨蒼然，墳山下玉泉。鱉靈時共盡，龍女事同遷。',48,'御定全唐詩/json/073.json','["武擔獨蒼然，墳山下玉泉。鱉靈時共盡，龍女事同遷。", "松柏銜哀處，幡花種福田。詎知留鏡石，長與法輪圓。"]'),
('yuding-29','餞潞州陸長史再守汾州','蘇頲','唐','御定全唐诗','yuding','','[]','河尹政成期，為汾昔所推。不榮三入地，還美再臨時。',48,'御定全唐詩/json/073.json','["河尹政成期，為汾昔所推。不榮三入地，還美再臨時。", "擁傳雲初合，聞鶯日正遲。道傍多出餞，別有吏民思。"]'),
('yuding-30','餞荊州崔司馬','蘇頲','唐','御定全唐诗','yuding','','[]','茂禮雕龍昔，香名展驥初。水連南海漲，星拱北辰居。',48,'御定全唐詩/json/073.json','["茂禮雕龍昔，香名展驥初。水連南海漲，星拱北辰居。", "稍發仙人履，將題別駕輿。明年征拜入，荊玉不藏諸。"]'),
('yuding-31','送吏部李侍郎東歸得歸字','蘇頲','唐','御定全唐诗','yuding','','[]','陌上有光輝，披雲向洛畿。賞來榮扈從，別至惜分飛。',48,'御定全唐詩/json/073.json','["陌上有光輝，披雲向洛畿。賞來榮扈從，別至惜分飛。", "泉溜含風急，山煙帶日微。茂曹今去矣，人物喜東歸。"]'),
('yuding-32','送光祿姚卿還都','蘇頲','唐','御定全唐诗','yuding','','[]','漢室有英台，荀家寵俊才。九卿朝已入，三子暮同來。',48,'御定全唐詩/json/073.json','["漢室有英台，荀家寵俊才。九卿朝已入，三子暮同來。", "不授綸為草，還司鼎用梅。兩京王者宅，駟馬日應回。"]'),
('yuding-33','春晚送瑕丘田少府還任，因寄洛中鏡上人','蘇頲','唐','御定全唐诗','yuding','','[]','聞道還沂上，因聲寄洛濱。別時花欲盡，歸處酒應春。',48,'御定全唐詩/json/073.json','["聞道還沂上，因聲寄洛濱。別時花欲盡，歸處酒應春。", "聚散同行客，悲歡屬故人。少年追樂地，遙贈一沾巾。"]'),
('yuding-34','送賈起居奉使入洛取圖書因便拜覲','蘇頲','唐','御定全唐诗','yuding','','[]','舊國才因地，當朝史命官。遺文征闕簡，還思采芳蘭。',48,'御定全唐詩/json/073.json','["舊國才因地，當朝史命官。遺文征闕簡，還思采芳蘭。", "傳發關門候，觴稱邑裏歡。早持京副入，旋佇洛書刊。"]'),
('yuding-35','送常侍舒公歸覲','蘇頲','唐','御定全唐诗','yuding','','[]','朝聞講藝餘，晨省拜恩初。訓胄尊庠序，榮親耀裏閭。',48,'御定全唐詩/json/073.json','["朝聞講藝餘，晨省拜恩初。訓胄尊庠序，榮親耀裏閭。", "朱丹華轂送，斑白綺筵舒。江上春流滿，還應薦躍魚。"]'),
('yuding-36','興州出行','蘇頲','唐','御定全唐诗','yuding','','[]','危途曉未分，驅馬傍江濆。滴滴泣花露，微微出岫雲。',48,'御定全唐詩/json/073.json','["危途曉未分，驅馬傍江濆。滴滴泣花露，微微出岫雲。", "松梢半吐月，蘿翳漸移曛。旅客腸應斷，吟猿更使聞。"]'),
('yuding-37','邊秋薄暮','蘇頲','唐','御定全唐诗','yuding','','[]','海外秋鷹擊，霜前旅雁歸。邊風思鞞鼓，落日慘旌麾。',48,'御定全唐詩/json/073.json','["海外秋鷹擊，霜前旅雁歸。邊風思鞞鼓，落日慘旌麾。", "浦暗漁舟入，川長獵騎稀。客悲逢薄暮，況乃事戎機。"]'),
('yuding-38','曉發方騫驛','蘇頲','唐','御定全唐诗','yuding','','[]','傳置遠山蹊，龍鍾蹴澗泥。片陰常作雨，微照已生霓。',48,'御定全唐詩/json/073.json','["傳置遠山蹊，龍鍾蹴澗泥。片陰常作雨，微照已生霓。", "鬢髮愁氛換，心情險路迷。方知向蜀者，偏識子規啼。"]'),
('yuding-39','經三泉路作','蘇頲','唐','御定全唐诗','yuding','','[]','三月松作花，春行日漸賒。竹障山鳥路，藤蔓野人家。',48,'御定全唐詩/json/073.json','["三月松作花，春行日漸賒。竹障山鳥路，藤蔓野人家。", "透石飛梁下，尋雲絕磴斜。此中誰與樂，揮涕語年華。"]'),
('yuding-40','故高安大長公主挽詞','蘇頲','唐','御定全唐诗','yuding','','[]','彤管承師訓，青圭備禮容。孟孫家代寵，元女國朝封。',48,'御定全唐詩/json/073.json','["彤管承師訓，青圭備禮容。孟孫家代寵，元女國朝封。", "柔軌題貞順，閑規賦肅雍。寧知落照盡，霜吹入悲松。"]'),
('yuding-41','贈司徒豆盧府君挽詞','蘇頲','唐','御定全唐诗','yuding','','[]','寵贈追胡廣，親臨比賀循。幾聞投劍客，多會服緦人。',48,'御定全唐詩/json/073.json','["寵贈追胡廣，親臨比賀循。幾聞投劍客，多會服緦人。", "草閉墳將古，松陰地不春。二陵猶可望，存歿有忠臣。"]'),
('yuding-42','故右散騎常侍舒國公褚公挽詞','蘇頲','唐','御定全唐诗','yuding','','[]','陽翟疏豐構，臨平演慶源。學筵尊授幾，儒服寵乘軒。',48,'御定全唐詩/json/073.json','["陽翟疏豐構，臨平演慶源。學筵尊授幾，儒服寵乘軒。", "審諭留中密，開陳與上言。徂暉一不借，空有賜東園。"]'),
('yuding-43','奉和初春幸太平公主南莊應制','蘇頲','唐','御定全唐诗','yuding','','[]','主第山門起灞川，宸游風景入初年。鳳凰樓下交天仗，',40,'御定全唐詩/json/073.json','["主第山門起灞川，宸游風景入初年。鳳凰樓下交天仗，", "今朝扈蹕平陽館，不羨乘槎雲漢邊。"]'),
('yuding-44','奉和春日幸望春宮應制','蘇頲','唐','御定全唐诗','yuding','','[]','東望望春春可憐，更逢晴日柳含煙。宮中下見南山盡，',40,'御定全唐詩/json/073.json','["東望望春春可憐，更逢晴日柳含煙。宮中下見南山盡，", "宸遊對此歡無極，鳥哢聲聲入管弦。"]'),
('yuding-45','人日重宴大明宮恩賜彩縷人勝應制','蘇頲','唐','御定全唐诗','yuding','','[]','疏龍磴道切昭回，建鳳旗門繞帝台。七葉仙蓂依月吐，',40,'御定全唐詩/json/073.json','["疏龍磴道切昭回，建鳳旗門繞帝台。七葉仙蓂依月吐，", "是日皇靈知竊幸，群心就捧大明來。"]'),
('yuding-46','侍宴安樂公主山莊應制','蘇頲','唐','御定全唐诗','yuding','','[]','駸駸羽騎曆城池，帝女樓臺向晚披。霧灑旌旗雲外出，',40,'御定全唐詩/json/073.json','["駸駸羽騎曆城池，帝女樓臺向晚披。霧灑旌旗雲外出，", "簫鼓宸遊陪宴日，和鳴雙鳳喜來儀。"]'),
('yuding-47','興慶池侍宴應制','蘇頲','唐','御定全唐诗','yuding','','[]','降鶴池前回步輦，棲鸞樹杪出行宮。山光積翠遙疑逼，',40,'御定全唐詩/json/073.json','["降鶴池前回步輦，棲鸞樹杪出行宮。山光積翠遙疑逼，", "皇歡未使恩波極，日暮樓船更起風。"]'),
('yuding-48','廣達樓下夜侍酺宴應制','蘇頲','唐','御定全唐诗','yuding','','[]','東嶽封回宴洛京，西墉通晚會公卿。樓臺絕勝宜春苑，',40,'御定全唐詩/json/073.json','["東嶽封回宴洛京，西墉通晚會公卿。樓臺絕勝宜春苑，", "酺來萬舞群臣醉，喜戴千年聖主明。"]'),
('yuding-49','龍池樂章','蘇頲','唐','御定全唐诗','yuding','','[]','西京鳳邸躍龍泉，佳氣休光鎮在天。軒後霧圖今已得，',40,'御定全唐詩/json/073.json','["西京鳳邸躍龍泉，佳氣休光鎮在天。軒後霧圖今已得，", "願侍巡遊同舊裏，更聞簫鼓濟樓船。"]'),
('yuding-50','扈從鄠杜間奉呈刑部尚書舅崔黃門馬常侍','蘇頲','唐','御定全唐诗','yuding','','[]','翠輦紅旗出帝京，長楊鄠杜昔知名。雲山一一看皆美，',40,'御定全唐詩/json/073.json','["翠輦紅旗出帝京，長楊鄠杜昔知名。雲山一一看皆美，", "漢家曾草巡遊賦，何似今來應聖明。"]'),
('yuding-51','景龍觀送裴士曹','蘇頲','唐','御定全唐诗','yuding','','[]','昔日嘗聞公主第，今時變作列仙家。池傍坐客穿叢筱，',40,'御定全唐詩/json/073.json','["昔日嘗聞公主第，今時變作列仙家。池傍坐客穿叢筱，", "君還洛邑分明記，此處同來閱歲華。"]'),
('yuding-52','春晚紫微省直寄內','蘇頲','唐','御定全唐诗','yuding','','[]','直省清華接建章，向來無事日猶長。花間燕子棲鳷鵲，',40,'御定全唐詩/json/073.json','["直省清華接建章，向來無事日猶長。花間燕子棲鳷鵲，", "別離不慣無窮憶，莫誤卿卿學太常。"]'),
('yuding-53','贈彭州權別駕','蘇頲','唐','御定全唐诗','yuding','','[]','雙流脈脈錦城開，追餞年年往復回。只道歌謠迎半刺，',40,'御定全唐詩/json/073.json','["雙流脈脈錦城開，追餞年年往復回。只道歌謠迎半刺，", "莫愴分飛岐路別，還當奏最掖垣來。"]'),
('yuding-54','寒食宴於中舍別駕兄弟宅','蘇頲','唐','御定全唐诗','yuding','','[]','子推山上歌龍罷，定國門前結駟來。始睹元昆鏘玉至，',40,'御定全唐詩/json/073.json','["子推山上歌龍罷，定國門前結駟來。始睹元昆鏘玉至，", "自有長筵歡不極，還將彩服詠南陔。"]'),
('yuding-55','九月九日望蜀台','蘇頲','唐','御定全唐诗','yuding','','[]','蜀王望蜀舊台前，九日分明見一川。北料鄉關方自此，',40,'御定全唐詩/json/073.json','["蜀王望蜀舊台前，九日分明見一川。北料鄉關方自此，", "自昔登臨湮滅盡，獨聞忠孝兩能傳。"]'),
('yuding-0','奉和晦日幸昆明池應制','蘇頲','唐','御定全唐诗','yuding','','[]','炎曆事邊陲，昆明始鑿池。豫游光後聖，征戰罷前規。',72,'御定全唐詩/json/074.json','["炎曆事邊陲，昆明始鑿池。豫游光後聖，征戰罷前規。", "霽色清珍宇，年芳入錦陂。禦杯蘭薦葉，仙仗柳交枝。", "二石分河瀉，雙珠代月移。微臣比翔泳，恩廣自無涯。"]'),
('yuding-1','奉和聖制幸禮部尚書竇希玠宅應制','蘇頲','唐','御定全唐诗','yuding','','[]','尚書列侯第，外戚近臣家。飛棟臨青綺，回輿轉翠華。',72,'御定全唐詩/json/074.json','["尚書列侯第，外戚近臣家。飛棟臨青綺，回輿轉翠華。", "日交當戶樹，泉漾滿池花。圓頂圖嵩石，方流擁魏沙。", "豫遊今聽履，侍從昔鳴笳。自有天文降，無勞訪海槎。"]'),
('yuding-2','奉和幸韋嗣立山莊應制','蘇頲','唐','御定全唐诗','yuding','','[]','摐金寒野霽，步玉曉山幽。帝幄期松子，臣廬訪葛侯。',96,'御定全唐詩/json/074.json','["摐金寒野霽，步玉曉山幽。帝幄期松子，臣廬訪葛侯。", "百工征往夢，七聖扈來遊。斗柄乘時轉，臺階捧日留。", "樹重岩籟合，泉迸水光浮。石徑喧朝履，璜溪擁釣舟。", "恩如犯星夜，歡擬濟河秋。不學堯年隱，空令傲許由。"]'),
('yuding-3','奉和聖制送張說上集賢學士賜宴得茲字','蘇頲','唐','御定全唐诗','yuding','','[]','肅肅金殿裏，招賢固在茲。鏘鏘石渠內，序拜亦同時。',72,'御定全唐詩/json/074.json','["肅肅金殿裏，招賢固在茲。鏘鏘石渠內，序拜亦同時。", "宴錫歡談道，文成貴說詩。用儒今作相，敦學舊為師。", "下際天光近，中來帝渥滋。國朝良史載，能事日論思。"]'),
('yuding-4','奉和聖制途經華嶽應制','蘇頲','唐','御定全唐诗','yuding','','[]','朝望蓮華獄，神心就日來。晴觀五千仞，仙掌拓山開。',72,'御定全唐詩/json/074.json','["朝望蓮華獄，神心就日來。晴觀五千仞，仙掌拓山開。", "受命金符葉，過祥玉瑞陪。霧披乘鹿見，雲起馭龍回。", "偃樹枝封雪，殘碑石冒苔。聖皇惟道契，文字勒岩隈。"]'),
('yuding-5','奉和聖制經河上公廟應制','蘇頲','唐','御定全唐诗','yuding','','[]','河流無日夜，河上有神仙。輦路曾經此，壇場即宛然。',72,'御定全唐詩/json/074.json','["河流無日夜，河上有神仙。輦路曾經此，壇場即宛然。", "下疑成洞穴，高若在空煙。善物遺方外，和光繞道邊。", "事因周史得，言與漢王傳。喜屬膺期聖，邦家業又玄。"]'),
('yuding-6','奉和聖制答張說出雀鼠谷','蘇頲','唐','御定全唐诗','yuding','','[]','雨施巡方罷，雲從訓俗回。密途汾水衛，清蹕晉郊陪。',72,'御定全唐詩/json/074.json','["雨施巡方罷，雲從訓俗回。密途汾水衛，清蹕晉郊陪。", "寒著山邊盡，春當日下來。禦祠玄鳥應，仙仗綠楊開。", "作頌音傳雅，觀文色動台。更知西向樂，宸藻協鹽梅。"]'),
('yuding-7','奉和恩賜樂遊園宴應制','蘇頲','唐','御定全唐诗','yuding','','[]','樂遊光地選，酺飲慶天從。座密千官盛，場開百戲容。',72,'御定全唐詩/json/074.json','["樂遊光地選，酺飲慶天從。座密千官盛，場開百戲容。", "綠塍際山盡，緹幕倚雲重。下上花齊發，周回柳遍濃。", "奪晴紛劍履，喧聽雜歌鐘。日晚銜恩散，堯人並可封。"]'),
('yuding-8','恩制尚書省僚宴昆明池同用堯字','蘇頲','唐','御定全唐诗','yuding','','[]','露渥灑雲霄，天官次鬥杓。昆明四十裏，空水極晴朝。',72,'御定全唐詩/json/074.json','["露渥灑雲霄，天官次鬥杓。昆明四十裏，空水極晴朝。", "雁似銜紅葉，鯨疑噴海潮。翠山來徹底，白日去回標。", "泳廣漁杈溢，浮深妓舫搖。飽恩皆醉止，合舞共歌堯。"]'),
('yuding-9','奉和聖制幸望春宮送朔方大總管張仁亶','蘇頲','唐','御定全唐诗','yuding','','[]','北風吹早雁，日夕渡河飛。氣冷膠應折，霜明草正腓。',72,'御定全唐詩/json/074.json','["北風吹早雁，日夕渡河飛。氣冷膠應折，霜明草正腓。", "老臣帷幄算，元宰廟堂機。餞飲回仙蹕，臨戎解禦衣。", "軍裝乘曉發，師律候春歸。方佇勳庸盛，天詞降紫微。"]'),
('yuding-10','奉和聖制登太行山中言志應制','蘇頲','唐','御定全唐诗','yuding','','[]','北山東入海，馳道上連天。順動三光注，登臨萬象懸。',96,'御定全唐詩/json/074.json','["北山東入海，馳道上連天。順動三光注，登臨萬象懸。", "俯觀河內邑，平指洛陽川。按蹕夷關險，張旗亙井泉。", "曉岩中警柝，春事下搜田。德重周王問，歌輕漢後傳。", "宸遊鋪令典，睿思起芳年。願以封書奏，回鑾禪肅然。"]'),
('yuding-11','奉和聖制漕橋東送新除岳牧','蘇頲','唐','御定全唐诗','yuding','','[]','寶賢不遺俊，台閣盡鵷鸞。未若調人切，其如簡帝難。',120,'御定全唐詩/json/074.json','["寶賢不遺俊，台閣盡鵷鸞。未若調人切，其如簡帝難。", "上才膺出典，中旨念分官。特以專城貴，深惟列郡安。", "政行思務本，風靡屬勝殘。有令田知急，無分獄在寬。", "至言題睿劄，殊渥灑仙翰。詔餞三台降，朝榮萬國歡。", "舉杯臨水發，張樂擁橋觀。式佇東封會，鏘鏘檢玉壇。"]'),
('yuding-12','奉和聖制途次舊居應制','蘇頲','唐','御定全唐诗','yuding','','[]','潞國臨淄邸，天王別駕輿。出潛離隱際，小往大來初。',144,'御定全唐詩/json/074.json','["潞國臨淄邸，天王別駕輿。出潛離隱際，小往大來初。", "東陸行春典，南陽即舊居。約川星罕駐，扶道日旗舒。", "雲覆連行在，風回助掃除。木行城邑望，皋落土田疏。", "昔試邦興後，今過俗徯予。示威寧校獵，崇讓不陳魚。", "府吏趨宸扆，鄉耆捧帝車。帳傾三飲處，閑整六飛餘。", "盛業銘汾鼎，昌期應洛書。願陪歌賦末，留比蜀相如。"]'),
('yuding-13','奉和聖制至長春宮登樓望稼穡之作','蘇頲','唐','御定全唐诗','yuding','','[]','帝跡奚其遠，皇符之所崇。敬時堯務作，盡力禹稱功。',144,'御定全唐詩/json/074.json','["帝跡奚其遠，皇符之所崇。敬時堯務作，盡力禹稱功。", "赫赫惟元後，經營自左馮。變蕪粳稻實，流惡水泉通。", "國阜猶前豹，人疲詎昔熊。黃圖巡沃野，清吹入離宮。", "是閱京坻富，仍觀都邑雄。憑軒一何綺，積溜寫晴空。", "禮節家安外，和平俗在中。見龍垂渭北，辭雁指河東。", "睿思方居鎬，宸游若飲豐。寧誇子雲從，只為獵扶風。"]'),
('yuding-14','利州北佛龕前重於去歲題處作','蘇頲','唐','御定全唐诗','yuding','','[]','重岩載看美，分塔起層標。蜀守經塗處，巴人作禮朝。',60,'御定全唐詩/json/074.json','["重岩載看美，分塔起層標。蜀守經塗處，巴人作禮朝。", "地疑三界出，空是六塵銷。臥石鋪蒼蘚，行塍覆綠條。", "歲年書有記，非為學題橋。"]');
